#[derive(Debug, Clone, Copy)]
enum RawScalarDtype {
    Bf16,
    F32,
}

impl RawScalarDtype {
    fn as_str(self) -> &'static str {
        match self {
            Self::Bf16 => "bf16",
            Self::F32 => "f32",
        }
    }
}

