fn load_and_validate_official_k_rope_state(
    cli: &Cli,
    case: &ArtifactCase,
    num_tokens: usize,
    num_kv_heads: usize,
    head_dim: usize,
) -> Result<OfficialKRopeStateArtifact> {
    let artifact = load_official_k_rope_state_artifact(&cli.official_k_rope_state_artifact)?;
    if artifact.boundary != "layer0_k_rope_state" {
        bail!(
            "official k-rope-state boundary mismatch: expected layer0_k_rope_state, found {}",
            artifact.boundary
        );
    }
    if artifact.case_id != case.id {
        bail!(
            "official k-rope-state case id mismatch: expected {}, found {}",
            case.id,
            artifact.case_id
        );
    }
    if artifact.input_token_ids != case.input_token_ids {
        bail!("official k-rope-state token ids do not match the exact smoke case");
    }
    if artifact.token_positions.len() != num_tokens {
        bail!(
            "official k-rope-state token position length mismatch: expected {}, found {}",
            num_tokens,
            artifact.token_positions.len()
        );
    }
    if artifact.final_token_index != num_tokens.saturating_sub(1) {
        bail!(
            "official k-rope-state final token index mismatch: expected {}, found {}",
            num_tokens.saturating_sub(1),
            artifact.final_token_index
        );
    }
    if artifact.effective_position_id != artifact.final_token_index as i32 {
        bail!(
            "official k-rope-state effective position mismatch: expected {}, found {}",
            artifact.final_token_index,
            artifact.effective_position_id
        );
    }
    if artifact.num_kv_heads != num_kv_heads {
        bail!(
            "official k-rope-state num_kv_heads mismatch: expected {}, found {}",
            num_kv_heads,
            artifact.num_kv_heads
        );
    }
    if artifact.head_dim != head_dim {
        bail!(
            "official k-rope-state head_dim mismatch: expected {}, found {}",
            head_dim,
            artifact.head_dim
        );
    }
    if artifact.half_dim * 2 != artifact.head_dim {
        bail!("official k-rope-state half_dim/head_dim are inconsistent");
    }
    if artifact.expanded_cos_row_f32.len() != head_dim
        || artifact.expanded_sin_row_f32.len() != head_dim
    {
        bail!(
            "official k-rope-state expanded factor lengths mismatch for head_dim {}: cos {}, sin {}",
            head_dim,
            artifact.expanded_cos_row_f32.len(),
            artifact.expanded_sin_row_f32.len()
        );
    }
    Ok(artifact)
}

