fn feature_major_to_token_major(
    feature_major: &[f32],
    token_count: usize,
    feature_count: usize,
) -> Result<Vec<f32>> {
    if feature_major.len() != token_count * feature_count {
        bail!(
            "feature-major buffer length {} does not match expected {}",
            feature_major.len(),
            token_count * feature_count
        );
    }
    let mut token_major = vec![0.0f32; token_count * feature_count];
    for token_idx in 0..token_count {
        for feature_idx in 0..feature_count {
            token_major[token_idx * feature_count + feature_idx] =
                feature_major[feature_idx * token_count + token_idx];
        }
    }
    Ok(token_major)
}

fn run_raw_bf16_gemm_activation_by_weight_feature_major(
    blas: &CudaBlas,
    stream: &std::sync::Arc<cudarc::driver::CudaStream>,
    activation_bf16: &[bf16],
    k_weight_bf16: &[bf16],
    token_count: usize,
    kv_dim: usize,
    hidden_size: usize,
) -> Result<Vec<f32>> {
    use cudarc::cublas::sys::{
        cublasComputeType_t::CUBLAS_COMPUTE_32F,
        cublasGemmAlgo_t::CUBLAS_GEMM_DEFAULT_TENSOR_OP,
        cublasOperation_t::{CUBLAS_OP_N, CUBLAS_OP_T},
        cublasStatus_t::CUBLAS_STATUS_SUCCESS,
        cudaDataType_t::CUDA_R_16BF,
    };

    if activation_bf16.len() != token_count * hidden_size {
        bail!(
            "activation length {} does not match expected {}",
            activation_bf16.len(),
            token_count * hidden_size
        );
    }
    if k_weight_bf16.len() != kv_dim * hidden_size {
        bail!(
            "K weight length {} does not match expected {}",
            k_weight_bf16.len(),
            kv_dim * hidden_size
        );
    }

    let activation_gpu = stream
        .clone_htod(activation_bf16)
        .map_err(|e| anyhow::anyhow!("alternate feature-major activation htod failed: {e}"))?;
    let k_weight_gpu = stream
        .clone_htod(k_weight_bf16)
        .map_err(|e| anyhow::anyhow!("alternate feature-major K weight htod failed: {e}"))?;
    let mut output_gpu = stream
        .alloc_zeros::<bf16>(token_count * kv_dim)
        .map_err(|e| anyhow::anyhow!("alternate feature-major output alloc failed: {e}"))?;

    {
        let (activation_ptr, _activation_guard) = DevicePtr::device_ptr(&activation_gpu, &stream);
        let (weight_ptr, _weight_guard) = DevicePtr::device_ptr(&k_weight_gpu, &stream);
        let (output_ptr, _output_guard) = DevicePtrMut::device_ptr_mut(&mut output_gpu, &stream);

        unsafe {
            let status = cudarc::cublas::sys::cublasGemmEx(
                *blas.handle(),
                CUBLAS_OP_T,
                CUBLAS_OP_N,
                token_count as i32,
                kv_dim as i32,
                hidden_size as i32,
                &1.0f32 as *const f32 as *const c_void,
                activation_ptr as *const c_void,
                CUDA_R_16BF,
                hidden_size as i32,
                weight_ptr as *const c_void,
                CUDA_R_16BF,
                hidden_size as i32,
                &0.0f32 as *const f32 as *const c_void,
                output_ptr as *mut c_void,
                CUDA_R_16BF,
                token_count as i32,
                CUBLAS_COMPUTE_32F,
                CUBLAS_GEMM_DEFAULT_TENSOR_OP,
            );
            if status != CUBLAS_STATUS_SUCCESS {
                bail!("alternate feature-major cublasGemmEx failed: {status:?}");
            }
        }
    }

    let output_host: Vec<bf16> = stream
        .clone_dtoh(&output_gpu)
        .map_err(|e| anyhow::anyhow!("alternate feature-major output dtoh failed: {e}"))?;
    Ok(output_host.iter().map(|value| value.to_f32()).collect())
}

fn classify_all_token_k_gemm_contract_status(
    full_vs_cpu: &CompareMetrics,
    stitched_vs_cpu: &CompareMetrics,
    variants: &[GemmContractVariantSummary],
) -> (&'static str, &'static str) {
    let variant_collapses_to_stitched = variants.iter().any(|variant| {
        !matches!(
            variant.name.as_str(),
            "current_full_m74_helper_path" | "stitched_74x_m1_helper_path"
        ) && (collapse_rule_satisfied(full_vs_cpu, &variant.vs_cpu_reference)
            || candidate_clearly_better(&variant.vs_cpu_reference, full_vs_cpu))
            && (variant.vs_stitched_reference.matched
                || variant.vs_stitched_reference.mean_abs_diff
                    <= stitched_vs_cpu.mean_abs_diff.max(1.0e-6) * 10.0)
    });

    if variant_collapses_to_stitched {
        (
            "multi_row_gemm_contract_identified",
            "turn the identified GEMM contract variant into a surgical runtime proof/fix",
        )
    } else {
        (
            "multi_row_gemm_contract_not_explained",
            "inspect the multi-row helper's cuBLAS math mode/algorithm behavior under the captured internally consistent contract",
        )
    }
}

fn run_all_token_k_gemm_contract_status(cli: &Cli) -> Result<()> {
    use cudarc::cublas::sys::cublasOperation_t::{CUBLAS_OP_N, CUBLAS_OP_T};

    let source_artifact_path = PathBuf::from(DEFAULT_ALL_TOKEN_K_MULTI_ROW_STATUS_OUTPUT);
    let source_artifact: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_artifact_path).with_context(|| {
            format!(
                "failed to read source multi-row artifact {}",
                source_artifact_path.display()
            )
        })?,
    )
    .with_context(|| {
        format!(
            "failed to parse source multi-row artifact {}",
            source_artifact_path.display()
        )
    })?;
    if source_artifact
        .get("classification")
        .and_then(serde_json::Value::as_str)
        != Some("multi_row_invocation_mismatch")
    {
        bail!(
            "source multi-row artifact classification is not multi_row_invocation_mismatch: {}",
            source_artifact_path.display()
        );
    }

    let (attn_norm_artifact, attn_norm_case) =
        load_single_case_artifact(&cli.local_attn_norm_artifact)?;
    let exact_hidden_size = attn_norm_case
        .hidden_size
        .context("exact smoke case missing hidden_size")?;
    validate_exact_case_artifact(
        &attn_norm_artifact,
        &attn_norm_case,
        "layer0_attn_norm_output",
        "developer-message-user-smoke",
        &attn_norm_case.input_token_ids,
    )?;

    let model_root = Path::new(&attn_norm_artifact.provenance.model);
    let max_model_len = attn_norm_artifact.provenance.max_model_len.unwrap_or(128);
    let gpu_memory_utilization = attn_norm_artifact
        .provenance
        .gpu_memory_utilization
        .unwrap_or(0.75);
    let visible_devices = attn_norm_artifact
        .provenance
        .visible_devices
        .clone()
        .unwrap_or_else(|| env::var("CUDA_VISIBLE_DEVICES").unwrap_or_else(|_| "<unset>".into()));

    info!(
        model_root = %model_root.display(),
        max_model_len,
        gpu_memory_utilization,
        visible_devices = %visible_devices,
        "starting exact-case all-token K GEMM contract status run"
    );

    let _guard = EnvFlagGuard::set(BF16_DENSE_QKV_ENV, true);
    let worker = build_worker(model_root, max_model_len, gpu_memory_utilization)?;
    let live_trace = capture_layer0_qkv_trace(&worker, &attn_norm_case.input_token_ids)?;
    if !live_trace.branch_taken {
        bail!("all-token K GEMM contract trace did not take the bf16 fused-qkv branch");
    }
    let token_count = live_trace.num_tokens;
    if token_count != 74 {
        bail!("expected exact smoke token_count 74, found {token_count}");
    }

    let activation_full_bf16 =
        bf16_bits_to_bf16_slice(&live_trace.standalone_activation_full_bf16_bits);
    let standalone_k_weight_bf16 =
        bf16_bits_to_bf16_slice(&live_trace.standalone_k_weight_bf16_bits);
    let cpu_reference = cpu_bf16_row_major_gemm(
        &activation_full_bf16,
        &standalone_k_weight_bf16,
        token_count,
        live_trace.kv_dim,
        exact_hidden_size,
    )?;
    let cpu_reference_f32 = bf16_slice_to_f32(&cpu_reference);

    let stream = worker.gpu_stream().clone();
    let k_weight_gpu = stream
        .clone_htod(&standalone_k_weight_bf16)
        .map_err(|e| anyhow::anyhow!("gemm-contract K weight htod failed: {e}"))?;
    let activation_gpu = stream
        .clone_htod(&activation_full_bf16)
        .map_err(|e| anyhow::anyhow!("gemm-contract full activation htod failed: {e}"))?;
    let mut full_output_gpu = stream
        .alloc_zeros::<bf16>(token_count * live_trace.kv_dim)
        .map_err(|e| anyhow::anyhow!("gemm-contract full output alloc failed: {e}"))?;
    worker.blas().hgemm_bf16(
        token_count,
        live_trace.kv_dim,
        exact_hidden_size,
        bf16::ONE,
        &activation_gpu,
        &k_weight_gpu,
        bf16::ZERO,
        &mut full_output_gpu,
    )?;
    let full_helper_output: Vec<f32> = stream
        .clone_dtoh(&full_output_gpu)
        .map_err(|e| anyhow::anyhow!("gemm-contract full output dtoh failed: {e}"))?
        .iter()
        .map(|value| value.to_f32())
        .collect();

    let mut stitched_helper_output = Vec::with_capacity(token_count * live_trace.kv_dim);
    for row_idx in 0..token_count {
        let start = row_idx * exact_hidden_size;
        let end = start + exact_hidden_size;
        let row_activation_gpu = stream
            .clone_htod(&activation_full_bf16[start..end])
            .map_err(|e| {
                anyhow::anyhow!("gemm-contract stitched row {row_idx} activation htod failed: {e}")
            })?;
        let mut row_output_gpu = stream.alloc_zeros::<bf16>(live_trace.kv_dim).map_err(|e| {
            anyhow::anyhow!("gemm-contract stitched row {row_idx} output alloc failed: {e}")
        })?;
        worker.blas().hgemm_bf16(
            1,
            live_trace.kv_dim,
            exact_hidden_size,
            bf16::ONE,
            &row_activation_gpu,
            &k_weight_gpu,
            bf16::ZERO,
            &mut row_output_gpu,
        )?;
        stitched_helper_output.extend(
            stream
                .clone_dtoh(&row_output_gpu)
                .map_err(|e| {
                    anyhow::anyhow!("gemm-contract stitched row {row_idx} output dtoh failed: {e}")
                })?
                .iter()
                .map(|value| value.to_f32()),
        );
    }

    let raw_blas = CudaBlas::new(worker.gpu_stream().clone())
        .map_err(|e| anyhow::anyhow!("failed to create GEMM contract raw cuBLAS handle: {e}"))?;
    let current_raw_output = run_raw_bf16_gemm_contract_all_tokens(
        &raw_blas,
        worker.gpu_stream(),
        &activation_full_bf16,
        &standalone_k_weight_bf16,
        token_count,
        live_trace.kv_dim,
        exact_hidden_size,
        RawBf16GemmContract {
            trans_weight: CUBLAS_OP_T,
            trans_input: CUBLAS_OP_N,
            lda: exact_hidden_size as i32,
            ldb: exact_hidden_size as i32,
            ldc: live_trace.kv_dim as i32,
            alpha_beta_dtype: RawScalarDtype::F32,
        },
    )?;
    let current_raw_vs_full = compare_vectors(&current_raw_output, &full_helper_output)?;
    if !current_raw_vs_full.matched {
        bail!("raw current GEMM contract did not reproduce the full helper output");
    }

    let current_feature_major_reinterpretation =
        feature_major_to_token_major(&full_helper_output, token_count, live_trace.kv_dim)?;
    let alternate_feature_major_raw = run_raw_bf16_gemm_activation_by_weight_feature_major(
        &raw_blas,
        worker.gpu_stream(),
        &activation_full_bf16,
        &standalone_k_weight_bf16,
        token_count,
        live_trace.kv_dim,
        exact_hidden_size,
    )?;
    let alternate_feature_major_token_major =
        feature_major_to_token_major(&alternate_feature_major_raw, token_count, live_trace.kv_dim)?;

    let current_full_vs_cpu_metrics = compare_vectors(&full_helper_output, &cpu_reference_f32)?;
    let stitched_vs_cpu_metrics = compare_vectors(&stitched_helper_output, &cpu_reference_f32)?;
    let captured_gemm_params =
        current_all_token_k_invocation_capture(token_count, live_trace.kv_dim, exact_hidden_size);
    let alternate_invocation = alternate_feature_major_k_invocation_capture(
        token_count,
        live_trace.kv_dim,
        exact_hidden_size,
    );

    let variants = vec![
        GemmContractVariantSummary {
            name: "current_full_m74_helper_path".into(),
            description: "runtime helper full multi-row call with current token-major output interpretation".into(),
            invocation: Some(current_all_token_k_invocation_capture(
                token_count,
                live_trace.kv_dim,
                exact_hidden_size,
            )),
            output_interpretation: "token-major [token, feature]".into(),
            vs_cpu_reference: current_full_vs_cpu_metrics.clone(),
            vs_stitched_reference: compare_vectors(&full_helper_output, &stitched_helper_output)?,
        },
        GemmContractVariantSummary {
            name: "stitched_74x_m1_helper_path".into(),
            description: "74 independent m=1 helper calls stitched in token order".into(),
            invocation: Some(current_all_token_k_invocation_capture(
                1,
                live_trace.kv_dim,
                exact_hidden_size,
            )),
            output_interpretation: "token-major [token, feature] after stitching".into(),
            vs_cpu_reference: stitched_vs_cpu_metrics.clone(),
            vs_stitched_reference: compare_vectors(&stitched_helper_output, &stitched_helper_output)?,
        },
        GemmContractVariantSummary {
            name: "current_full_feature_major_reinterpretation".into(),
            description: "same current full helper bytes, interpreted as feature-major C and transposed for comparison".into(),
            invocation: None,
            output_interpretation: "feature-major reinterpretation of current helper output, then transposed to token-major".into(),
            vs_cpu_reference: compare_vectors(
                &current_feature_major_reinterpretation,
                &cpu_reference_f32,
            )?,
            vs_stitched_reference: compare_vectors(
                &current_feature_major_reinterpretation,
                &stitched_helper_output,
            )?,
        },
        GemmContractVariantSummary {
            name: "alternate_feature_major_cublas_contract".into(),
            description: "safe local alternate cuBLAS orientation: activation as A, K weight as B, C_col=[token, feature] with ldc=token, then transposed to token-major".into(),
            invocation: Some(alternate_invocation),
            output_interpretation: "feature-major C_col=[token, feature], then transposed to token-major".into(),
            vs_cpu_reference: compare_vectors(
                &alternate_feature_major_token_major,
                &cpu_reference_f32,
            )?,
            vs_stitched_reference: compare_vectors(
                &alternate_feature_major_token_major,
                &stitched_helper_output,
            )?,
        },
    ];

    let first_differing_row_column_full_vs_stitched = first_differing_element(
        &full_helper_output,
        &stitched_helper_output,
        token_count,
        live_trace.kv_dim,
    )?;
    let (classification, next_bounded_step) = classify_all_token_k_gemm_contract_status(
        &current_full_vs_cpu_metrics,
        &stitched_vs_cpu_metrics,
        &variants,
    );
    let runtime_forward_all_token_k_gemm_contract_status_now = format!(
        "runtime-forward all-token K GEMM contract status now: current full vs_cpu max_abs={} mean_abs={}; stitched vs_cpu max_abs={} mean_abs={}; classification={}; next bounded step: {}.",
        current_full_vs_cpu_metrics.max_abs_diff,
        current_full_vs_cpu_metrics.mean_abs_diff,
        stitched_vs_cpu_metrics.max_abs_diff,
        stitched_vs_cpu_metrics.mean_abs_diff,
        classification,
        next_bounded_step
    );
    let summary = AllTokenKGemmContractStatusSummary {
        schema_version: "runtime_forward_layer0_all_token_k_gemm_contract_status/v1".into(),
        source_artifact_path,
        provenance: AllTokenKHelperContractProvenance {
            local_attn_norm_artifact_path: cli.local_attn_norm_artifact.clone(),
            all_token_k_projection_microproof_status_artifact_path: PathBuf::from(
                DEFAULT_ALL_TOKEN_K_PROJECTION_MICROPROOF_STATUS_OUTPUT,
            ),
            model_root: attn_norm_artifact.provenance.model.clone(),
            visible_devices,
            dense_qkv_env_var: BF16_DENSE_QKV_ENV.to_string(),
        },
        exact_case: KGainPreservationExactCase {
            case_id: attn_norm_case.id.clone(),
            input_token_ids: attn_norm_case.input_token_ids.clone(),
            hidden_size: exact_hidden_size,
            num_tokens: live_trace.num_tokens,
            q_dim: live_trace.q_dim,
            kv_dim: live_trace.kv_dim,
            qkv_dim: live_trace.qkv_dim,
        },
        seam_name: "layer0_k_raw_projection_all_token_gemm_contract".into(),
        mode: "all-token-k-gemm-contract-status".into(),
        captured_gemm_params,
        current_full_vs_cpu_metrics,
        stitched_vs_cpu_metrics,
        variants,
        first_differing_row_column_full_vs_stitched,
        classification: classification.into(),
        runtime_forward_all_token_k_gemm_contract_status_now,
        next_bounded_step: next_bounded_step.into(),
    };
    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::AllTokenKGemmContractStatus.default_output());
    write_pretty_json(&output, &summary)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn run_raw_bf16_gemm_math_mode_variant(
    blas: &CudaBlas,
    stream: &std::sync::Arc<cudarc::driver::CudaStream>,
    activation_bf16: &[bf16],
    k_weight_bf16: &[bf16],
    token_count: usize,
    kv_dim: usize,
    hidden_size: usize,
    math_mode: cudarc::cublas::sys::cublasMath_t,
    atomics_mode: cudarc::cublas::sys::cublasAtomicsMode_t,
    compute_type: cudarc::cublas::sys::cublasComputeType_t,
    algo: cudarc::cublas::sys::cublasGemmAlgo_t,
) -> Result<Vec<f32>> {
    use cudarc::cublas::sys::{
        cublasOperation_t::{CUBLAS_OP_N, CUBLAS_OP_T},
        cublasStatus_t::CUBLAS_STATUS_SUCCESS,
        cudaDataType_t::CUDA_R_16BF,
    };

    if activation_bf16.len() != token_count * hidden_size {
        bail!(
            "activation length {} does not match expected {}",
            activation_bf16.len(),
            token_count * hidden_size
        );
    }
    if k_weight_bf16.len() != kv_dim * hidden_size {
        bail!(
            "K weight length {} does not match expected {}",
            k_weight_bf16.len(),
            kv_dim * hidden_size
        );
    }

    unsafe {
        let math_status = cudarc::cublas::sys::cublasSetMathMode(*blas.handle(), math_mode);
        if math_status != CUBLAS_STATUS_SUCCESS {
            bail!("cublasSetMathMode({math_mode:?}) failed: {math_status:?}");
        }
        let atomics_status =
            cudarc::cublas::sys::cublasSetAtomicsMode(*blas.handle(), atomics_mode);
        if atomics_status != CUBLAS_STATUS_SUCCESS {
            bail!("cublasSetAtomicsMode({atomics_mode:?}) failed: {atomics_status:?}");
        }
    }

    let activation_gpu = stream
        .clone_htod(activation_bf16)
        .map_err(|e| anyhow::anyhow!("math-mode activation htod failed: {e}"))?;
    let k_weight_gpu = stream
        .clone_htod(k_weight_bf16)
        .map_err(|e| anyhow::anyhow!("math-mode K weight htod failed: {e}"))?;
    let mut output_gpu = stream
        .alloc_zeros::<bf16>(token_count * kv_dim)
        .map_err(|e| anyhow::anyhow!("math-mode output alloc failed: {e}"))?;

    {
        let (weight_ptr, _weight_guard) = DevicePtr::device_ptr(&k_weight_gpu, &stream);
        let (activation_ptr, _activation_guard) = DevicePtr::device_ptr(&activation_gpu, &stream);
        let (output_ptr, _output_guard) = DevicePtrMut::device_ptr_mut(&mut output_gpu, &stream);

        unsafe {
            let status = cudarc::cublas::sys::cublasGemmEx(
                *blas.handle(),
                CUBLAS_OP_T,
                CUBLAS_OP_N,
                kv_dim as i32,
                token_count as i32,
                hidden_size as i32,
                &1.0f32 as *const f32 as *const c_void,
                weight_ptr as *const c_void,
                CUDA_R_16BF,
                hidden_size as i32,
                activation_ptr as *const c_void,
                CUDA_R_16BF,
                hidden_size as i32,
                &0.0f32 as *const f32 as *const c_void,
                output_ptr as *mut c_void,
                CUDA_R_16BF,
                kv_dim as i32,
                compute_type,
                algo,
            );
            if status != CUBLAS_STATUS_SUCCESS {
                bail!(
                    "math-mode cublasGemmEx math={math_mode:?} atomics={atomics_mode:?} compute={compute_type:?} algo={algo:?} failed: {status:?}"
                );
            }
        }
    }

    let output_host: Vec<bf16> = stream
        .clone_dtoh(&output_gpu)
        .map_err(|e| anyhow::anyhow!("math-mode output dtoh failed: {e}"))?;
    Ok(output_host.iter().map(|value| value.to_f32()).collect())
}

#[allow(clippy::too_many_arguments)]
fn evaluate_gemm_math_mode_variant(
    name: &str,
    description: &str,
    stream: &std::sync::Arc<cudarc::driver::CudaStream>,
    activation_bf16: &[bf16],
    k_weight_bf16: &[bf16],
    token_count: usize,
    kv_dim: usize,
    hidden_size: usize,
    cpu_reference: &[f32],
    stitched_reference: &[f32],
    math_mode: cudarc::cublas::sys::cublasMath_t,
    atomics_mode: cudarc::cublas::sys::cublasAtomicsMode_t,
    compute_type: cudarc::cublas::sys::cublasComputeType_t,
    algo: cudarc::cublas::sys::cublasGemmAlgo_t,
) -> GemmMathModeVariantSummary {
    let raw_blas = match CudaBlas::new(stream.clone()) {
        Ok(blas) => blas,
        Err(error) => {
            return GemmMathModeVariantSummary {
                name: name.into(),
                description: description.into(),
                available: false,
                skipped_reason: Some(format!("failed to create cuBLAS handle: {error}")),
                math_mode: format!("{math_mode:?}"),
                atomics_mode: format!("{atomics_mode:?}"),
                compute_type: format!("{compute_type:?}"),
                algo: format!("{algo:?}"),
                vs_cpu_reference: None,
                vs_stitched_reference: None,
            };
        }
    };
    match run_raw_bf16_gemm_math_mode_variant(
        &raw_blas,
        stream,
        activation_bf16,
        k_weight_bf16,
        token_count,
        kv_dim,
        hidden_size,
        math_mode,
        atomics_mode,
        compute_type,
        algo,
    ) {
        Ok(output) => GemmMathModeVariantSummary {
            name: name.into(),
            description: description.into(),
            available: true,
            skipped_reason: None,
            math_mode: format!("{math_mode:?}"),
            atomics_mode: format!("{atomics_mode:?}"),
            compute_type: format!("{compute_type:?}"),
            algo: format!("{algo:?}"),
            vs_cpu_reference: Some(
                compare_vectors(&output, cpu_reference)
                    .expect("math-mode output length must match CPU reference"),
            ),
            vs_stitched_reference: Some(
                compare_vectors(&output, stitched_reference)
                    .expect("math-mode output length must match stitched reference"),
            ),
        },
        Err(error) => GemmMathModeVariantSummary {
            name: name.into(),
            description: description.into(),
            available: false,
            skipped_reason: Some(error.to_string()),
            math_mode: format!("{math_mode:?}"),
            atomics_mode: format!("{atomics_mode:?}"),
            compute_type: format!("{compute_type:?}"),
            algo: format!("{algo:?}"),
            vs_cpu_reference: None,
            vs_stitched_reference: None,
        },
    }
}

fn classify_all_token_k_gemm_math_mode_status(
    current_vs_cpu: &CompareMetrics,
    stitched_vs_cpu: &CompareMetrics,
    variants: &[GemmMathModeVariantSummary],
) -> (&'static str, &'static str) {
    let available_variants: Vec<&GemmMathModeVariantSummary> = variants
        .iter()
        .filter(|variant| variant.available)
        .collect();
    let any_collapses = available_variants.iter().any(|variant| {
        !matches!(
            variant.name.as_str(),
            "current_full_m74_helper_path" | "stitched_74x_m1_helper_path"
        ) && variant.vs_cpu_reference.as_ref().is_some_and(|metrics| {
            collapse_rule_satisfied(current_vs_cpu, metrics)
                || candidate_clearly_better(metrics, current_vs_cpu)
        }) && variant
            .vs_stitched_reference
            .as_ref()
            .is_some_and(|metrics| {
                metrics.matched
                    || metrics.mean_abs_diff <= stitched_vs_cpu.mean_abs_diff.max(1.0e-6) * 10.0
            })
    });
    if any_collapses {
        (
            "multi_row_gemm_math_mode_identified",
            "turn the identified math-mode/algorithm setting into a surgical runtime proof/fix",
        )
    } else if available_variants.len() <= 2
        && variants.iter().any(|variant| {
            variant.algo.contains("TENSOR_OP") || variant.math_mode.contains("TENSOR_OP")
        })
    {
        (
            "multi_row_gemm_math_mode_suspect",
            "add one more locally available non-tensor-op cuBLAS path or inspect cuBLASLt alternatives under the same seam",
        )
    } else {
        (
            "multi_row_gemm_math_mode_not_explained",
            "move to a narrower multi-row helper discriminator outside simple cuBLAS math-mode and algorithm toggles",
        )
    }
}

fn run_all_token_k_gemm_math_mode_status(cli: &Cli) -> Result<()> {
    use cudarc::cublas::sys::{
        cublasAtomicsMode_t::{CUBLAS_ATOMICS_ALLOWED, CUBLAS_ATOMICS_NOT_ALLOWED},
        cublasComputeType_t::{CUBLAS_COMPUTE_32F, CUBLAS_COMPUTE_32F_PEDANTIC},
        cublasGemmAlgo_t::{CUBLAS_GEMM_ALGO0, CUBLAS_GEMM_DEFAULT_TENSOR_OP, CUBLAS_GEMM_DFALT},
        cublasMath_t::{CUBLAS_DEFAULT_MATH, CUBLAS_PEDANTIC_MATH},
    };

    let source_artifact_path = PathBuf::from(DEFAULT_ALL_TOKEN_K_GEMM_CONTRACT_STATUS_OUTPUT);
    let source_artifact: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_artifact_path).with_context(|| {
            format!(
                "failed to read source GEMM contract artifact {}",
                source_artifact_path.display()
            )
        })?,
    )
    .with_context(|| {
        format!(
            "failed to parse source GEMM contract artifact {}",
            source_artifact_path.display()
        )
    })?;
    if source_artifact
        .get("classification")
        .and_then(serde_json::Value::as_str)
        != Some("multi_row_gemm_contract_not_explained")
    {
        bail!(
            "source GEMM contract artifact classification is not multi_row_gemm_contract_not_explained: {}",
            source_artifact_path.display()
        );
    }
    let captured_gemm_contract_from_prior_seam = source_artifact
        .get("captured_gemm_params")
        .cloned()
        .context("source GEMM contract artifact missing captured_gemm_params")?;

    let (attn_norm_artifact, attn_norm_case) =
        load_single_case_artifact(&cli.local_attn_norm_artifact)?;
    let exact_hidden_size = attn_norm_case
        .hidden_size
        .context("exact smoke case missing hidden_size")?;
    validate_exact_case_artifact(
        &attn_norm_artifact,
        &attn_norm_case,
        "layer0_attn_norm_output",
        "developer-message-user-smoke",
        &attn_norm_case.input_token_ids,
    )?;

    let model_root = Path::new(&attn_norm_artifact.provenance.model);
    let max_model_len = attn_norm_artifact.provenance.max_model_len.unwrap_or(128);
    let gpu_memory_utilization = attn_norm_artifact
        .provenance
        .gpu_memory_utilization
        .unwrap_or(0.75);
    let visible_devices = attn_norm_artifact
        .provenance
        .visible_devices
        .clone()
        .unwrap_or_else(|| env::var("CUDA_VISIBLE_DEVICES").unwrap_or_else(|_| "<unset>".into()));

    info!(
        model_root = %model_root.display(),
        max_model_len,
        gpu_memory_utilization,
        visible_devices = %visible_devices,
        "starting exact-case all-token K GEMM math-mode status run"
    );

    let _guard = EnvFlagGuard::set(BF16_DENSE_QKV_ENV, true);
    let worker = build_worker(model_root, max_model_len, gpu_memory_utilization)?;
    let live_trace = capture_layer0_qkv_trace(&worker, &attn_norm_case.input_token_ids)?;
    if !live_trace.branch_taken {
        bail!("all-token K GEMM math-mode trace did not take the bf16 fused-qkv branch");
    }
    let token_count = live_trace.num_tokens;
    if token_count != 74 {
        bail!("expected exact smoke token_count 74, found {token_count}");
    }

    let activation_full_bf16 =
        bf16_bits_to_bf16_slice(&live_trace.standalone_activation_full_bf16_bits);
    let standalone_k_weight_bf16 =
        bf16_bits_to_bf16_slice(&live_trace.standalone_k_weight_bf16_bits);
    let cpu_reference = cpu_bf16_row_major_gemm(
        &activation_full_bf16,
        &standalone_k_weight_bf16,
        token_count,
        live_trace.kv_dim,
        exact_hidden_size,
    )?;
    let cpu_reference_f32 = bf16_slice_to_f32(&cpu_reference);

    let stream = worker.gpu_stream().clone();
    let k_weight_gpu = stream
        .clone_htod(&standalone_k_weight_bf16)
        .map_err(|e| anyhow::anyhow!("math-mode stitched K weight htod failed: {e}"))?;
    let activation_gpu = stream
        .clone_htod(&activation_full_bf16)
        .map_err(|e| anyhow::anyhow!("math-mode full activation htod failed: {e}"))?;
    let mut full_output_gpu = stream
        .alloc_zeros::<bf16>(token_count * live_trace.kv_dim)
        .map_err(|e| anyhow::anyhow!("math-mode full output alloc failed: {e}"))?;
    worker.blas().hgemm_bf16(
        token_count,
        live_trace.kv_dim,
        exact_hidden_size,
        bf16::ONE,
        &activation_gpu,
        &k_weight_gpu,
        bf16::ZERO,
        &mut full_output_gpu,
    )?;
    let full_helper_output: Vec<f32> = stream
        .clone_dtoh(&full_output_gpu)
        .map_err(|e| anyhow::anyhow!("math-mode full output dtoh failed: {e}"))?
        .iter()
        .map(|value| value.to_f32())
        .collect();

    let mut stitched_helper_output = Vec::with_capacity(token_count * live_trace.kv_dim);
    for row_idx in 0..token_count {
        let start = row_idx * exact_hidden_size;
        let end = start + exact_hidden_size;
        let row_activation_gpu = stream
            .clone_htod(&activation_full_bf16[start..end])
            .map_err(|e| {
                anyhow::anyhow!("math-mode stitched row {row_idx} activation htod failed: {e}")
            })?;
        let mut row_output_gpu = stream.alloc_zeros::<bf16>(live_trace.kv_dim).map_err(|e| {
            anyhow::anyhow!("math-mode stitched row {row_idx} output alloc failed: {e}")
        })?;
        worker.blas().hgemm_bf16(
            1,
            live_trace.kv_dim,
            exact_hidden_size,
            bf16::ONE,
            &row_activation_gpu,
            &k_weight_gpu,
            bf16::ZERO,
            &mut row_output_gpu,
        )?;
        stitched_helper_output.extend(
            stream
                .clone_dtoh(&row_output_gpu)
                .map_err(|e| {
                    anyhow::anyhow!("math-mode stitched row {row_idx} output dtoh failed: {e}")
                })?
                .iter()
                .map(|value| value.to_f32()),
        );
    }

    let current_full_vs_cpu = compare_vectors(&full_helper_output, &cpu_reference_f32)?;
    let stitched_vs_cpu = compare_vectors(&stitched_helper_output, &cpu_reference_f32)?;
    let first_differing_row_column_current_full_vs_stitched = first_differing_element(
        &full_helper_output,
        &stitched_helper_output,
        token_count,
        live_trace.kv_dim,
    )?;

    let mut variants = vec![
        GemmMathModeVariantSummary {
            name: "current_full_m74_helper_path".into(),
            description: "runtime helper full multi-row call".into(),
            available: true,
            skipped_reason: None,
            math_mode: "wrapper current handle state".into(),
            atomics_mode: "wrapper current handle state".into(),
            compute_type: "CUBLAS_COMPUTE_32F".into(),
            algo: "CUBLAS_GEMM_DEFAULT_TENSOR_OP".into(),
            vs_cpu_reference: Some(current_full_vs_cpu.clone()),
            vs_stitched_reference: Some(compare_vectors(
                &full_helper_output,
                &stitched_helper_output,
            )?),
        },
        GemmMathModeVariantSummary {
            name: "stitched_74x_m1_helper_path".into(),
            description: "74 independent m=1 helper calls stitched in token order".into(),
            available: true,
            skipped_reason: None,
            math_mode: "wrapper current handle state".into(),
            atomics_mode: "wrapper current handle state".into(),
            compute_type: "CUBLAS_COMPUTE_32F".into(),
            algo: "CUBLAS_GEMM_DEFAULT_TENSOR_OP".into(),
            vs_cpu_reference: Some(stitched_vs_cpu.clone()),
            vs_stitched_reference: Some(compare_vectors(
                &stitched_helper_output,
                &stitched_helper_output,
            )?),
        },
    ];

    variants.push(evaluate_gemm_math_mode_variant(
        "raw_full_m74_atomics_not_allowed",
        "full m=74 raw cuBLAS replay with atomics explicitly disabled",
        worker.gpu_stream(),
        &activation_full_bf16,
        &standalone_k_weight_bf16,
        token_count,
        live_trace.kv_dim,
        exact_hidden_size,
        &cpu_reference_f32,
        &stitched_helper_output,
        CUBLAS_DEFAULT_MATH,
        CUBLAS_ATOMICS_NOT_ALLOWED,
        CUBLAS_COMPUTE_32F,
        CUBLAS_GEMM_DEFAULT_TENSOR_OP,
    ));
    variants.push(evaluate_gemm_math_mode_variant(
        "raw_full_m74_default_math",
        "full m=74 raw cuBLAS replay with default math mode and default tensor-op algorithm",
        worker.gpu_stream(),
        &activation_full_bf16,
        &standalone_k_weight_bf16,
        token_count,
        live_trace.kv_dim,
        exact_hidden_size,
        &cpu_reference_f32,
        &stitched_helper_output,
        CUBLAS_DEFAULT_MATH,
        CUBLAS_ATOMICS_ALLOWED,
        CUBLAS_COMPUTE_32F,
        CUBLAS_GEMM_DEFAULT_TENSOR_OP,
    ));
    variants.push(evaluate_gemm_math_mode_variant(
        "raw_full_m74_pedantic_no_tensor_op",
        "full m=74 raw cuBLAS replay with pedantic math, pedantic f32 compute, and non-tensor-op default algorithm",
        worker.gpu_stream(),
        &activation_full_bf16,
        &standalone_k_weight_bf16,
        token_count,
        live_trace.kv_dim,
        exact_hidden_size,
        &cpu_reference_f32,
        &stitched_helper_output,
        CUBLAS_PEDANTIC_MATH,
        CUBLAS_ATOMICS_NOT_ALLOWED,
        CUBLAS_COMPUTE_32F_PEDANTIC,
        CUBLAS_GEMM_DFALT,
    ));
    variants.push(evaluate_gemm_math_mode_variant(
        "raw_full_m74_conservative_algo0",
        "full m=74 raw cuBLAS replay with atomics disabled and explicit non-tensor-op ALGO0",
        worker.gpu_stream(),
        &activation_full_bf16,
        &standalone_k_weight_bf16,
        token_count,
        live_trace.kv_dim,
        exact_hidden_size,
        &cpu_reference_f32,
        &stitched_helper_output,
        CUBLAS_DEFAULT_MATH,
        CUBLAS_ATOMICS_NOT_ALLOWED,
        CUBLAS_COMPUTE_32F,
        CUBLAS_GEMM_ALGO0,
    ));

    let (classification, next_bounded_step) = classify_all_token_k_gemm_math_mode_status(
        &current_full_vs_cpu,
        &stitched_vs_cpu,
        &variants,
    );
    let runtime_forward_all_token_k_gemm_math_mode_status_now = format!(
        "runtime-forward all-token K GEMM math-mode status now: current full vs_cpu max_abs={} mean_abs={}; stitched vs_cpu max_abs={} mean_abs={}; classification={}; next bounded step: {}.",
        current_full_vs_cpu.max_abs_diff,
        current_full_vs_cpu.mean_abs_diff,
        stitched_vs_cpu.max_abs_diff,
        stitched_vs_cpu.mean_abs_diff,
        classification,
        next_bounded_step
    );

    let summary = AllTokenKGemmMathModeStatusSummary {
        schema_version: "runtime_forward_layer0_all_token_k_gemm_math_mode_status/v1".into(),
        source_artifact_path,
        provenance: AllTokenKHelperContractProvenance {
            local_attn_norm_artifact_path: cli.local_attn_norm_artifact.clone(),
            all_token_k_projection_microproof_status_artifact_path: PathBuf::from(
                DEFAULT_ALL_TOKEN_K_PROJECTION_MICROPROOF_STATUS_OUTPUT,
            ),
            model_root: attn_norm_artifact.provenance.model.clone(),
            visible_devices,
            dense_qkv_env_var: BF16_DENSE_QKV_ENV.to_string(),
        },
        exact_case: KGainPreservationExactCase {
            case_id: attn_norm_case.id.clone(),
            input_token_ids: attn_norm_case.input_token_ids.clone(),
            hidden_size: exact_hidden_size,
            num_tokens: live_trace.num_tokens,
            q_dim: live_trace.q_dim,
            kv_dim: live_trace.kv_dim,
            qkv_dim: live_trace.qkv_dim,
        },
        seam_name: "layer0_k_raw_projection_all_token_gemm_math_mode".into(),
        mode: "all-token-k-gemm-math-mode-status".into(),
        captured_gemm_contract_from_prior_seam,
        variants,
        first_differing_row_column_current_full_vs_stitched,
        classification: classification.into(),
        runtime_forward_all_token_k_gemm_math_mode_status_now,
        next_bounded_step: next_bounded_step.into(),
    };
    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::AllTokenKGemmMathModeStatus.default_output());
    write_pretty_json(&output, &summary)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn run_all_token_k_pedantic_runtime_fix_status(cli: &Cli) -> Result<()> {
    use cudarc::cublas::sys::{
        cublasAtomicsMode_t::CUBLAS_ATOMICS_ALLOWED, cublasComputeType_t::CUBLAS_COMPUTE_32F,
        cublasGemmAlgo_t::CUBLAS_GEMM_DEFAULT_TENSOR_OP, cublasMath_t::CUBLAS_DEFAULT_MATH,
    };

    let source_artifact_path = PathBuf::from(DEFAULT_ALL_TOKEN_K_GEMM_MATH_MODE_STATUS_OUTPUT);
    let source_artifact: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_artifact_path).with_context(|| {
            format!(
                "failed to read source GEMM math-mode artifact {}",
                source_artifact_path.display()
            )
        })?,
    )
    .with_context(|| {
        format!(
            "failed to parse source GEMM math-mode artifact {}",
            source_artifact_path.display()
        )
    })?;
    if source_artifact
        .get("classification")
        .and_then(serde_json::Value::as_str)
        != Some("multi_row_gemm_math_mode_identified")
    {
        bail!(
            "source GEMM math-mode artifact classification is not multi_row_gemm_math_mode_identified: {}",
            source_artifact_path.display()
        );
    }

    let (attn_norm_artifact, attn_norm_case) =
        load_single_case_artifact(&cli.local_attn_norm_artifact)?;
    let exact_hidden_size = attn_norm_case
        .hidden_size
        .context("exact smoke case missing hidden_size")?;
    validate_exact_case_artifact(
        &attn_norm_artifact,
        &attn_norm_case,
        "layer0_attn_norm_output",
        "developer-message-user-smoke",
        &attn_norm_case.input_token_ids,
    )?;

    let model_root = Path::new(&attn_norm_artifact.provenance.model);
    let max_model_len = attn_norm_artifact.provenance.max_model_len.unwrap_or(128);
    let gpu_memory_utilization = attn_norm_artifact
        .provenance
        .gpu_memory_utilization
        .unwrap_or(0.75);
    let visible_devices = attn_norm_artifact
        .provenance
        .visible_devices
        .clone()
        .unwrap_or_else(|| env::var("CUDA_VISIBLE_DEVICES").unwrap_or_else(|_| "<unset>".into()));

    info!(
        model_root = %model_root.display(),
        max_model_len,
        gpu_memory_utilization,
        visible_devices = %visible_devices,
        "starting exact-case all-token K pedantic runtime fix status run"
    );

    let _guard = EnvFlagGuard::set(BF16_DENSE_QKV_ENV, true);
    let worker = build_worker(model_root, max_model_len, gpu_memory_utilization)?;
    let live_trace = capture_layer0_qkv_trace(&worker, &attn_norm_case.input_token_ids)?;
    if !live_trace.branch_taken {
        bail!("all-token K pedantic runtime fix trace did not take the bf16 fused-qkv branch");
    }
    let token_count = live_trace.num_tokens;
    if token_count != 74 {
        bail!("expected exact smoke token_count 74, found {token_count}");
    }
    if live_trace.standalone_k_gemm_output_full_bf16_bits.len() != token_count * live_trace.kv_dim {
        bail!(
            "live trace standalone K GEMM output length {} does not match expected {}",
            live_trace.standalone_k_gemm_output_full_bf16_bits.len(),
            token_count * live_trace.kv_dim
        );
    }

    let activation_full_bf16 =
        bf16_bits_to_bf16_slice(&live_trace.standalone_activation_full_bf16_bits);
    let standalone_k_weight_bf16 =
        bf16_bits_to_bf16_slice(&live_trace.standalone_k_weight_bf16_bits);
    let cpu_reference = cpu_bf16_row_major_gemm(
        &activation_full_bf16,
        &standalone_k_weight_bf16,
        token_count,
        live_trace.kv_dim,
        exact_hidden_size,
    )?;
    let cpu_reference_f32 = bf16_slice_to_f32(&cpu_reference);
    let live_fixed_full_output =
        bf16_bits_to_f32_slice(&live_trace.standalone_k_gemm_output_full_bf16_bits);

    let stream = worker.gpu_stream().clone();
    let k_weight_gpu = stream
        .clone_htod(&standalone_k_weight_bf16)
        .map_err(|e| anyhow::anyhow!("pedantic-fix stitched K weight htod failed: {e}"))?;
    let mut stitched_helper_output = Vec::with_capacity(token_count * live_trace.kv_dim);
    for row_idx in 0..token_count {
        let start = row_idx * exact_hidden_size;
        let end = start + exact_hidden_size;
        let row_activation_gpu = stream
            .clone_htod(&activation_full_bf16[start..end])
            .map_err(|e| {
                anyhow::anyhow!("pedantic-fix stitched row {row_idx} activation htod failed: {e}")
            })?;
        let mut row_output_gpu = stream.alloc_zeros::<bf16>(live_trace.kv_dim).map_err(|e| {
            anyhow::anyhow!("pedantic-fix stitched row {row_idx} output alloc failed: {e}")
        })?;
        worker.blas().hgemm_bf16(
            1,
            live_trace.kv_dim,
            exact_hidden_size,
            bf16::ONE,
            &row_activation_gpu,
            &k_weight_gpu,
            bf16::ZERO,
            &mut row_output_gpu,
        )?;
        stitched_helper_output.extend(
            stream
                .clone_dtoh(&row_output_gpu)
                .map_err(|e| {
                    anyhow::anyhow!("pedantic-fix stitched row {row_idx} output dtoh failed: {e}")
                })?
                .iter()
                .map(|value| value.to_f32()),
        );
    }

    let live_fixed_full_m74_helper_vs_cpu_reference =
        compare_vectors(&live_fixed_full_output, &cpu_reference_f32)?;
    let stitched_74x_m1_helper_vs_cpu_reference =
        compare_vectors(&stitched_helper_output, &cpu_reference_f32)?;
    let live_fixed_full_m74_helper_vs_stitched_reference =
        compare_vectors(&live_fixed_full_output, &stitched_helper_output)?;

    let legacy_non_pedantic_replay = Some(evaluate_gemm_math_mode_variant(
        "legacy_raw_full_m74_non_pedantic_tensor_op_replay",
        "local contrast replay of the pre-fix full m=74 tensor-op GEMM contract",
        worker.gpu_stream(),
        &activation_full_bf16,
        &standalone_k_weight_bf16,
        token_count,
        live_trace.kv_dim,
        exact_hidden_size,
        &cpu_reference_f32,
        &stitched_helper_output,
        CUBLAS_DEFAULT_MATH,
        CUBLAS_ATOMICS_ALLOWED,
        CUBLAS_COMPUTE_32F,
        CUBLAS_GEMM_DEFAULT_TENSOR_OP,
    ));

    let live_fixed_full_m74_matches_cpu = live_fixed_full_m74_helper_vs_cpu_reference.matched
        || bf16_close(&live_fixed_full_m74_helper_vs_cpu_reference);
    let live_fixed_full_m74_within_bf16_tolerance_of_stitched =
        live_fixed_full_m74_helper_vs_stitched_reference.matched
            || bf16_close(&live_fixed_full_m74_helper_vs_stitched_reference);

    let (classification, next_bounded_step) = if live_fixed_full_m74_matches_cpu {
        (
            "all_token_k_pedantic_runtime_fix_proven",
            "rerun the exact downstream grouped pre/post-RoPE K and first score-consumer seams with the K-only pedantic helper in place",
        )
    } else {
        (
            "all_token_k_pedantic_runtime_fix_not_sufficient",
            "keep the scope on the all-token K helper and inspect why the runtime pedantic call differs from the raw pedantic replay",
        )
    };

    let runtime_forward_all_token_k_pedantic_runtime_fix_status_now = format!(
        "runtime-forward all-token K pedantic runtime fix status now: fixed full vs_cpu max_abs={} mean_abs={}; stitched vs_cpu max_abs={} mean_abs={}; fixed full vs_stitched max_abs={} mean_abs={}; classification={}; next bounded step: {}.",
        live_fixed_full_m74_helper_vs_cpu_reference.max_abs_diff,
        live_fixed_full_m74_helper_vs_cpu_reference.mean_abs_diff,
        stitched_74x_m1_helper_vs_cpu_reference.max_abs_diff,
        stitched_74x_m1_helper_vs_cpu_reference.mean_abs_diff,
        live_fixed_full_m74_helper_vs_stitched_reference.max_abs_diff,
        live_fixed_full_m74_helper_vs_stitched_reference.mean_abs_diff,
        classification,
        next_bounded_step
    );

    let summary = AllTokenKPedanticRuntimeFixStatusSummary {
        schema_version: "runtime_forward_layer0_all_token_k_pedantic_runtime_fix_status/v1".into(),
        source_artifact_path,
        provenance: AllTokenKHelperContractProvenance {
            local_attn_norm_artifact_path: cli.local_attn_norm_artifact.clone(),
            all_token_k_projection_microproof_status_artifact_path: PathBuf::from(
                DEFAULT_ALL_TOKEN_K_PROJECTION_MICROPROOF_STATUS_OUTPUT,
            ),
            model_root: attn_norm_artifact.provenance.model.clone(),
            visible_devices,
            dense_qkv_env_var: BF16_DENSE_QKV_ENV.to_string(),
        },
        exact_case: KGainPreservationExactCase {
            case_id: attn_norm_case.id.clone(),
            input_token_ids: attn_norm_case.input_token_ids.clone(),
            hidden_size: exact_hidden_size,
            num_tokens: live_trace.num_tokens,
            q_dim: live_trace.q_dim,
            kv_dim: live_trace.kv_dim,
            qkv_dim: live_trace.qkv_dim,
        },
        mode: "all-token-k-pedantic-runtime-fix-status".into(),
        seam_name: "layer0_k_raw_projection_all_token_pedantic_runtime_fix".into(),
        files_changed: vec![
            "crates/gpt-oss-gpu/src/cublas.rs".into(),
            "crates/gpt-oss-model-runner/src/gpu_layer.rs".into(),
            "crates/gpt-oss-bench/src/bin/runtime_forward_layer0_qkv_bf16_candidate_status.rs"
                .into(),
        ],
        cublas_settings_now_used: PedanticRuntimeFixSettings {
            math_mode: "CUBLAS_PEDANTIC_MATH".into(),
            atomics_mode: "CUBLAS_ATOMICS_NOT_ALLOWED".into(),
            compute_type: "CUBLAS_COMPUTE_32F_PEDANTIC".into(),
            algo: "CUBLAS_GEMM_DFALT".into(),
            scoped_runtime_path: "layer0 standalone all-token K BF16 raw projection helper only"
                .into(),
        },
        live_fixed_full_m74_helper_vs_cpu_reference,
        stitched_74x_m1_helper_vs_cpu_reference,
        live_fixed_full_m74_helper_vs_stitched_reference,
        legacy_non_pedantic_replay,
        live_fixed_full_m74_matches_cpu,
        live_fixed_full_m74_within_bf16_tolerance_of_stitched,
        classification: classification.into(),
        runtime_forward_all_token_k_pedantic_runtime_fix_status_now,
        next_bounded_step: next_bounded_step.into(),
    };

    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::AllTokenKPedanticRuntimeFixStatus.default_output());
    write_pretty_json(&output, &summary)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn run_k_downstream_after_pedantic_fix_status(cli: &Cli) -> Result<()> {
    let source_fix_artifact_path =
        PathBuf::from(DEFAULT_ALL_TOKEN_K_PEDANTIC_RUNTIME_FIX_STATUS_OUTPUT);
    let source_fix_artifact: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_fix_artifact_path).with_context(|| {
            format!(
                "failed to read source pedantic fix artifact {}",
                source_fix_artifact_path.display()
            )
        })?,
    )
    .with_context(|| {
        format!(
            "failed to parse source pedantic fix artifact {}",
            source_fix_artifact_path.display()
        )
    })?;
    if source_fix_artifact
        .get("classification")
        .and_then(serde_json::Value::as_str)
        != Some("all_token_k_pedantic_runtime_fix_proven")
    {
        bail!(
            "source pedantic fix artifact classification is not all_token_k_pedantic_runtime_fix_proven: {}",
            source_fix_artifact_path.display()
        );
    }
    let k_helper_pedantic_path_active = source_fix_artifact
        .get("live_fixed_full_m74_matches_cpu")
        .and_then(serde_json::Value::as_bool)
        .unwrap_or(false)
        && source_fix_artifact
            .pointer("/cublas_settings_now_used/math_mode")
            .and_then(serde_json::Value::as_str)
            == Some("CUBLAS_PEDANTIC_MATH")
        && source_fix_artifact
            .pointer("/cublas_settings_now_used/compute_type")
            .and_then(serde_json::Value::as_str)
            == Some("CUBLAS_COMPUTE_32F_PEDANTIC")
        && source_fix_artifact
            .pointer("/cublas_settings_now_used/algo")
            .and_then(serde_json::Value::as_str)
            == Some("CUBLAS_GEMM_DFALT");
    if !k_helper_pedantic_path_active {
        bail!(
            "source pedantic fix artifact does not confirm active K helper pedantic path: {}",
            source_fix_artifact_path.display()
        );
    }
    let files_changed_already_in_fix: Vec<String> = source_fix_artifact
        .get("files_changed")
        .and_then(serde_json::Value::as_array)
        .context("source pedantic fix artifact missing files_changed")?
        .iter()
        .map(|value| {
            value
                .as_str()
                .map(str::to_owned)
                .context("files_changed entry is not a string")
        })
        .collect::<Result<Vec<_>>>()?;
    let cublas_settings_now_used = source_fix_artifact
        .get("cublas_settings_now_used")
        .cloned()
        .context("source pedantic fix artifact missing cublas_settings_now_used")?;

    let official_k_rope_bundle =
        load_official_k_rope_bundle_artifact(&cli.official_k_rope_bundle_artifact)?;
    let official_k_post_rope_grouped =
        load_official_vector_artifact(&cli.official_k_post_rope_grouped_artifact)?;
    let official_logits = load_official_vector_artifact(
        &cli.official_final_token_raw_scaled_qk_logits_pre_mask_artifact,
    )?;
    if official_k_rope_bundle.case_id != "developer-message-user-smoke"
        || official_k_post_rope_grouped.case_id != "developer-message-user-smoke"
        || official_logits.case_id != "developer-message-user-smoke"
    {
        bail!("one or more official downstream K seam artifacts are not the exact smoke case");
    }
    if official_k_post_rope_grouped.boundary != "layer0_k_post_rope_grouped" {
        bail!(
            "unexpected official grouped post-RoPE boundary {}",
            official_k_post_rope_grouped.boundary
        );
    }
    if official_logits.boundary != "layer0_final_token_raw_scaled_qk_logits_pre_mask" {
        bail!(
            "unexpected official logits boundary {}",
            official_logits.boundary
        );
    }

    let (attn_norm_artifact, attn_norm_case) =
        load_single_case_artifact(&cli.local_attn_norm_artifact)?;
    let exact_hidden_size = attn_norm_case
        .hidden_size
        .context("exact smoke case missing hidden_size")?;
    validate_exact_case_artifact(
        &attn_norm_artifact,
        &attn_norm_case,
        "layer0_attn_norm_output",
        "developer-message-user-smoke",
        &attn_norm_case.input_token_ids,
    )?;
    if official_k_rope_bundle.input_token_ids != attn_norm_case.input_token_ids
        || official_k_post_rope_grouped.input_token_ids != attn_norm_case.input_token_ids
        || official_logits.input_token_ids != attn_norm_case.input_token_ids
    {
        bail!("official downstream K seam token IDs do not match the exact local case");
    }

    let model_root = Path::new(&attn_norm_artifact.provenance.model);
    let max_model_len = attn_norm_artifact.provenance.max_model_len.unwrap_or(128);
    let gpu_memory_utilization = attn_norm_artifact
        .provenance
        .gpu_memory_utilization
        .unwrap_or(0.75);
    let visible_devices = attn_norm_artifact
        .provenance
        .visible_devices
        .clone()
        .unwrap_or_else(|| env::var("CUDA_VISIBLE_DEVICES").unwrap_or_else(|_| "<unset>".into()));

    info!(
        model_root = %model_root.display(),
        max_model_len,
        gpu_memory_utilization,
        visible_devices = %visible_devices,
        "starting exact-case K downstream after pedantic fix status run"
    );

    let _guard = EnvFlagGuard::set(BF16_DENSE_QKV_ENV, true);
    let worker = build_worker(model_root, max_model_len, gpu_memory_utilization)?;
    let live_trace = capture_layer0_qkv_trace(&worker, &attn_norm_case.input_token_ids)?;
    if !live_trace.branch_taken {
        bail!("K downstream after pedantic fix trace did not take the bf16 fused-qkv branch");
    }
    if live_trace.num_tokens != official_k_rope_bundle.token_count {
        bail!(
            "token count mismatch: live {} vs official {}",
            live_trace.num_tokens,
            official_k_rope_bundle.token_count
        );
    }
    if live_trace.kv_dim != official_k_rope_bundle.kv_dim {
        bail!(
            "kv_dim mismatch: live {} vs official {}",
            live_trace.kv_dim,
            official_k_rope_bundle.kv_dim
        );
    }

    let local_grouped_pre_rope_k =
        bf16_bits_to_f32_slice(&live_trace.standalone_k_post_bias_bf16_bits);
    if local_grouped_pre_rope_k.len() != official_k_rope_bundle.layer0_k_pre_rope_f32.len() {
        bail!(
            "grouped pre-RoPE K length mismatch: live {} vs official {}",
            local_grouped_pre_rope_k.len(),
            official_k_rope_bundle.layer0_k_pre_rope_f32.len()
        );
    }
    if live_trace.k_post_rope_pre_cache_f32.len() != official_k_post_rope_grouped.values.len() {
        bail!(
            "grouped post-RoPE K length mismatch: live {} vs official {}",
            live_trace.k_post_rope_pre_cache_f32.len(),
            official_k_post_rope_grouped.values.len()
        );
    }
    let local_logits = build_final_token_raw_scaled_qk_logits_pre_mask(&live_trace)?;
    if local_logits.len() != official_logits.values.len() {
        bail!(
            "attention score logits length mismatch: live {} vs official {}",
            local_logits.len(),
            official_logits.values.len()
        );
    }

    let grouped_pre_rope_k = compare_vectors(
        &local_grouped_pre_rope_k,
        &official_k_rope_bundle.layer0_k_pre_rope_f32,
    )?;
    let grouped_post_rope_k = compare_vectors(
        &live_trace.k_post_rope_pre_cache_f32,
        &official_k_post_rope_grouped.values,
    )?;
    let layer0_final_token_raw_scaled_qk_logits_pre_mask =
        compare_vectors(&local_logits, &official_logits.values)?;

    let earliest_remaining_mismatching_seam = if !grouped_pre_rope_k.matched {
        Some("grouped_pre_rope_k".to_string())
    } else if !grouped_post_rope_k.matched {
        Some("grouped_post_rope_k".to_string())
    } else if !layer0_final_token_raw_scaled_qk_logits_pre_mask.matched {
        Some("layer0_final_token_raw_scaled_qk_logits_pre_mask".to_string())
    } else {
        None
    };

    let (classification, next_bounded_step) = match earliest_remaining_mismatching_seam.as_deref() {
        None => (
            "k_pedantic_fix_clears_downstream_k_and_score_seams",
            "move forward to the next exact runtime-forward mismatch outside these cleared K and first-score seams",
        ),
        Some("grouped_pre_rope_k") => (
            "grouped_pre_rope_k_still_mismatches_after_helper_fix",
            "stay on grouped pre-RoPE K generation and inspect the remaining non-helper contribution under the exact case",
        ),
        Some("grouped_post_rope_k") => (
            "post_rope_k_still_mismatches_after_helper_fix",
            "stay on K-through-RoPE value production under the exact case",
        ),
        Some("layer0_final_token_raw_scaled_qk_logits_pre_mask") => (
            "first_attention_score_consumer_still_mismatches_after_k_fix",
            "resume first score-consumer attribution now that grouped K seams are cleared",
        ),
        Some(other) => bail!("unexpected downstream seam classification target {other}"),
    };

    let runtime_forward_k_downstream_after_pedantic_fix_status_now = format!(
        "runtime-forward K downstream after pedantic fix status now: grouped_pre_rope max_abs={} mean_abs={} matched={}; grouped_post_rope max_abs={} mean_abs={} matched={}; logits max_abs={} mean_abs={} matched={}; earliest_remaining_mismatching_seam={}; classification={}; next bounded step: {}.",
        grouped_pre_rope_k.max_abs_diff,
        grouped_pre_rope_k.mean_abs_diff,
        grouped_pre_rope_k.matched,
        grouped_post_rope_k.max_abs_diff,
        grouped_post_rope_k.mean_abs_diff,
        grouped_post_rope_k.matched,
        layer0_final_token_raw_scaled_qk_logits_pre_mask.max_abs_diff,
        layer0_final_token_raw_scaled_qk_logits_pre_mask.mean_abs_diff,
        layer0_final_token_raw_scaled_qk_logits_pre_mask.matched,
        earliest_remaining_mismatching_seam
            .as_deref()
            .unwrap_or("none"),
        classification,
        next_bounded_step
    );

    let summary = KDownstreamAfterPedanticFixStatusSummary {
        schema_version: "runtime_forward_layer0_k_downstream_after_pedantic_fix_status/v1".into(),
        exact_case: KGainPreservationExactCase {
            case_id: attn_norm_case.id.clone(),
            input_token_ids: attn_norm_case.input_token_ids.clone(),
            hidden_size: exact_hidden_size,
            num_tokens: live_trace.num_tokens,
            q_dim: live_trace.q_dim,
            kv_dim: live_trace.kv_dim,
            qkv_dim: live_trace.qkv_dim,
        },
        mode: "k-downstream-after-pedantic-fix-status".into(),
        source_fix_artifact_path: source_fix_artifact_path.clone(),
        files_changed_already_in_fix,
        k_helper_pedantic_path_active,
        cublas_settings_now_used,
        provenance: KDownstreamAfterPedanticFixProvenance {
            local_attn_norm_artifact_path: cli.local_attn_norm_artifact.clone(),
            source_fix_artifact_path,
            official_k_rope_bundle_artifact_path: cli.official_k_rope_bundle_artifact.clone(),
            official_k_post_rope_grouped_artifact_path: cli
                .official_k_post_rope_grouped_artifact
                .clone(),
            official_final_token_raw_scaled_qk_logits_pre_mask_artifact_path: cli
                .official_final_token_raw_scaled_qk_logits_pre_mask_artifact
                .clone(),
            model_root: attn_norm_artifact.provenance.model.clone(),
            visible_devices,
            dense_qkv_env_var: BF16_DENSE_QKV_ENV.to_string(),
        },
        per_seam_metrics: KDownstreamAfterPedanticFixMetrics {
            grouped_pre_rope_k,
            grouped_post_rope_k,
            layer0_final_token_raw_scaled_qk_logits_pre_mask,
        },
        earliest_remaining_mismatching_seam,
        classification: classification.into(),
        runtime_forward_k_downstream_after_pedantic_fix_status_now,
        next_bounded_step: next_bounded_step.into(),
    };

    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::KDownstreamAfterPedanticFixStatus.default_output());
    write_pretty_json(&output, &summary)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn grouped_pre_rope_k_step_summary(
    step_name: &str,
    operation: &str,
    local_tensor_name: &str,
    reference_tensor_name: &str,
    local: &[f32],
    reference: &[f32],
    token_count: usize,
    kv_dim: usize,
    head_dim: usize,
) -> Result<GroupedPreRopeKStepSummary> {
    let metrics = compare_vectors(local, reference)?;
    Ok(GroupedPreRopeKStepSummary {
        step_name: step_name.into(),
        operation: operation.into(),
        local_tensor_name: local_tensor_name.into(),
        reference_tensor_name: reference_tensor_name.into(),
        local_shape: vec![token_count, kv_dim / head_dim, head_dim],
        reference_shape: vec![token_count, kv_dim / head_dim, head_dim],
        logical_layout: "[token, kv_head, lane] contiguous; equivalent flat [token, kv_dim]".into(),
        physical_stride: vec![kv_dim, head_dim, 1],
        first_differing_token_head_lane: first_differing_k_lane(
            local,
            reference,
            token_count,
            kv_dim,
            head_dim,
        )?,
        metrics,
    })
}

fn run_grouped_pre_rope_k_source_breakdown_status(cli: &Cli) -> Result<()> {
    let source_downstream_artifact_path =
        PathBuf::from(DEFAULT_K_DOWNSTREAM_AFTER_PEDANTIC_FIX_STATUS_OUTPUT);
    let source_downstream_artifact: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_downstream_artifact_path).with_context(|| {
            format!(
                "failed to read downstream artifact {}",
                source_downstream_artifact_path.display()
            )
        })?,
    )
    .with_context(|| {
        format!(
            "failed to parse downstream artifact {}",
            source_downstream_artifact_path.display()
        )
    })?;
    if source_downstream_artifact
        .get("classification")
        .and_then(serde_json::Value::as_str)
        != Some("grouped_pre_rope_k_still_mismatches_after_helper_fix")
    {
        bail!(
            "source downstream artifact classification is not grouped_pre_rope_k_still_mismatches_after_helper_fix: {}",
            source_downstream_artifact_path.display()
        );
    }
    if source_downstream_artifact
        .get("k_helper_pedantic_path_active")
        .and_then(serde_json::Value::as_bool)
        != Some(true)
    {
        bail!(
            "source downstream artifact does not confirm active pedantic K helper: {}",
            source_downstream_artifact_path.display()
        );
    }

    let source_fix_artifact_path =
        PathBuf::from(DEFAULT_ALL_TOKEN_K_PEDANTIC_RUNTIME_FIX_STATUS_OUTPUT);
    let source_fix_artifact: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_fix_artifact_path).with_context(|| {
            format!(
                "failed to read source fix artifact {}",
                source_fix_artifact_path.display()
            )
        })?,
    )
    .with_context(|| {
        format!(
            "failed to parse source fix artifact {}",
            source_fix_artifact_path.display()
        )
    })?;
    let files_changed_already_in_fix: Vec<String> = source_fix_artifact
        .get("files_changed")
        .and_then(serde_json::Value::as_array)
        .context("source fix artifact missing files_changed")?
        .iter()
        .map(|value| {
            value
                .as_str()
                .map(str::to_owned)
                .context("files_changed entry is not a string")
        })
        .collect::<Result<Vec<_>>>()?;
    let k_helper_pedantic_path_active = source_fix_artifact
        .get("live_fixed_full_m74_matches_cpu")
        .and_then(serde_json::Value::as_bool)
        .unwrap_or(false)
        && source_fix_artifact
            .pointer("/cublas_settings_now_used/math_mode")
            .and_then(serde_json::Value::as_str)
            == Some("CUBLAS_PEDANTIC_MATH");
    if !k_helper_pedantic_path_active {
        bail!(
            "source fix artifact does not confirm active pedantic helper path: {}",
            source_fix_artifact_path.display()
        );
    }

    let official_k_rope_bundle =
        load_official_k_rope_bundle_artifact(&cli.official_k_rope_bundle_artifact)?;
    if official_k_rope_bundle.case_id != "developer-message-user-smoke" {
        bail!(
            "official K RoPE bundle is not the exact smoke case: {}",
            official_k_rope_bundle.case_id
        );
    }

    let (attn_norm_artifact, attn_norm_case) =
        load_single_case_artifact(&cli.local_attn_norm_artifact)?;
    let exact_hidden_size = attn_norm_case
        .hidden_size
        .context("exact smoke case missing hidden_size")?;
    validate_exact_case_artifact(
        &attn_norm_artifact,
        &attn_norm_case,
        "layer0_attn_norm_output",
        "developer-message-user-smoke",
        &attn_norm_case.input_token_ids,
    )?;
    if official_k_rope_bundle.input_token_ids != attn_norm_case.input_token_ids {
        bail!("official K RoPE bundle token IDs do not match the exact local case");
    }

    let model_root = Path::new(&attn_norm_artifact.provenance.model);
    let max_model_len = attn_norm_artifact.provenance.max_model_len.unwrap_or(128);
    let gpu_memory_utilization = attn_norm_artifact
        .provenance
        .gpu_memory_utilization
        .unwrap_or(0.75);
    let visible_devices = attn_norm_artifact
        .provenance
        .visible_devices
        .clone()
        .unwrap_or_else(|| env::var("CUDA_VISIBLE_DEVICES").unwrap_or_else(|_| "<unset>".into()));

    info!(
        model_root = %model_root.display(),
        max_model_len,
        gpu_memory_utilization,
        visible_devices = %visible_devices,
        "starting exact-case grouped pre-RoPE K source breakdown status run"
    );

    let _guard = EnvFlagGuard::set(BF16_DENSE_QKV_ENV, true);
    let worker = build_worker(model_root, max_model_len, gpu_memory_utilization)?;
    let live_trace = capture_layer0_qkv_trace(&worker, &attn_norm_case.input_token_ids)?;
    if !live_trace.branch_taken {
        bail!("grouped pre-RoPE K source breakdown trace did not take the bf16 fused-qkv branch");
    }
    let token_count = live_trace.num_tokens;
    let kv_dim = live_trace.kv_dim;
    let head_dim = official_k_rope_bundle.layer0_k_rope_state.head_dim;
    if token_count != official_k_rope_bundle.token_count || kv_dim != official_k_rope_bundle.kv_dim
    {
        bail!(
            "live K dimensions [{}, {}] do not match official [{}, {}]",
            token_count,
            kv_dim,
            official_k_rope_bundle.token_count,
            official_k_rope_bundle.kv_dim
        );
    }

    let activation_full_bf16 =
        bf16_bits_to_bf16_slice(&live_trace.standalone_activation_full_bf16_bits);
    let standalone_k_weight_bf16 =
        bf16_bits_to_bf16_slice(&live_trace.standalone_k_weight_bf16_bits);
    let cpu_helper_reference_bf16 = cpu_bf16_row_major_gemm(
        &activation_full_bf16,
        &standalone_k_weight_bf16,
        token_count,
        kv_dim,
        exact_hidden_size,
    )?;
    let cpu_helper_reference = bf16_slice_to_f32(&cpu_helper_reference_bf16);
    let fixed_helper_output =
        bf16_bits_to_f32_slice(&live_trace.standalone_k_gemm_output_full_bf16_bits);
    let standalone_pre_bias = bf16_bits_to_f32_slice(&live_trace.standalone_k_pre_bias_bf16_bits);
    let fused_k_slice = bf16_bits_to_f32_slice(&live_trace.fused_k_slice_bf16_bits);
    let standalone_post_bias = bf16_bits_to_f32_slice(&live_trace.standalone_k_post_bias_bf16_bits);

    if fixed_helper_output.len() != token_count * kv_dim
        || standalone_pre_bias.len() != token_count * kv_dim
        || standalone_post_bias.len() != token_count * kv_dim
        || fused_k_slice.len() != token_count * kv_dim
    {
        bail!("one or more local grouped pre-RoPE K source tensors have unexpected length");
    }
    let (expected_post_bias, copy_pack_reference_name) =
        if live_trace.canonical_k_bias_bf16_bits.is_empty() {
            (
                fixed_helper_output.clone(),
                "fixed helper output; no captured K bias in this exact trace",
            )
        } else if live_trace.canonical_k_bias_bf16_bits.len() == kv_dim {
            let canonical_k_bias_bf16 =
                bf16_bits_to_bf16_slice(&live_trace.canonical_k_bias_bf16_bits);
            let expected_post_bias_bf16 = add_k_bias_bf16_output(
                &bf16_bits_to_bf16_slice(&live_trace.standalone_k_gemm_output_full_bf16_bits),
                &canonical_k_bias_bf16,
                token_count,
                kv_dim,
            )?;
            (
                bf16_slice_to_f32(&expected_post_bias_bf16),
                "host recompute from fixed helper output plus captured K bias",
            )
        } else {
            bail!(
                "canonical K bias length mismatch: expected {} or 0, found {}",
                kv_dim,
                live_trace.canonical_k_bias_bf16_bits.len()
            );
        };

    let per_step_metrics = vec![
        grouped_pre_rope_k_step_summary(
            "fixed_all_token_k_helper_output",
            "pedantic all-token K helper GEMM output before bias",
            "live_trace.standalone_k_gemm_output_full_bf16_bits",
            "CPU BF16 row-major K GEMM reference",
            &fixed_helper_output,
            &cpu_helper_reference,
            token_count,
            kv_dim,
            head_dim,
        )?,
        grouped_pre_rope_k_step_summary(
            "k_slice_extraction_from_helper_output",
            "standalone K pre-bias slice captured from the helper output",
            "live_trace.standalone_k_pre_bias_bf16_bits",
            "live_trace.standalone_k_gemm_output_full_bf16_bits",
            &standalone_pre_bias,
            &fixed_helper_output,
            token_count,
            kv_dim,
            head_dim,
        )?,
        grouped_pre_rope_k_step_summary(
            "grouped_k_reshape_view",
            "flat [token, kv_dim] K interpreted as grouped [token, kv_head, lane]",
            "live_trace.standalone_k_pre_bias_bf16_bits as grouped K",
            "CPU BF16 row-major K GEMM reference as grouped K",
            &standalone_pre_bias,
            &cpu_helper_reference,
            token_count,
            kv_dim,
            head_dim,
        )?,
        grouped_pre_rope_k_step_summary(
            "copy_cast_or_bias_pack_before_rope",
            "BF16 K bias add / copy-pack surface before RoPE",
            "live_trace.standalone_k_post_bias_bf16_bits",
            copy_pack_reference_name,
            &standalone_post_bias,
            &expected_post_bias,
            token_count,
            kv_dim,
            head_dim,
        )?,
        grouped_pre_rope_k_step_summary(
            "full_qkv_k_slice_readout_after_pack",
            "K slice read back from the full QKV buffer after local packing",
            "live_trace.fused_k_slice_bf16_bits",
            "live_trace.standalone_k_post_bias_bf16_bits",
            &fused_k_slice,
            &standalone_post_bias,
            token_count,
            kv_dim,
            head_dim,
        )?,
        grouped_pre_rope_k_step_summary(
            "final_grouped_pre_rope_k",
            "final local grouped pre-RoPE K compared to authoritative PPP grouped pre-RoPE K",
            "live_trace.standalone_k_post_bias_bf16_bits",
            "official_k_rope_bundle.layer0_k_pre_rope_f32",
            &standalone_post_bias,
            &official_k_rope_bundle.layer0_k_pre_rope_f32,
            token_count,
            kv_dim,
            head_dim,
        )?,
    ];

    let helper_matches = per_step_metrics[0].metrics.matched;
    let slice_matches = per_step_metrics[1].metrics.matched;
    let grouped_matches = per_step_metrics[2].metrics.matched;
    let copy_pack_matches = per_step_metrics[3].metrics.matched;
    let full_qkv_readout_matches = per_step_metrics[4].metrics.matched;
    let final_matches = per_step_metrics[5].metrics.matched;

    let (earliest_operation_where_mismatch_appears, classification, next_bounded_step) =
        if !helper_matches {
            (
                "fixed_all_token_k_helper_output",
                "grouped_pre_rope_k_reference_or_measurement_mismatch",
                "re-run the all-token K pedantic helper proof before inspecting grouped pre-RoPE assembly",
            )
        } else if !slice_matches {
            (
                "k_slice_extraction_from_helper_output",
                "k_slice_extraction_mismatch_after_helper_fix",
                "inspect the helper-output to K-slice extraction surface only",
            )
        } else if !grouped_matches {
            (
                "grouped_k_reshape_view",
                "grouped_k_layout_or_view_mismatch_after_helper_fix",
                "inspect the grouped [token, kv_head, lane] K layout/view interpretation before RoPE",
            )
        } else if !copy_pack_matches || !full_qkv_readout_matches {
            (
                "copy_cast_or_bias_pack_before_rope",
                "grouped_k_copy_cast_or_pack_mismatch_after_helper_fix",
                "inspect the local copy/cast/pack surface from standalone K into the pre-RoPE K buffer",
            )
        } else if !final_matches {
            (
                "final_grouped_pre_rope_k",
                "grouped_pre_rope_k_reference_or_measurement_mismatch",
                "compare the captured local K bias and official grouped pre-RoPE semantics under the exact case",
            )
        } else {
            (
                "none",
                "grouped_pre_rope_k_reference_or_measurement_mismatch",
                "rerun k-downstream-after-pedantic-fix-status because grouped pre-RoPE now matches in this breakdown",
            )
        };

    let runtime_forward_grouped_pre_rope_k_source_breakdown_status_now = format!(
        "runtime-forward grouped pre-RoPE K source breakdown status now: helper max_abs={} mean_abs={} matched={}; slice max_abs={} mean_abs={} matched={}; grouped_view max_abs={} mean_abs={} matched={}; copy_pack max_abs={} mean_abs={} matched={}; full_qkv_readout max_abs={} mean_abs={} matched={}; final_vs_official max_abs={} mean_abs={} matched={}; earliest_operation={}; classification={}; next bounded step: {}.",
        per_step_metrics[0].metrics.max_abs_diff,
        per_step_metrics[0].metrics.mean_abs_diff,
        per_step_metrics[0].metrics.matched,
        per_step_metrics[1].metrics.max_abs_diff,
        per_step_metrics[1].metrics.mean_abs_diff,
        per_step_metrics[1].metrics.matched,
        per_step_metrics[2].metrics.max_abs_diff,
        per_step_metrics[2].metrics.mean_abs_diff,
        per_step_metrics[2].metrics.matched,
        per_step_metrics[3].metrics.max_abs_diff,
        per_step_metrics[3].metrics.mean_abs_diff,
        per_step_metrics[3].metrics.matched,
        per_step_metrics[4].metrics.max_abs_diff,
        per_step_metrics[4].metrics.mean_abs_diff,
        per_step_metrics[4].metrics.matched,
        per_step_metrics[5].metrics.max_abs_diff,
        per_step_metrics[5].metrics.mean_abs_diff,
        per_step_metrics[5].metrics.matched,
        earliest_operation_where_mismatch_appears,
        classification,
        next_bounded_step
    );

    let summary = GroupedPreRopeKSourceBreakdownStatusSummary {
        schema_version: "runtime_forward_layer0_grouped_pre_rope_k_source_breakdown_status/v1"
            .into(),
        exact_case: KGainPreservationExactCase {
            case_id: attn_norm_case.id.clone(),
            input_token_ids: attn_norm_case.input_token_ids.clone(),
            hidden_size: exact_hidden_size,
            num_tokens: live_trace.num_tokens,
            q_dim: live_trace.q_dim,
            kv_dim: live_trace.kv_dim,
            qkv_dim: live_trace.qkv_dim,
        },
        mode: "grouped-pre-rope-k-source-breakdown-status".into(),
        source_downstream_artifact_path: source_downstream_artifact_path.clone(),
        files_changed_already_in_fix,
        k_helper_pedantic_path_active,
        provenance: GroupedPreRopeKSourceBreakdownProvenance {
            local_attn_norm_artifact_path: cli.local_attn_norm_artifact.clone(),
            source_downstream_artifact_path,
            source_fix_artifact_path,
            official_k_rope_bundle_artifact_path: cli.official_k_rope_bundle_artifact.clone(),
            model_root: attn_norm_artifact.provenance.model.clone(),
            visible_devices,
            dense_qkv_env_var: BF16_DENSE_QKV_ENV.to_string(),
        },
        per_step_metrics,
        earliest_operation_where_mismatch_appears: earliest_operation_where_mismatch_appears.into(),
        classification: classification.into(),
        runtime_forward_grouped_pre_rope_k_source_breakdown_status_now,
        next_bounded_step: next_bounded_step.into(),
    };

    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::GroupedPreRopeKSourceBreakdownStatus.default_output());
    write_pretty_json(&output, &summary)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn run_grouped_pre_rope_k_bias_reference_semantics_status(cli: &Cli) -> Result<()> {
    let source_artifact_path =
        PathBuf::from(DEFAULT_GROUPED_PRE_ROPE_K_SOURCE_BREAKDOWN_STATUS_OUTPUT);
    let source_artifact: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_artifact_path).with_context(|| {
            format!(
                "failed to read grouped pre-RoPE source breakdown artifact {}",
                source_artifact_path.display()
            )
        })?,
    )
    .with_context(|| {
        format!(
            "failed to parse grouped pre-RoPE source breakdown artifact {}",
            source_artifact_path.display()
        )
    })?;
    if source_artifact
        .get("classification")
        .and_then(serde_json::Value::as_str)
        != Some("grouped_pre_rope_k_reference_or_measurement_mismatch")
    {
        bail!(
            "source artifact classification is not grouped_pre_rope_k_reference_or_measurement_mismatch: {}",
            source_artifact_path.display()
        );
    }
    if source_artifact
        .get("k_helper_pedantic_path_active")
        .and_then(serde_json::Value::as_bool)
        != Some(true)
    {
        bail!(
            "source artifact does not confirm active pedantic K helper: {}",
            source_artifact_path.display()
        );
    }

    let source_downstream_artifact_path =
        PathBuf::from(DEFAULT_K_DOWNSTREAM_AFTER_PEDANTIC_FIX_STATUS_OUTPUT);
    let source_fix_artifact_path =
        PathBuf::from(DEFAULT_ALL_TOKEN_K_PEDANTIC_RUNTIME_FIX_STATUS_OUTPUT);
    let official_k_rope_bundle =
        load_official_k_rope_bundle_artifact(&cli.official_k_rope_bundle_artifact)?;
    if official_k_rope_bundle.case_id != "developer-message-user-smoke" {
        bail!(
            "official K RoPE bundle is not the exact smoke case: {}",
            official_k_rope_bundle.case_id
        );
    }

    let (attn_norm_artifact, attn_norm_case) =
        load_single_case_artifact(&cli.local_attn_norm_artifact)?;
    let exact_hidden_size = attn_norm_case
        .hidden_size
        .context("exact smoke case missing hidden_size")?;
    validate_exact_case_artifact(
        &attn_norm_artifact,
        &attn_norm_case,
        "layer0_attn_norm_output",
        "developer-message-user-smoke",
        &attn_norm_case.input_token_ids,
    )?;
    if official_k_rope_bundle.input_token_ids != attn_norm_case.input_token_ids {
        bail!("official K RoPE bundle token IDs do not match the exact local case");
    }

    let model_root = Path::new(&attn_norm_artifact.provenance.model);
    let max_model_len = attn_norm_artifact.provenance.max_model_len.unwrap_or(128);
    let gpu_memory_utilization = attn_norm_artifact
        .provenance
        .gpu_memory_utilization
        .unwrap_or(0.75);
    let visible_devices = attn_norm_artifact
        .provenance
        .visible_devices
        .clone()
        .unwrap_or_else(|| env::var("CUDA_VISIBLE_DEVICES").unwrap_or_else(|_| "<unset>".into()));

    info!(
        model_root = %model_root.display(),
        max_model_len,
        gpu_memory_utilization,
        visible_devices = %visible_devices,
        "starting exact-case grouped pre-RoPE K bias/reference semantics status run"
    );

    let _guard = EnvFlagGuard::set(BF16_DENSE_QKV_ENV, true);
    let worker = build_worker(model_root, max_model_len, gpu_memory_utilization)?;
    let live_trace = capture_layer0_qkv_trace(&worker, &attn_norm_case.input_token_ids)?;
    if !live_trace.branch_taken {
        bail!("grouped pre-RoPE K bias/reference trace did not take the bf16 fused-qkv branch");
    }
    let token_count = live_trace.num_tokens;
    let kv_dim = live_trace.kv_dim;
    let q_dim = live_trace.q_dim;
    let head_dim = official_k_rope_bundle.layer0_k_rope_state.head_dim;
    if token_count != official_k_rope_bundle.token_count || kv_dim != official_k_rope_bundle.kv_dim
    {
        bail!(
            "live K dimensions [{}, {}] do not match official [{}, {}]",
            token_count,
            kv_dim,
            official_k_rope_bundle.token_count,
            official_k_rope_bundle.kv_dim
        );
    }

    let activation_full_bf16 =
        bf16_bits_to_bf16_slice(&live_trace.standalone_activation_full_bf16_bits);
    let standalone_k_weight_bf16 =
        bf16_bits_to_bf16_slice(&live_trace.standalone_k_weight_bf16_bits);
    let cpu_helper_reference_bf16 = cpu_bf16_row_major_gemm(
        &activation_full_bf16,
        &standalone_k_weight_bf16,
        token_count,
        kv_dim,
        exact_hidden_size,
    )?;
    let cpu_helper_reference = bf16_slice_to_f32(&cpu_helper_reference_bf16);
    let helper_output = bf16_bits_to_f32_slice(&live_trace.standalone_k_gemm_output_full_bf16_bits);
    let local_pre_bias = bf16_bits_to_f32_slice(&live_trace.standalone_k_pre_bias_bf16_bits);
    let local_post_bias = bf16_bits_to_f32_slice(&live_trace.standalone_k_post_bias_bf16_bits);
    if local_pre_bias.len() != token_count * kv_dim
        || local_post_bias.len() != token_count * kv_dim
        || helper_output.len() != token_count * kv_dim
    {
        bail!("one or more local grouped pre-RoPE K tensors have unexpected length");
    }

    let (bias_present, bias_shape, bias_dtype, bias_source, local_bias_added) =
        if live_trace.canonical_k_bias_bf16_bits.is_empty() {
            (
                false,
                vec![0],
                "bf16".to_string(),
                "no captured K bias tensor/slice for this exact grouped K path".to_string(),
                local_pre_bias.clone(),
            )
        } else if live_trace.canonical_k_bias_bf16_bits.len() == kv_dim {
            let bias_bf16 = bf16_bits_to_bf16_slice(&live_trace.canonical_k_bias_bf16_bits);
            let local_bias_added_bf16 = add_k_bias_bf16_output(
                &bf16_bits_to_bf16_slice(&live_trace.standalone_k_pre_bias_bf16_bits),
                &bias_bf16,
                token_count,
                kv_dim,
            )?;
            (
                true,
                vec![kv_dim],
                "bf16".to_string(),
                "live_trace.canonical_k_bias_bf16_bits".to_string(),
                bf16_slice_to_f32(&local_bias_added_bf16),
            )
        } else {
            bail!(
                "canonical K bias length mismatch: expected {} or 0, found {}",
                kv_dim,
                live_trace.canonical_k_bias_bf16_bits.len()
            );
        };

    let local_pre_bias_vs_local_post_bias = compare_vectors(&local_pre_bias, &local_post_bias)?;
    let helper_output_vs_cpu_reference = compare_vectors(&helper_output, &cpu_helper_reference)?;
    let local_no_bias_grouped_k_vs_official = compare_vectors(
        &local_pre_bias,
        &official_k_rope_bundle.layer0_k_pre_rope_f32,
    )?;
    let local_bias_added_grouped_k_vs_official = compare_vectors(
        &local_bias_added,
        &official_k_rope_bundle.layer0_k_pre_rope_f32,
    )?;
    let local_helper_reference_k_path_vs_official = compare_vectors(
        &cpu_helper_reference,
        &official_k_rope_bundle.layer0_k_pre_rope_f32,
    )?;
    let local_post_bias_grouped_k_vs_official = compare_vectors(
        &local_post_bias,
        &official_k_rope_bundle.layer0_k_pre_rope_f32,
    )?;

    let bias_already_included_in_helper_output = bias_present
        && compare_vectors(&helper_output, &local_post_bias)?.matched
        && !compare_vectors(&helper_output, &local_pre_bias)?.matched;
    let bias_metadata = GroupedPreRopeKBiasMetadata {
        present: bias_present,
        shape: bias_shape,
        dtype: bias_dtype,
        source: bias_source,
        bias_slice_offsets_used: if bias_present {
            Some(vec![q_dim, q_dim + kv_dim])
        } else {
            None
        },
        bias_already_included_in_helper_output,
    };

    let local_bias_application_bug = bias_present
        && !compare_vectors(&local_bias_added, &local_post_bias)?.matched
        || (!bias_present && !local_pre_bias_vs_local_post_bias.matched);
    let classification = if local_no_bias_grouped_k_vs_official.matched {
        "official_grouped_pre_rope_k_is_pre_bias"
    } else if local_bias_added_grouped_k_vs_official.matched {
        "official_grouped_pre_rope_k_is_post_bias_and_local_measurement_bug"
    } else if local_bias_application_bug {
        "local_grouped_pre_rope_k_bias_application_bug"
    } else if helper_output_vs_cpu_reference.matched
        && !local_no_bias_grouped_k_vs_official.matched
        && !local_bias_added_grouped_k_vs_official.matched
    {
        "official_grouped_pre_rope_k_reference_semantics_mismatch"
    } else {
        "official_grouped_pre_rope_k_reference_semantics_mismatch"
    };
    let next_bounded_step = match classification {
        "official_grouped_pre_rope_k_is_pre_bias" => {
            "treat official grouped pre-RoPE K as pre-bias and rerun downstream K comparisons against the no-bias local tensor"
        }
        "official_grouped_pre_rope_k_is_post_bias_and_local_measurement_bug" => {
            "repair the local grouped pre-RoPE measurement to use the bias-added tensor consistently"
        }
        "local_grouped_pre_rope_k_bias_application_bug" => {
            "inspect only the local K bias application surface before RoPE under the exact case"
        }
        "official_grouped_pre_rope_k_reference_semantics_mismatch" => {
            "ask PPP to clarify the grouped pre-RoPE K reference semantics or compare against the CPU helper-reference K path before returning to RoPE"
        }
        _ => "keep scope on grouped pre-RoPE K reference semantics",
    };

    let first_differing_token_head_lane = GroupedPreRopeKBiasReferenceFirstDiffs {
        local_no_bias_grouped_k_vs_official: first_differing_k_lane(
            &local_pre_bias,
            &official_k_rope_bundle.layer0_k_pre_rope_f32,
            token_count,
            kv_dim,
            head_dim,
        )?,
        local_bias_added_grouped_k_vs_official: first_differing_k_lane(
            &local_bias_added,
            &official_k_rope_bundle.layer0_k_pre_rope_f32,
            token_count,
            kv_dim,
            head_dim,
        )?,
        local_helper_reference_k_path_vs_official: first_differing_k_lane(
            &cpu_helper_reference,
            &official_k_rope_bundle.layer0_k_pre_rope_f32,
            token_count,
            kv_dim,
            head_dim,
        )?,
        local_post_bias_grouped_k_vs_official: first_differing_k_lane(
            &local_post_bias,
            &official_k_rope_bundle.layer0_k_pre_rope_f32,
            token_count,
            kv_dim,
            head_dim,
        )?,
    };

    let comparison_metrics = GroupedPreRopeKBiasReferenceComparisons {
        local_pre_bias_vs_local_post_bias,
        helper_output_vs_cpu_reference,
        local_no_bias_grouped_k_vs_official,
        local_bias_added_grouped_k_vs_official,
        local_helper_reference_k_path_vs_official,
        local_post_bias_grouped_k_vs_official,
    };

    let runtime_forward_grouped_pre_rope_k_bias_reference_semantics_status_now = format!(
        "runtime-forward grouped pre-RoPE K bias/reference semantics status now: bias_present={} bias_shape={:?}; no_bias_vs_official max_abs={} mean_abs={} matched={}; bias_added_vs_official max_abs={} mean_abs={} matched={}; helper_reference_vs_official max_abs={} mean_abs={} matched={}; classification={}; next bounded step: {}.",
        bias_metadata.present,
        bias_metadata.shape,
        comparison_metrics.local_no_bias_grouped_k_vs_official.max_abs_diff,
        comparison_metrics.local_no_bias_grouped_k_vs_official.mean_abs_diff,
        comparison_metrics.local_no_bias_grouped_k_vs_official.matched,
        comparison_metrics.local_bias_added_grouped_k_vs_official.max_abs_diff,
        comparison_metrics.local_bias_added_grouped_k_vs_official.mean_abs_diff,
        comparison_metrics.local_bias_added_grouped_k_vs_official.matched,
        comparison_metrics.local_helper_reference_k_path_vs_official.max_abs_diff,
        comparison_metrics.local_helper_reference_k_path_vs_official.mean_abs_diff,
        comparison_metrics.local_helper_reference_k_path_vs_official.matched,
        classification,
        next_bounded_step
    );

    let summary = GroupedPreRopeKBiasReferenceSemanticsStatusSummary {
        schema_version:
            "runtime_forward_layer0_grouped_pre_rope_k_bias_reference_semantics_status/v1".into(),
        exact_case: KGainPreservationExactCase {
            case_id: attn_norm_case.id.clone(),
            input_token_ids: attn_norm_case.input_token_ids.clone(),
            hidden_size: exact_hidden_size,
            num_tokens: live_trace.num_tokens,
            q_dim: live_trace.q_dim,
            kv_dim: live_trace.kv_dim,
            qkv_dim: live_trace.qkv_dim,
        },
        mode: "grouped-pre-rope-k-bias-reference-semantics-status".into(),
        source_artifact_path: source_artifact_path.clone(),
        k_helper_pedantic_path_active: true,
        provenance: GroupedPreRopeKBiasReferenceSemanticsProvenance {
            local_attn_norm_artifact_path: cli.local_attn_norm_artifact.clone(),
            source_artifact_path,
            source_downstream_artifact_path,
            source_fix_artifact_path,
            official_k_rope_bundle_artifact_path: cli.official_k_rope_bundle_artifact.clone(),
            model_root: attn_norm_artifact.provenance.model.clone(),
            visible_devices,
            dense_qkv_env_var: BF16_DENSE_QKV_ENV.to_string(),
        },
        bias_metadata,
        comparison_metrics,
        first_differing_token_head_lane,
        classification: classification.into(),
        runtime_forward_grouped_pre_rope_k_bias_reference_semantics_status_now,
        next_bounded_step: next_bounded_step.into(),
    };

    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::GroupedPreRopeKBiasReferenceSemanticsStatus.default_output());
    write_pretty_json(&output, &summary)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn run_grouped_pre_rope_k_current_path_status(cli: &Cli) -> Result<()> {
    let source_rmsnorm_residual_artifact_path =
        PathBuf::from(DEFAULT_LAYER0_ATTN_RMSNORM_LIVE_CUDA_RESIDUAL_LANE_STATUS_OUTPUT);
    let source_rmsnorm_bf16_fix_artifact_path =
        PathBuf::from(DEFAULT_LAYER0_ATTN_RMSNORM_BF16_RUNTIME_FIX_STATUS_OUTPUT);
    let source_k_pedantic_helper_fix_artifact_path =
        PathBuf::from(DEFAULT_ALL_TOKEN_K_PEDANTIC_RUNTIME_FIX_STATUS_OUTPUT);

    let rmsnorm_residual_artifact: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_rmsnorm_residual_artifact_path).with_context(|| {
            format!(
                "failed to read RMSNorm residual artifact {}",
                source_rmsnorm_residual_artifact_path.display()
            )
        })?,
    )?;
    let rmsnorm_fix_artifact: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_rmsnorm_bf16_fix_artifact_path).with_context(|| {
            format!(
                "failed to read RMSNorm BF16 fix artifact {}",
                source_rmsnorm_bf16_fix_artifact_path.display()
            )
        })?,
    )?;
    let k_pedantic_fix_artifact: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_k_pedantic_helper_fix_artifact_path).with_context(
            || {
                format!(
                    "failed to read K pedantic helper fix artifact {}",
                    source_k_pedantic_helper_fix_artifact_path.display()
                )
            },
        )?,
    )?;
    if rmsnorm_residual_artifact
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || rmsnorm_fix_artifact
            .pointer("/exact_case/case_id")
            .and_then(serde_json::Value::as_str)
            != Some("developer-message-user-smoke")
        || k_pedantic_fix_artifact
            .pointer("/exact_case/case_id")
            .and_then(serde_json::Value::as_str)
            != Some("developer-message-user-smoke")
    {
        bail!("source artifacts are not all the exact smoke case");
    }
    if rmsnorm_residual_artifact
        .get("classification")
        .and_then(serde_json::Value::as_str)
        != Some("live_cuda_rmsnorm_final_token_residual_cleared_or_prior_measurement_bug")
    {
        bail!("RMSNorm residual artifact does not confirm final-token residual is cleared");
    }
    if k_pedantic_fix_artifact
        .get("classification")
        .and_then(serde_json::Value::as_str)
        != Some("all_token_k_pedantic_runtime_fix_proven")
    {
        bail!("K pedantic helper fix artifact is not proven");
    }

    let active_rmsnorm_policy = rmsnorm_fix_artifact
        .get("new_live_policy")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("unknown")
        .to_string();
    let rmsnorm_bf16_path_active = rmsnorm_fix_artifact
        .get("scoped_only_to_layer0_attention_rmsnorm")
        .and_then(serde_json::Value::as_bool)
        .unwrap_or(false)
        && active_rmsnorm_policy == "bf16_input_bf16_weight_f32_reduction_bf16_output";
    let active_k_helper_gemm_policy = k_pedantic_fix_artifact
        .get("cublas_settings_now_used")
        .cloned()
        .context("K pedantic fix artifact missing cublas_settings_now_used")?;
    let k_helper_pedantic_path_active = k_pedantic_fix_artifact
        .get("live_fixed_full_m74_matches_cpu")
        .and_then(serde_json::Value::as_bool)
        .unwrap_or(false)
        && active_k_helper_gemm_policy
            .get("math_mode")
            .and_then(serde_json::Value::as_str)
            == Some("CUBLAS_PEDANTIC_MATH")
        && active_k_helper_gemm_policy
            .get("compute_type")
            .and_then(serde_json::Value::as_str)
            == Some("CUBLAS_COMPUTE_32F_PEDANTIC")
        && active_k_helper_gemm_policy
            .get("algo")
            .and_then(serde_json::Value::as_str)
            == Some("CUBLAS_GEMM_DFALT");

    let official_k_rope_bundle =
        load_official_k_rope_bundle_artifact(&cli.official_k_rope_bundle_artifact)?;
    if official_k_rope_bundle.case_id != "developer-message-user-smoke" {
        bail!("official K RoPE bundle is not the exact smoke case");
    }
    let official_capture_path = cli.official_attn_norm_full_input_capture_artifact.clone();
    let official_capture: FullAttnNormOfficialCapture = serde_json::from_str(
        &std::fs::read_to_string(&official_capture_path).with_context(|| {
            format!(
                "failed to read official full attn.norm capture {}",
                official_capture_path.display()
            )
        })?,
    )?;
    if official_capture.case_id != "developer-message-user-smoke" {
        bail!("official full attn.norm capture is not the exact smoke case");
    }

    let (attn_norm_artifact, attn_norm_case) =
        load_single_case_artifact(&cli.local_attn_norm_artifact)?;
    let exact_hidden_size = attn_norm_case
        .hidden_size
        .context("exact smoke case missing hidden_size")?;
    validate_exact_case_artifact(
        &attn_norm_artifact,
        &attn_norm_case,
        "layer0_attn_norm_output",
        "developer-message-user-smoke",
        &attn_norm_case.input_token_ids,
    )?;
    if official_k_rope_bundle.input_token_ids != attn_norm_case.input_token_ids
        || official_capture.input_token_ids != attn_norm_case.input_token_ids
    {
        bail!("official/runtime token IDs do not match the exact case");
    }

    let model_root = Path::new(&attn_norm_artifact.provenance.model);
    let max_model_len = attn_norm_artifact.provenance.max_model_len.unwrap_or(128);
    let gpu_memory_utilization = attn_norm_artifact
        .provenance
        .gpu_memory_utilization
        .unwrap_or(0.75);
    let visible_devices = attn_norm_artifact
        .provenance
        .visible_devices
        .clone()
        .unwrap_or_else(|| env::var("CUDA_VISIBLE_DEVICES").unwrap_or_else(|_| "<unset>".into()));

    info!(
        model_root = %model_root.display(),
        max_model_len,
        gpu_memory_utilization,
        visible_devices = %visible_devices,
        "starting exact-case grouped pre-RoPE K current path status run"
    );

    let _guard = EnvFlagGuard::set(BF16_DENSE_QKV_ENV, true);
    let worker = build_worker(model_root, max_model_len, gpu_memory_utilization)?;
    let live_trace = capture_layer0_qkv_trace(&worker, &attn_norm_case.input_token_ids)?;
    if !live_trace.branch_taken {
        bail!("grouped pre-RoPE K current path trace did not take the bf16 fused-qkv branch");
    }
    let token_count = live_trace.num_tokens;
    let kv_dim = live_trace.kv_dim;
    let head_dim = official_k_rope_bundle.layer0_k_rope_state.head_dim;
    if token_count != official_k_rope_bundle.token_count
        || kv_dim != official_k_rope_bundle.kv_dim
        || official_capture.token_count != token_count
        || official_capture.hidden_size != exact_hidden_size
    {
        bail!("live, official K, and official attn.norm shapes do not agree");
    }

    let current_attn_norm_output =
        bf16_bits_to_f32_slice(&live_trace.standalone_activation_full_bf16_bits);
    let upstream_attn_norm_provenance_metrics = compare_vectors(
        &current_attn_norm_output,
        &official_capture.layer0_attn_norm_output_f32,
    )?;

    let activation_full_bf16 =
        bf16_bits_to_bf16_slice(&live_trace.standalone_activation_full_bf16_bits);
    let standalone_k_weight_bf16 =
        bf16_bits_to_bf16_slice(&live_trace.standalone_k_weight_bf16_bits);
    let cpu_reference_k_bf16 = cpu_bf16_row_major_gemm(
        &activation_full_bf16,
        &standalone_k_weight_bf16,
        token_count,
        kv_dim,
        exact_hidden_size,
    )?;
    let cpu_reference_k = bf16_slice_to_f32(&cpu_reference_k_bf16);
    let live_k_helper_output =
        bf16_bits_to_f32_slice(&live_trace.standalone_k_gemm_output_full_bf16_bits);
    let k_helper_guard_metrics = compare_vectors(&live_k_helper_output, &cpu_reference_k)?;

    let local_grouped_pre_rope_k =
        bf16_bits_to_f32_slice(&live_trace.standalone_k_post_bias_bf16_bits);
    let official_grouped_pre_rope_k = &official_k_rope_bundle.layer0_k_pre_rope_f32;
    let grouped_pre_rope_k_metrics =
        compare_vectors(&local_grouped_pre_rope_k, official_grouped_pre_rope_k)?;
    let first_differing_token_head_lane = first_differing_k_lane(
        &local_grouped_pre_rope_k,
        official_grouped_pre_rope_k,
        token_count,
        kv_dim,
        head_dim,
    )?;
    let worst_differing_token_head_lane = worst_differing_k_lane(
        &local_grouped_pre_rope_k,
        official_grouped_pre_rope_k,
        token_count,
        kv_dim,
        head_dim,
    )?;

    let classification = if !upstream_attn_norm_provenance_metrics.matched {
        "upstream_layer0_attn_norm_still_mismatches_current_path"
    } else if !k_helper_guard_metrics.matched {
        "all_token_k_pedantic_helper_regressed"
    } else if grouped_pre_rope_k_metrics.matched {
        "grouped_pre_rope_k_cleared_after_rmsnorm_and_k_fixes"
    } else {
        "grouped_pre_rope_k_still_mismatches_after_current_fixes"
    };
    let next_bounded_step = match classification {
        "upstream_layer0_attn_norm_still_mismatches_current_path" => {
            "stay on current all-token layer0 attention RMSNorm output before re-attributing grouped pre-RoPE K"
        }
        "all_token_k_pedantic_helper_regressed" => {
            "rerun the all-token K pedantic helper proof before inspecting grouped K assembly"
        }
        "grouped_pre_rope_k_cleared_after_rmsnorm_and_k_fixes" => {
            "advance one narrow seam to grouped post-RoPE K with the current runtime path"
        }
        "grouped_pre_rope_k_still_mismatches_after_current_fixes" => {
            "inspect the remaining grouped pre-RoPE K assembly/reference delta with the current RMSNorm and pedantic K helper paths active"
        }
        _ => "keep scope on grouped pre-RoPE K current path",
    };

    let runtime_forward_grouped_pre_rope_k_current_path_status_now = format!(
        "runtime-forward grouped pre-RoPE K current path status now: attn_norm max_abs={} mean_abs={} matched={}; k_helper_guard max_abs={} mean_abs={} matched={}; grouped_pre_rope max_abs={} mean_abs={} matched={}; classification={}; next bounded step: {}.",
        upstream_attn_norm_provenance_metrics.max_abs_diff,
        upstream_attn_norm_provenance_metrics.mean_abs_diff,
        upstream_attn_norm_provenance_metrics.matched,
        k_helper_guard_metrics.max_abs_diff,
        k_helper_guard_metrics.mean_abs_diff,
        k_helper_guard_metrics.matched,
        grouped_pre_rope_k_metrics.max_abs_diff,
        grouped_pre_rope_k_metrics.mean_abs_diff,
        grouped_pre_rope_k_metrics.matched,
        classification,
        next_bounded_step
    );

    let metrics = GroupedPreRopeKCurrentPathMetrics {
        upstream_attn_norm_output_vs_official: upstream_attn_norm_provenance_metrics.clone(),
        k_helper_output_vs_cpu_reference: k_helper_guard_metrics.clone(),
        grouped_pre_rope_k_vs_official: grouped_pre_rope_k_metrics.clone(),
    };
    let summary = GroupedPreRopeKCurrentPathStatusSummary {
        schema_version: "runtime_forward_layer0_grouped_pre_rope_k_current_path_status/v1".into(),
        exact_case: KGainPreservationExactCase {
            case_id: attn_norm_case.id.clone(),
            input_token_ids: attn_norm_case.input_token_ids.clone(),
            hidden_size: exact_hidden_size,
            num_tokens: token_count,
            q_dim: live_trace.q_dim,
            kv_dim,
            qkv_dim: live_trace.qkv_dim,
        },
        mode: "grouped-pre-rope-k-current-path-status".into(),
        source_rmsnorm_residual_artifact_path,
        source_rmsnorm_bf16_fix_artifact_path,
        source_k_pedantic_helper_fix_artifact_path,
        active_rmsnorm_policy,
        active_k_helper_gemm_policy,
        rmsnorm_bf16_path_active,
        k_helper_pedantic_path_active,
        upstream_attn_norm_provenance_metrics: upstream_attn_norm_provenance_metrics.clone(),
        k_helper_guard_metrics: k_helper_guard_metrics.clone(),
        grouped_pre_rope_k_metrics: grouped_pre_rope_k_metrics.clone(),
        local_grouped_pre_rope_k_metadata: GroupedPreRopeKTensorMetadata {
            tensor_name: "live_trace.standalone_k_post_bias_bf16_bits".into(),
            shape: vec![token_count, kv_dim / head_dim, head_dim],
            dtype: "bf16_serialized_as_f32".into(),
            logical_layout: "token-major [token, kv_head, lane]".into(),
            physical_stride: vec![kv_dim, head_dim, 1],
        },
        official_grouped_pre_rope_k_metadata: GroupedPreRopeKTensorMetadata {
            tensor_name: "official_k_rope_bundle.layer0_k_pre_rope_f32".into(),
            shape: vec![token_count, kv_dim / head_dim, head_dim],
            dtype: "bf16_serialized_as_f32".into(),
            logical_layout: "token-major [token, kv_head, lane]".into(),
            physical_stride: vec![kv_dim, head_dim, 1],
        },
        first_differing_token_head_lane,
        worst_differing_token_head_lane,
        metrics,
        classification: classification.into(),
        runtime_forward_grouped_pre_rope_k_current_path_status_now,
        next_bounded_step: next_bounded_step.into(),
    };

    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::GroupedPreRopeKCurrentPathStatus.default_output());
    write_pretty_json(&output, &summary)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn run_k_helper_reference_vs_official_qkv_arithmetic_status(cli: &Cli) -> Result<()> {
    let source_ppp_artifact_path = cli
        .ppp_grouped_pre_rope_k_reference_semantics_status_artifact
        .clone();
    let source_ppp_artifact: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_ppp_artifact_path).with_context(|| {
            format!(
                "failed to read PPP grouped pre-RoPE semantics artifact {}",
                source_ppp_artifact_path.display()
            )
        })?,
    )
    .with_context(|| {
        format!(
            "failed to parse PPP grouped pre-RoPE semantics artifact {}",
            source_ppp_artifact_path.display()
        )
    })?;
    if source_ppp_artifact
        .get("classification")
        .and_then(serde_json::Value::as_str)
        != Some("runtime_k_reference_path_not_authoritative_enough")
    {
        bail!(
            "PPP grouped pre-RoPE semantics artifact classification is not runtime_k_reference_path_not_authoritative_enough: {}",
            source_ppp_artifact_path.display()
        );
    }

    let source_runtime_artifact_path =
        PathBuf::from(DEFAULT_GROUPED_PRE_ROPE_K_BIAS_REFERENCE_SEMANTICS_STATUS_OUTPUT);
    let source_runtime_artifact: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_runtime_artifact_path).with_context(|| {
            format!(
                "failed to read runtime grouped pre-RoPE bias/reference artifact {}",
                source_runtime_artifact_path.display()
            )
        })?,
    )
    .with_context(|| {
        format!(
            "failed to parse runtime grouped pre-RoPE bias/reference artifact {}",
            source_runtime_artifact_path.display()
        )
    })?;
    if source_runtime_artifact
        .get("classification")
        .and_then(serde_json::Value::as_str)
        != Some("official_grouped_pre_rope_k_reference_semantics_mismatch")
    {
        bail!(
            "runtime grouped pre-RoPE bias/reference artifact classification is not official_grouped_pre_rope_k_reference_semantics_mismatch: {}",
            source_runtime_artifact_path.display()
        );
    }

    let official_k_rope_bundle =
        load_official_k_rope_bundle_artifact(&cli.official_k_rope_bundle_artifact)?;
    if official_k_rope_bundle.case_id != "developer-message-user-smoke" {
        bail!(
            "official K RoPE bundle is not the exact smoke case: {}",
            official_k_rope_bundle.case_id
        );
    }
    let (attn_norm_artifact, attn_norm_case) =
        load_single_case_artifact(&cli.local_attn_norm_artifact)?;
    let (_, official_attn_norm_case) = load_single_case_artifact(&cli.official_attn_norm_artifact)?;
    let exact_hidden_size = attn_norm_case
        .hidden_size
        .context("exact smoke case missing hidden_size")?;
    validate_exact_case_artifact(
        &attn_norm_artifact,
        &attn_norm_case,
        "layer0_attn_norm_output",
        "developer-message-user-smoke",
        &attn_norm_case.input_token_ids,
    )?;
    if official_k_rope_bundle.input_token_ids != attn_norm_case.input_token_ids
        || official_attn_norm_case.input_token_ids != attn_norm_case.input_token_ids
    {
        bail!("official/runtime token IDs do not match the exact case");
    }

    let model_root = Path::new(&attn_norm_artifact.provenance.model);
    let max_model_len = attn_norm_artifact.provenance.max_model_len.unwrap_or(128);
    let gpu_memory_utilization = attn_norm_artifact
        .provenance
        .gpu_memory_utilization
        .unwrap_or(0.75);
    let visible_devices = attn_norm_artifact
        .provenance
        .visible_devices
        .clone()
        .unwrap_or_else(|| env::var("CUDA_VISIBLE_DEVICES").unwrap_or_else(|_| "<unset>".into()));

    info!(
        model_root = %model_root.display(),
        max_model_len,
        gpu_memory_utilization,
        visible_devices = %visible_devices,
        "starting exact-case K helper-reference vs official qkv arithmetic status run"
    );

    let _guard = EnvFlagGuard::set(BF16_DENSE_QKV_ENV, true);
    let worker = build_worker(model_root, max_model_len, gpu_memory_utilization)?;
    let live_trace = capture_layer0_qkv_trace(&worker, &attn_norm_case.input_token_ids)?;
    if !live_trace.branch_taken {
        bail!("K helper-reference vs official qkv arithmetic trace did not take the bf16 fused-qkv branch");
    }
    let token_count = live_trace.num_tokens;
    let kv_dim = live_trace.kv_dim;
    let q_dim = live_trace.q_dim;
    let qkv_dim = live_trace.qkv_dim;
    let head_dim = official_k_rope_bundle.layer0_k_rope_state.head_dim;
    if token_count != official_k_rope_bundle.token_count || kv_dim != official_k_rope_bundle.kv_dim
    {
        bail!(
            "live K dimensions [{}, {}] do not match official [{}, {}]",
            token_count,
            kv_dim,
            official_k_rope_bundle.token_count,
            official_k_rope_bundle.kv_dim
        );
    }

    let activation_full_bf16 =
        bf16_bits_to_bf16_slice(&live_trace.standalone_activation_full_bf16_bits);
    let activation_full_f32 = bf16_slice_to_f32(&activation_full_bf16);
    let standalone_k_weight_bf16 =
        bf16_bits_to_bf16_slice(&live_trace.standalone_k_weight_bf16_bits);
    let explicit_replay_bf16 = cpu_bf16_row_major_gemm(
        &activation_full_bf16,
        &standalone_k_weight_bf16,
        token_count,
        kv_dim,
        exact_hidden_size,
    )?;
    let explicit_replay = bf16_slice_to_f32(&explicit_replay_bf16);
    let helper_reference = explicit_replay.clone();
    let live_fixed_helper_output =
        bf16_bits_to_f32_slice(&live_trace.standalone_k_gemm_output_full_bf16_bits);

    let input_comparison_if_available = if let Some(official_final_token_hidden) =
        &official_attn_norm_case.final_token_hidden_f32
    {
        let final_token_index = token_count
            .checked_sub(1)
            .context("trace has no final token")?;
        let final_token_start = final_token_index * exact_hidden_size;
        let local_final_token =
            &activation_full_f32[final_token_start..final_token_start + exact_hidden_size];
        KProjectionInputComparisonSummary {
            available: true,
            scope: "final_token_only_existing_official_artifact".into(),
            local_tensor_name: "live_trace.standalone_activation_full_bf16_bits[final_token]"
                .into(),
            official_tensor_name: "official layer0_attn_norm_output.final_token_hidden_f32".into(),
            local_shape: vec![exact_hidden_size],
            official_shape: vec![official_final_token_hidden.len()],
            metrics: Some(compare_vectors(
                local_final_token,
                official_final_token_hidden,
            )?),
        }
    } else {
        KProjectionInputComparisonSummary {
            available: false,
            scope: "official_normalized_hidden_input_not_available".into(),
            local_tensor_name: "live_trace.standalone_activation_full_bf16_bits".into(),
            official_tensor_name: "not_available".into(),
            local_shape: vec![token_count, exact_hidden_size],
            official_shape: vec![],
            metrics: None,
        }
    };

    let runtime_cpu_helper_reference_k_vs_official = compare_vectors(
        &helper_reference,
        &official_k_rope_bundle.layer0_k_pre_rope_f32,
    )?;
    let explicit_runtime_input_x_runtime_k_weight_replay_vs_official = compare_vectors(
        &explicit_replay,
        &official_k_rope_bundle.layer0_k_pre_rope_f32,
    )?;
    let explicit_replay_vs_helper_reference = compare_vectors(&explicit_replay, &helper_reference)?;
    let live_fixed_helper_output_vs_cpu_helper_reference =
        compare_vectors(&live_fixed_helper_output, &helper_reference)?;

    let metadata_inconsistent_with_ppp =
        q_dim + kv_dim > qkv_dim || standalone_k_weight_bf16.len() != kv_dim * exact_hidden_size;
    let input_differs = input_comparison_if_available
        .metrics
        .as_ref()
        .is_some_and(|metrics| !metrics.matched);
    let classification = if input_differs {
        "k_projection_input_mismatch"
    } else if metadata_inconsistent_with_ppp {
        "k_weight_slice_or_orientation_mismatch"
    } else if explicit_runtime_input_x_runtime_k_weight_replay_vs_official.matched
        && !runtime_cpu_helper_reference_k_vs_official.matched
    {
        "helper_reference_measurement_bug"
    } else if !explicit_runtime_input_x_runtime_k_weight_replay_vs_official.matched {
        "k_projection_arithmetic_policy_mismatch"
    } else {
        "k_projection_arithmetic_policy_mismatch"
    };
    let next_bounded_step = match classification {
        "k_projection_input_mismatch" => {
            "compare full-token runtime normalized hidden input against official PyTorch attn.norm output before changing K projection arithmetic"
        }
        "k_weight_slice_or_orientation_mismatch" => {
            "inspect the runtime fused qkv weight slicing/orientation against official attn.qkv K weight metadata only"
        }
        "helper_reference_measurement_bug" => {
            "repair the helper-reference measurement path because explicit replay matches official"
        }
        "k_projection_arithmetic_policy_mismatch" => {
            "compare runtime BF16 CPU replay policy against official PyTorch Linear arithmetic policy for the K slice under the exact case"
        }
        _ => "keep scope on exact K projection arithmetic",
    };

    let k_weight_slice_metadata = KWeightSliceMetadata {
        source_tensor_name: "layer0 fused attn.qkv weight cast to BF16; K slice".into(),
        shape: vec![kv_dim, exact_hidden_size],
        dtype: "bf16".into(),
        row_column_orientation:
            "row-major [k_output_feature, hidden]; helper computes activation[token, hidden] x K_weight^T"
                .into(),
        k_slice_offsets: vec![q_dim * exact_hidden_size, (q_dim + kv_dim) * exact_hidden_size],
        logical_layout: "[kv_dim, hidden_size]".into(),
        physical_stride: vec![exact_hidden_size, 1],
    };

    let first_differing_token_head_lane = first_differing_k_lane(
        &explicit_replay,
        &official_k_rope_bundle.layer0_k_pre_rope_f32,
        token_count,
        kv_dim,
        head_dim,
    )?;

    let metrics = KHelperReferenceVsOfficialQkvArithmeticMetrics {
        input_comparison_if_available,
        runtime_cpu_helper_reference_k_vs_official,
        explicit_runtime_input_x_runtime_k_weight_replay_vs_official,
        explicit_replay_vs_helper_reference,
        live_fixed_helper_output_vs_cpu_helper_reference,
    };

    let runtime_forward_k_helper_reference_vs_official_qkv_arithmetic_status_now = format!(
        "runtime-forward K helper-reference vs official qkv arithmetic status now: input_available={} input_max_abs={}; explicit_replay_vs_official max_abs={} mean_abs={} matched={}; helper_reference_vs_official max_abs={} mean_abs={} matched={}; classification={}; next bounded step: {}.",
        metrics.input_comparison_if_available.available,
        metrics
            .input_comparison_if_available
            .metrics
            .as_ref()
            .map(|m| m.max_abs_diff.to_string())
            .unwrap_or_else(|| "not_available".into()),
        metrics
            .explicit_runtime_input_x_runtime_k_weight_replay_vs_official
            .max_abs_diff,
        metrics
            .explicit_runtime_input_x_runtime_k_weight_replay_vs_official
            .mean_abs_diff,
        metrics
            .explicit_runtime_input_x_runtime_k_weight_replay_vs_official
            .matched,
        metrics.runtime_cpu_helper_reference_k_vs_official.max_abs_diff,
        metrics.runtime_cpu_helper_reference_k_vs_official.mean_abs_diff,
        metrics.runtime_cpu_helper_reference_k_vs_official.matched,
        classification,
        next_bounded_step
    );

    let summary = KHelperReferenceVsOfficialQkvArithmeticStatusSummary {
        schema_version:
            "runtime_forward_layer0_k_helper_reference_vs_official_qkv_arithmetic_status/v1".into(),
        exact_case: KGainPreservationExactCase {
            case_id: attn_norm_case.id.clone(),
            input_token_ids: attn_norm_case.input_token_ids.clone(),
            hidden_size: exact_hidden_size,
            num_tokens: live_trace.num_tokens,
            q_dim: live_trace.q_dim,
            kv_dim: live_trace.kv_dim,
            qkv_dim: live_trace.qkv_dim,
        },
        mode: "k-helper-reference-vs-official-qkv-arithmetic-status".into(),
        provenance: KHelperReferenceVsOfficialQkvArithmeticProvenance {
            source_ppp_artifact_path,
            source_runtime_artifact_path,
            local_attn_norm_artifact_path: cli.local_attn_norm_artifact.clone(),
            official_attn_norm_artifact_path: cli.official_attn_norm_artifact.clone(),
            official_k_rope_bundle_artifact_path: cli.official_k_rope_bundle_artifact.clone(),
            model_root: attn_norm_artifact.provenance.model.clone(),
            visible_devices,
            dense_qkv_env_var: BF16_DENSE_QKV_ENV.to_string(),
        },
        k_weight_slice_metadata,
        metrics,
        first_differing_token_head_lane,
        classification: classification.into(),
        runtime_forward_k_helper_reference_vs_official_qkv_arithmetic_status_now,
        next_bounded_step: next_bounded_step.into(),
    };

    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::KHelperReferenceVsOfficialQkvArithmeticStatus.default_output());
    write_pretty_json(&output, &summary)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn run_layer0_attn_norm_full_input_status(cli: &Cli) -> Result<()> {
    let source_artifact_path =
        PathBuf::from(DEFAULT_K_HELPER_REFERENCE_VS_OFFICIAL_QKV_ARITHMETIC_STATUS_OUTPUT);
    let source_artifact: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_artifact_path).with_context(|| {
            format!(
                "failed to read K helper-reference vs official qkv arithmetic artifact {}",
                source_artifact_path.display()
            )
        })?,
    )
    .with_context(|| {
        format!(
            "failed to parse K helper-reference vs official qkv arithmetic artifact {}",
            source_artifact_path.display()
        )
    })?;
    if source_artifact
        .get("classification")
        .and_then(serde_json::Value::as_str)
        != Some("k_projection_input_mismatch")
    {
        bail!(
            "source artifact classification is not k_projection_input_mismatch: {}",
            source_artifact_path.display()
        );
    }

    let (attn_norm_artifact, attn_norm_case) =
        load_single_case_artifact(&cli.local_attn_norm_artifact)?;
    let exact_hidden_size = attn_norm_case
        .hidden_size
        .context("exact smoke case missing hidden_size")?;
    validate_exact_case_artifact(
        &attn_norm_artifact,
        &attn_norm_case,
        "layer0_attn_norm_output",
        "developer-message-user-smoke",
        &attn_norm_case.input_token_ids,
    )?;

    let model_root = Path::new(&attn_norm_artifact.provenance.model);
    let max_model_len = attn_norm_artifact.provenance.max_model_len.unwrap_or(128);
    let gpu_memory_utilization = attn_norm_artifact
        .provenance
        .gpu_memory_utilization
        .unwrap_or(0.75);
    let visible_devices = attn_norm_artifact
        .provenance
        .visible_devices
        .clone()
        .unwrap_or_else(|| env::var("CUDA_VISIBLE_DEVICES").unwrap_or_else(|_| "<unset>".into()));

    let official_capture_path = cli.official_attn_norm_full_input_capture_artifact.clone();
    if let Some(parent) = official_capture_path.parent() {
        std::fs::create_dir_all(parent)?;
    }
    let official_capture_status = Command::new(&cli.torch_python)
        .arg(&cli.official_attn_norm_full_input_capture_script)
        .arg("--model-root")
        .arg(model_root)
        .arg("--output")
        .arg(&official_capture_path)
        .arg("--device")
        .arg("cpu")
        .status()
        .with_context(|| {
            format!(
                "failed to run official attn.norm full capture script {} with {}",
                cli.official_attn_norm_full_input_capture_script.display(),
                cli.torch_python.display()
            )
        })?;
    if !official_capture_status.success() {
        bail!(
            "official attn.norm full capture script failed with status {:?}",
            official_capture_status.code()
        );
    }

    let official_capture: FullAttnNormOfficialCapture = serde_json::from_str(
        &std::fs::read_to_string(&official_capture_path).with_context(|| {
            format!(
                "failed to read official full attn.norm capture {}",
                official_capture_path.display()
            )
        })?,
    )
    .with_context(|| {
        format!(
            "failed to parse official full attn.norm capture {}",
            official_capture_path.display()
        )
    })?;
    if official_capture.case_id != "developer-message-user-smoke"
        || official_capture.boundary != "layer0_attn_norm_output"
        || official_capture.input_token_ids != attn_norm_case.input_token_ids
    {
        bail!("official full attn.norm capture does not match the exact case/boundary");
    }

    info!(
        model_root = %model_root.display(),
        max_model_len,
        gpu_memory_utilization,
        visible_devices = %visible_devices,
        "starting exact-case layer0 attn.norm full-input status run"
    );

    let _guard = EnvFlagGuard::set(BF16_DENSE_QKV_ENV, true);
    let worker = build_worker(model_root, max_model_len, gpu_memory_utilization)?;
    let live_trace = capture_layer0_qkv_trace(&worker, &attn_norm_case.input_token_ids)?;
    if !live_trace.branch_taken {
        bail!("layer0 attn.norm full-input trace did not take the bf16 fused-qkv branch");
    }
    let token_count = live_trace.num_tokens;
    let official_output_shape = if official_capture.output_shape.is_empty() {
        official_capture.tensor_shape.clone()
    } else {
        official_capture.output_shape.clone()
    };
    let official_output_dtype = if official_capture.output_dtype.is_empty() {
        official_capture.tensor_dtype.clone()
    } else {
        official_capture.output_dtype.clone()
    };
    let official_output_layout = if official_capture.output_layout.is_empty() {
        official_capture.tensor_layout.clone()
    } else {
        official_capture.output_layout.clone()
    };
    if token_count != official_capture.token_count
        || exact_hidden_size != official_capture.hidden_size
        || official_capture.layer0_attn_norm_output_f32.len() != token_count * exact_hidden_size
    {
        bail!(
            "official capture shape does not match runtime trace: official shape {:?}, token_count {}, hidden {}",
            official_output_shape,
            token_count,
            exact_hidden_size
        );
    }

    let runtime_full = bf16_bits_to_f32_slice(&live_trace.standalone_activation_full_bf16_bits);
    if runtime_full.len() != token_count * exact_hidden_size {
        bail!(
            "runtime attn.norm full tensor has length {}, expected {}",
            runtime_full.len(),
            token_count * exact_hidden_size
        );
    }

    let official_full = official_capture.layer0_attn_norm_output_f32;
    let overall_metrics = compare_vectors(&runtime_full, &official_full)?;
    let mut per_token_summary = Vec::with_capacity(token_count);
    for token_index in 0..token_count {
        let start = token_index * exact_hidden_size;
        let metrics = compare_vectors(
            &runtime_full[start..start + exact_hidden_size],
            &official_full[start..start + exact_hidden_size],
        )?;
        per_token_summary.push(AttnNormTokenDiffSummary {
            token_index,
            max_abs_diff: metrics.max_abs_diff,
            mean_abs_diff: metrics.mean_abs_diff,
            matched: metrics.matched,
        });
    }
    let worst_token = per_token_summary
        .iter()
        .max_by(|lhs, rhs| {
            lhs.mean_abs_diff
                .partial_cmp(&rhs.mean_abs_diff)
                .unwrap_or(std::cmp::Ordering::Equal)
                .then_with(|| {
                    lhs.max_abs_diff
                        .partial_cmp(&rhs.max_abs_diff)
                        .unwrap_or(std::cmp::Ordering::Equal)
                })
        })
        .context("missing per-token summaries")?;
    let worst_token = AttnNormTokenDiffSummary {
        token_index: worst_token.token_index,
        max_abs_diff: worst_token.max_abs_diff,
        mean_abs_diff: worst_token.mean_abs_diff,
        matched: worst_token.matched,
    };
    let final_token_index = token_count
        .checked_sub(1)
        .context("trace has no final token")?;
    let final_token_start = final_token_index * exact_hidden_size;
    let final_token_metrics = compare_vectors(
        &runtime_full[final_token_start..final_token_start + exact_hidden_size],
        &official_full[final_token_start..final_token_start + exact_hidden_size],
    )?;
    let first_differing_token_hidden_lane = runtime_full
        .iter()
        .zip(official_full.iter())
        .enumerate()
        .find_map(|(flat_index, (runtime_value, official_value))| {
            if runtime_value == official_value {
                None
            } else {
                Some(FirstDifferingHiddenLaneSummary {
                    token_index: flat_index / exact_hidden_size,
                    hidden_lane_index: flat_index % exact_hidden_size,
                    flat_index,
                    runtime_value: *runtime_value,
                    official_value: *official_value,
                    abs_diff: (runtime_value - official_value).abs(),
                })
            }
        });

    let mismatching_tokens = per_token_summary
        .iter()
        .filter(|summary| !summary.matched)
        .count();
    let localized_limit = (token_count / 10).max(4);
    let classification = if overall_metrics.matched {
        "final_token_input_measurement_bug"
    } else if mismatching_tokens <= localized_limit {
        "layer0_attn_norm_localized_input_mismatch"
    } else {
        "layer0_attn_norm_broad_input_mismatch"
    };
    let next_bounded_step = match classification {
        "final_token_input_measurement_bug" => {
            "return to K projection arithmetic only after correcting the final-token input measurement"
        }
        "layer0_attn_norm_broad_input_mismatch" => {
            "inspect layer0 attention norm input and RMSNorm arithmetic across all tokens before changing QKV projection"
        }
        "layer0_attn_norm_localized_input_mismatch" => {
            "inspect token-position-specific layer0 attention norm input for the mismatching token subset"
        }
        _ => "capture an unambiguous official all-token layer0 attention norm output before proceeding",
    };

    let runtime_forward_layer0_attn_norm_full_input_status_now = format!(
        "runtime-forward layer0 attn.norm full input status now: overall max_abs={} mean_abs={} matched={}; mismatching_tokens={}/{}; worst_token={} max_abs={} mean_abs={}; final_token max_abs={} mean_abs={} matched={}; classification={}; next bounded step: {}.",
        overall_metrics.max_abs_diff,
        overall_metrics.mean_abs_diff,
        overall_metrics.matched,
        mismatching_tokens,
        token_count,
        worst_token.token_index,
        worst_token.max_abs_diff,
        worst_token.mean_abs_diff,
        final_token_metrics.max_abs_diff,
        final_token_metrics.mean_abs_diff,
        final_token_metrics.matched,
        classification,
        next_bounded_step
    );

    let summary = Layer0AttnNormFullInputStatusSummary {
        schema_version: "runtime_forward_layer0_attn_norm_full_input_status/v1".into(),
        exact_case: KGainPreservationExactCase {
            case_id: attn_norm_case.id.clone(),
            input_token_ids: attn_norm_case.input_token_ids.clone(),
            hidden_size: exact_hidden_size,
            num_tokens: token_count,
            q_dim: live_trace.q_dim,
            kv_dim: live_trace.kv_dim,
            qkv_dim: live_trace.qkv_dim,
        },
        mode: "layer0-attn-norm-full-input-status".into(),
        source_artifact_path: source_artifact_path.clone(),
        official_capture_path_or_python_script_used: format!(
            "{} via {}",
            official_capture_path.display(),
            cli.official_attn_norm_full_input_capture_script.display()
        ),
        provenance: Layer0AttnNormFullInputProvenance {
            source_artifact_path,
            local_attn_norm_artifact_path: cli.local_attn_norm_artifact.clone(),
            previous_official_final_token_artifact_path: cli.official_attn_norm_artifact.clone(),
            official_capture_path: official_capture_path.clone(),
            official_capture_script: cli.official_attn_norm_full_input_capture_script.clone(),
            torch_python: cli.torch_python.clone(),
            model_root: attn_norm_artifact.provenance.model.clone(),
            visible_devices,
            dense_qkv_env_var: BF16_DENSE_QKV_ENV.to_string(),
        },
        runtime_tensor: TensorMetadataSummary {
            shape: vec![token_count, exact_hidden_size],
            dtype: "bf16_serialized_as_f32".into(),
            layout: "token-major [token, hidden]".into(),
            source_tensor_name: "live_trace.standalone_activation_full_bf16_bits".into(),
        },
        official_tensor: TensorMetadataSummary {
            shape: official_output_shape,
            dtype: official_output_dtype,
            layout: official_output_layout,
            source_tensor_name: "official_capture.layer0_attn_norm_output_f32".into(),
        },
        overall_metrics,
        per_token_summary,
        worst_token,
        final_token_metrics,
        first_differing_token_hidden_lane,
        classification: classification.into(),
        runtime_forward_layer0_attn_norm_full_input_status_now,
        next_bounded_step: next_bounded_step.into(),
    };

    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::Layer0AttnNormFullInputStatus.default_output());
    write_pretty_json(&output, &summary)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn compare_token_major_hidden(
    lhs: &[f32],
    rhs: &[f32],
    token_count: usize,
    hidden_size: usize,
) -> Result<TensorComparisonWithTokenSummary> {
    let overall = compare_vectors(lhs, rhs)?;
    let mut worst_token: Option<AttnNormTokenDiffSummary> = None;
    let mut mismatching_tokens = 0usize;
    for token_index in 0..token_count {
        let start = token_index * hidden_size;
        let metrics = compare_vectors(
            &lhs[start..start + hidden_size],
            &rhs[start..start + hidden_size],
        )?;
        if !metrics.matched {
            mismatching_tokens += 1;
        }
        let summary = AttnNormTokenDiffSummary {
            token_index,
            max_abs_diff: metrics.max_abs_diff,
            mean_abs_diff: metrics.mean_abs_diff,
            matched: metrics.matched,
        };
        if worst_token.as_ref().is_none_or(|current| {
            summary.mean_abs_diff > current.mean_abs_diff
                || (summary.mean_abs_diff == current.mean_abs_diff
                    && summary.max_abs_diff > current.max_abs_diff)
        }) {
            worst_token = Some(summary);
        }
    }
    Ok(TensorComparisonWithTokenSummary {
        overall,
        mismatching_tokens,
        worst_token: worst_token.context("missing worst token")?,
    })
}

fn first_differing_hidden_lane(
    lhs: &[f32],
    rhs: &[f32],
    hidden_size: usize,
) -> Result<Option<FirstDifferingHiddenLaneSummary>> {
    if lhs.len() != rhs.len() {
        bail!(
            "hidden lane vector length mismatch: left {} vs right {}",
            lhs.len(),
            rhs.len()
        );
    }
    Ok(lhs
        .iter()
        .zip(rhs.iter())
        .enumerate()
        .find_map(|(flat_index, (lhs_value, rhs_value))| {
            if lhs_value == rhs_value {
                None
            } else {
                Some(FirstDifferingHiddenLaneSummary {
                    token_index: flat_index / hidden_size,
                    hidden_lane_index: flat_index % hidden_size,
                    flat_index,
                    runtime_value: *lhs_value,
                    official_value: *rhs_value,
                    abs_diff: (lhs_value - rhs_value).abs(),
                })
            }
        }))
}

fn worst_differing_hidden_lane(
    lhs: &[f32],
    rhs: &[f32],
    hidden_size: usize,
) -> Result<Option<FirstDifferingHiddenLaneSummary>> {
    if lhs.len() != rhs.len() {
        bail!(
            "hidden lane vector length mismatch: left {} vs right {}",
            lhs.len(),
            rhs.len()
        );
    }
    Ok(lhs
        .iter()
        .zip(rhs.iter())
        .enumerate()
        .map(|(flat_index, (lhs_value, rhs_value))| {
            let abs_diff = (lhs_value - rhs_value).abs();
            (flat_index, *lhs_value, *rhs_value, abs_diff)
        })
        .max_by(|(_, _, _, left), (_, _, _, right)| left.total_cmp(right))
        .and_then(|(flat_index, lhs_value, rhs_value, abs_diff)| {
            (abs_diff > 0.0).then_some(FirstDifferingHiddenLaneSummary {
                token_index: flat_index / hidden_size,
                hidden_lane_index: flat_index % hidden_size,
                flat_index,
                runtime_value: lhs_value,
                official_value: rhs_value,
                abs_diff,
            })
        }))
}

fn all_token_hidden_comparison_metrics(
    lhs: &[f32],
    rhs: &[f32],
    token_count: usize,
    hidden_size: usize,
) -> Result<AllTokenHiddenComparisonMetrics> {
    if lhs.len() != token_count * hidden_size || rhs.len() != token_count * hidden_size {
        bail!(
            "all-token hidden comparison length mismatch: left {} right {}, expected {}",
            lhs.len(),
            rhs.len(),
            token_count * hidden_size
        );
    }
    let base = compare_vectors(lhs, rhs)?;
    let mut differing_tokens = std::collections::BTreeSet::new();
    let mut differing_lanes = 0usize;
    for (flat_index, (lhs_value, rhs_value)) in lhs.iter().zip(rhs.iter()).enumerate() {
        if lhs_value != rhs_value {
            differing_lanes += 1;
            differing_tokens.insert(flat_index / hidden_size);
        }
    }
    Ok(AllTokenHiddenComparisonMetrics {
        max_abs_diff: base.max_abs_diff,
        mean_abs_diff: base.mean_abs_diff,
        matched: base.matched,
        differing_tokens: differing_tokens.len(),
        differing_lanes,
        first_differing_token_lane: first_differing_hidden_lane(lhs, rhs, hidden_size)?,
        worst_differing_token_lane: worst_differing_hidden_lane(lhs, rhs, hidden_size)?,
    })
}

fn token_diff_summaries(
    lhs: &[f32],
    rhs: &[f32],
    token_count: usize,
    hidden_size: usize,
) -> Result<Vec<TokenDiffSummary>> {
    if lhs.len() != token_count * hidden_size || rhs.len() != token_count * hidden_size {
        bail!("token diff summary input length mismatch");
    }
    let mut summaries = Vec::with_capacity(token_count);
    for token_index in 0..token_count {
        let start = token_index * hidden_size;
        let lhs_row = &lhs[start..start + hidden_size];
        let rhs_row = &rhs[start..start + hidden_size];
        let metrics = compare_vectors(lhs_row, rhs_row)?;
        let differing_lanes = lhs_row
            .iter()
            .zip(rhs_row.iter())
            .filter(|(lhs_value, rhs_value)| lhs_value != rhs_value)
            .count();
        summaries.push(TokenDiffSummary {
            token_index,
            max_abs_diff: metrics.max_abs_diff,
            mean_abs_diff: metrics.mean_abs_diff,
            differing_lanes,
            matched: metrics.matched,
        });
    }
    Ok(summaries)
}

fn rmsnorm_parameter_metadata(values: &[f32], dtype: &str) -> RmsNormParameterMetadata {
    let mut min_f32 = f32::INFINITY;
    let mut max_f32 = f32::NEG_INFINITY;
    let mut sum_f32 = 0.0f64;
    let mut sum_abs_f32 = 0.0f64;
    for value in values {
        min_f32 = min_f32.min(*value);
        max_f32 = max_f32.max(*value);
        sum_f32 += *value as f64;
        sum_abs_f32 += value.abs() as f64;
    }
    RmsNormParameterMetadata {
        shape: vec![values.len()],
        dtype: dtype.into(),
        first_values: values.iter().take(8).copied().collect(),
        last_values: values
            .iter()
            .rev()
            .take(8)
            .copied()
            .collect::<Vec<_>>()
            .into_iter()
            .rev()
            .collect(),
        sum_f32,
        sum_abs_f32,
        min_f32,
        max_f32,
    }
}

fn replay_rmsnorm_bf16_output(
    input: &[f32],
    weight: &[f32],
    token_count: usize,
    hidden_size: usize,
    epsilon: f32,
) -> Result<Vec<f32>> {
    if input.len() != token_count * hidden_size {
        bail!(
            "RMSNorm input length {} does not match [{}, {}]",
            input.len(),
            token_count,
            hidden_size
        );
    }
    if weight.len() != hidden_size {
        bail!(
            "RMSNorm weight length {} does not match hidden {}",
            weight.len(),
            hidden_size
        );
    }
    let mut output = Vec::with_capacity(input.len());
    for token_index in 0..token_count {
        let start = token_index * hidden_size;
        let row = &input[start..start + hidden_size];
        let sum_sq = row.iter().map(|value| value * value).sum::<f32>();
        let scale = (sum_sq / hidden_size as f32 + epsilon).sqrt().recip();
        for lane in 0..hidden_size {
            output.push(bf16::from_f32(row[lane] * weight[lane] * scale).to_f32());
        }
    }
    Ok(output)
}

fn replay_rmsnorm_bf16_policy_output(
    input: &[f32],
    weight: &[f32],
    token_count: usize,
    hidden_size: usize,
    epsilon: f32,
) -> Result<Vec<f32>> {
    if input.len() != token_count * hidden_size {
        bail!(
            "RMSNorm input length {} does not match [{}, {}]",
            input.len(),
            token_count,
            hidden_size
        );
    }
    if weight.len() != hidden_size {
        bail!(
            "RMSNorm weight length {} does not match hidden {}",
            weight.len(),
            hidden_size
        );
    }
    let mut output = Vec::with_capacity(input.len());
    for token_index in 0..token_count {
        let start = token_index * hidden_size;
        let row = &input[start..start + hidden_size];
        let mut sum_sq = 0.0f32;
        for value in row {
            let x = bf16::from_f32(*value).to_f32();
            sum_sq += x * x;
        }
        let scale = (sum_sq / hidden_size as f32 + epsilon).sqrt().recip();
        for lane in 0..hidden_size {
            let x = bf16::from_f32(row[lane]).to_f32();
            let w = bf16::from_f32(weight[lane]).to_f32();
            output.push(bf16::from_f32(x * w * scale).to_f32());
        }
    }
    Ok(output)
}

fn f32_pairwise_sum(values: &[f32]) -> f32 {
    if values.is_empty() {
        return 0.0;
    }
    let mut work = values.to_vec();
    while work.len() > 1 {
        let mut next = Vec::with_capacity(work.len().div_ceil(2));
        let mut chunks = work.chunks_exact(2);
        for pair in &mut chunks {
            next.push(pair[0] + pair[1]);
        }
        let remainder = chunks.remainder();
        if let Some(value) = remainder.first() {
            next.push(*value);
        }
        work = next;
    }
    work[0]
}

