fn run_layer0_attn_rmsnorm_scalar_runtime_fix_status(cli: &Cli) -> Result<()> {
    let source_scalar_capture_artifact_path =
        PathBuf::from(DEFAULT_LAYER0_ATTN_RMSNORM_CUDA_SINGLE_LANE_SCALAR_CAPTURE_STATUS_OUTPUT);
    let source_authoritative_replay_artifact_path = PathBuf::from(
        DEFAULT_LAYER0_ATTN_RMSNORM_RUST_BF16_REPLAY_MULTIPLY_ORDER_FIX_STATUS_OUTPUT,
    );
    let source_scalar_capture: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_scalar_capture_artifact_path).with_context(|| {
            format!(
                "failed to read scalar capture artifact {}",
                source_scalar_capture_artifact_path.display()
            )
        })?,
    )?;
    if source_scalar_capture
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || source_scalar_capture
            .get("classification")
            .and_then(serde_json::Value::as_str)
            != Some("live_cuda_rmsnorm_reduction_or_rsqrt_scalar_delta_captured")
    {
        bail!("source scalar-capture artifact is not the expected exact reduction-scalar state");
    }
    let source_authoritative_replay: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_authoritative_replay_artifact_path).with_context(
            || {
                format!(
                    "failed to read authoritative replay artifact {}",
                    source_authoritative_replay_artifact_path.display()
                )
            },
        )?,
    )?;
    if source_authoritative_replay
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || source_authoritative_replay
            .get("classification")
            .and_then(serde_json::Value::as_str)
            != Some("rust_bf16_replay_multiply_order_fix_proven")
    {
        bail!("source authoritative replay artifact is not the expected exact proven replay state");
    }

    let token_index = 18usize;
    let lane_index = 92usize;
    let (input_artifact, input_case) =
        load_single_case_artifact(&cli.local_residual_input_artifact)?;
    validate_exact_case_artifact(
        &input_artifact,
        &input_case,
        "layer0_residual_input",
        "developer-message-user-smoke",
        &input_case.input_token_ids,
    )?;
    let hidden_size = input_case
        .hidden_size
        .context("exact smoke case missing hidden_size")?;
    let model_root = Path::new(&input_artifact.provenance.model);
    let max_model_len = input_artifact.provenance.max_model_len.unwrap_or(128);
    let gpu_memory_utilization = input_artifact
        .provenance
        .gpu_memory_utilization
        .unwrap_or(0.75);

    let official_side_replay_path = cli
        .official_attn_rmsnorm_all_token_bf16_replay_artifact
        .clone();
    if let Some(parent) = official_side_replay_path.parent() {
        std::fs::create_dir_all(parent)?;
    }
    let official_side_status = Command::new(&cli.torch_python)
        .arg(&cli.official_attn_rmsnorm_all_token_bf16_replay_script)
        .arg("--model-root")
        .arg(model_root)
        .arg("--output")
        .arg(&official_side_replay_path)
        .arg("--device")
        .arg("cpu")
        .arg("--trace-token")
        .arg(token_index.to_string())
        .arg("--trace-lane")
        .arg(lane_index.to_string())
        .status()
        .with_context(|| {
            format!(
                "failed to run official-side RMSNorm replay script {} with {}",
                cli.official_attn_rmsnorm_all_token_bf16_replay_script
                    .display(),
                cli.torch_python.display()
            )
        })?;
    if !official_side_status.success() {
        bail!(
            "official-side RMSNorm replay script failed with status {:?}",
            official_side_status.code()
        );
    }
    let official_side: OfficialSideRmsNormReplayArtifact = serde_json::from_str(
        &std::fs::read_to_string(&official_side_replay_path).with_context(|| {
            format!(
                "failed to read official-side RMSNorm replay artifact {}",
                official_side_replay_path.display()
            )
        })?,
    )?;
    if official_side.case_id != "developer-message-user-smoke"
        || official_side.input_token_ids != input_case.input_token_ids
        || official_side.hidden_size != hidden_size
    {
        bail!("official-side RMSNorm replay artifact does not match exact smoke case");
    }
    let token_count = official_side.token_count;
    let expected_len = token_count * hidden_size;
    let epsilon = official_side.epsilon;
    let official_module_output = &official_side.official_module_output_f32;
    let authoritative_replay = replay_rmsnorm_bf16_policy_output_pairwise_reduction(
        &official_side.official_input_f32,
        &official_side.official_weight_f32,
        token_count,
        hidden_size,
        epsilon,
    )?;
    let authoritative_replay_vs_official = all_token_hidden_comparison_metrics(
        &authoritative_replay,
        official_module_output,
        token_count,
        hidden_size,
    )?;

    info!(
        model_root = %model_root.display(),
        max_model_len,
        gpu_memory_utilization,
        token_index,
        lane_index,
        "starting exact-case layer0 attention RMSNorm scalar runtime fix/proof status run"
    );
    let fixed_normal_trace = capture_layer0_qkv_trace_with_rmsnorm_scalar_debug(
        &input_artifact,
        &input_case,
        false,
        token_index,
        lane_index,
    )?;
    let fixed_debug_trace = capture_layer0_qkv_trace_with_rmsnorm_scalar_debug(
        &input_artifact,
        &input_case,
        true,
        token_index,
        lane_index,
    )?;
    if fixed_normal_trace.num_tokens != token_count
        || fixed_debug_trace.num_tokens != token_count
        || fixed_debug_trace.standalone_activation_full_bf16_bits.len() != expected_len
    {
        bail!("fixed live trace does not match exact all-token RMSNorm shape");
    }

    let fixed_live_output =
        bf16_bits_to_f32_slice(&fixed_debug_trace.standalone_activation_full_bf16_bits);
    let fixed_normal_output =
        bf16_bits_to_f32_slice(&fixed_normal_trace.standalone_activation_full_bf16_bits);
    let fixed_live_vs_authoritative = all_token_hidden_comparison_metrics(
        &fixed_live_output,
        &authoritative_replay,
        token_count,
        hidden_size,
    )?;
    let fixed_live_vs_official = all_token_hidden_comparison_metrics(
        &fixed_live_output,
        official_module_output,
        token_count,
        hidden_size,
    )?;
    let fixed_normal_vs_debug = all_token_hidden_comparison_metrics(
        &fixed_normal_output,
        &fixed_live_output,
        token_count,
        hidden_size,
    )?;
    let final_token_index = token_count.checked_sub(1).context("empty token sequence")?;
    let final_start = final_token_index * hidden_size;
    let fixed_live_final_token_vs_official = compare_vectors(
        &fixed_live_output[final_start..final_start + hidden_size],
        &official_module_output[final_start..final_start + hidden_size],
    )?;
    let token_lane_flat = token_index
        .checked_mul(hidden_size)
        .and_then(|start| start.checked_add(lane_index))
        .context("token/lane flat index overflow")?;
    let fixed_token_lane_value = fixed_live_output[token_lane_flat];
    let authoritative_token_lane_value = authoritative_replay[token_lane_flat];
    let official_token_lane_value = official_module_output[token_lane_flat];
    let fixed_token_lane_vs_authoritative =
        compare_vectors(&[fixed_token_lane_value], &[authoritative_token_lane_value])?;

    let debug_values = &fixed_debug_trace.rmsnorm_scalar_debug_f32;
    if debug_values.len() < 15 {
        bail!(
            "fixed debug trace missing RMSNorm scalar capture values: found {}",
            debug_values.len()
        );
    }
    let authoritative_trace = rmsnorm_single_lane_stage_trace(
        "authoritative_pairwise_tree_reduction_x_inverse_rms_then_weight",
        RmsNormReductionKind::PairwiseXScaleWeight,
        token_index,
        lane_index,
        &official_side.official_input_f32,
        &official_side.official_weight_f32,
        official_module_output,
        hidden_size,
        epsilon,
    )?;
    let legacy_trace = source_scalar_capture
        .get("captured_in_kernel_scalar_trace")
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    let token_lane_before_after_trace = serde_json::json!({
        "token_index": token_index,
        "lane_index": lane_index,
        "legacy_live_inverse_rms": legacy_trace.get("inverse_rms_scalar").cloned(),
        "fixed_live_inverse_rms": debug_values[4],
        "authoritative_replay_inverse_rms": authoritative_trace.get("inverse_rms_scalar").cloned(),
        "legacy_live_pre_cast_value": legacy_trace.get("final_weighted_f32_value_before_output_conversion").cloned(),
        "fixed_live_pre_cast_value": debug_values[11],
        "authoritative_replay_pre_cast_value": authoritative_trace.get("weighted_f32_value_before_output_bf16_cast").cloned(),
        "legacy_live_output": source_scalar_capture.get("normal_live_cuda_value").cloned(),
        "fixed_live_output": fixed_token_lane_value,
        "authoritative_replay_output": authoritative_token_lane_value,
        "official_output": official_token_lane_value,
        "fixed_debug_scalar_trace": {
            "thread0_square": debug_values[0],
            "final_reduced_sum_of_squares": debug_values[1],
            "mean_square": debug_values[2],
            "mean_square_plus_epsilon": debug_values[3],
            "inverse_rms_scalar": debug_values[4],
            "raw_input": debug_values[5],
            "input_bf16": debug_values[6],
            "raw_weight": debug_values[7],
            "weight_bf16": debug_values[8],
            "x_inverse_rms": debug_values[9],
            "x_weight": debug_values[10],
            "final_weighted_f32_before_output_cast": debug_values[11],
            "output_conversion_input": debug_values[12],
            "output_bf16_before_store": debug_values[13],
            "stored_output_decoded": debug_values[14],
        },
        "authoritative_replay_trace": authoritative_trace,
    });

    let activation_bf16 =
        bf16_bits_to_bf16_slice(&fixed_debug_trace.standalone_activation_full_bf16_bits);
    let k_weight_bf16 = bf16_bits_to_bf16_slice(&fixed_debug_trace.standalone_k_weight_bf16_bits);
    let cpu_k_helper_reference = cpu_bf16_row_major_gemm(
        &activation_bf16,
        &k_weight_bf16,
        token_count,
        fixed_debug_trace.kv_dim,
        hidden_size,
    )?;
    let cpu_k_helper_reference_f32 =
        bf16_bits_to_f32_slice(&bf16_slice_to_bits(&cpu_k_helper_reference));
    let live_k_helper_output =
        bf16_bits_to_f32_slice(&fixed_debug_trace.standalone_k_gemm_output_full_bf16_bits);
    let k_helper_guard_metric =
        compare_vectors(&live_k_helper_output, &cpu_k_helper_reference_f32)?;

    let official_bundle = validate_official_k_rope_bundle(
        cli,
        &input_case,
        fixed_debug_trace.num_tokens,
        fixed_debug_trace.kv_dim,
    )?;
    let grouped_pre_rope_k =
        bf16_bits_to_f32_slice(&fixed_debug_trace.standalone_k_post_bias_bf16_bits);
    let grouped_pre_rope_k_metric =
        compare_vectors(&grouped_pre_rope_k, &official_bundle.layer0_k_pre_rope_f32)?;
    let grouped_pre_rope_k_first_diff = first_differing_hidden_lane(
        &grouped_pre_rope_k,
        &official_bundle.layer0_k_pre_rope_f32,
        fixed_debug_trace.kv_dim,
    )?;
    let grouped_pre_rope_k_worst_diff = worst_differing_hidden_lane(
        &grouped_pre_rope_k,
        &official_bundle.layer0_k_pre_rope_f32,
        fixed_debug_trace.kv_dim,
    )?;

    let legacy_live_vs_authoritative = source_authoritative_replay
        .pointer("/live_cuda_captured_vs_fixed_replay_metric_informational_only")
        .cloned()
        .or_else(|| {
            source_scalar_capture
                .pointer(
                    "/required_comparisons/normal_uninstrumented_live_cuda_vs_authoritative_replay",
                )
                .cloned()
        });

    let classification = if fixed_live_vs_authoritative.matched && fixed_live_vs_official.matched {
        "layer0_attn_rmsnorm_scalar_runtime_fix_proven"
    } else if legacy_live_vs_authoritative
        .as_ref()
        .and_then(|value| serde_json::from_value::<CompareMetrics>(value.clone()).ok())
        .is_some_and(|legacy| {
            candidate_clearly_better(
                &CompareMetrics {
                    max_abs_diff: fixed_live_vs_authoritative.max_abs_diff,
                    mean_abs_diff: fixed_live_vs_authoritative.mean_abs_diff,
                    matched: fixed_live_vs_authoritative.matched,
                },
                &legacy,
            )
        })
    {
        "layer0_attn_rmsnorm_scalar_runtime_fix_partial"
    } else {
        "layer0_attn_rmsnorm_scalar_runtime_fix_not_sufficient"
    };
    let next_bounded_step = if fixed_live_vs_authoritative.matched
        && fixed_live_vs_official.matched
        && grouped_pre_rope_k_metric.matched
    {
        "rerun grouped post-RoPE K and first attention-score consumer seams"
    } else if fixed_live_vs_authoritative.matched && fixed_live_vs_official.matched {
        "re-enter grouped_pre_rope_k source breakdown with fixed RMSNorm provenance"
    } else {
        "keep scope on the layer0 attention RMSNorm scalar/reduction path"
    };

    let summary = serde_json::json!({
        "schema_version": "runtime_forward_layer0_attn_rmsnorm_scalar_runtime_fix_status/v1",
        "exact_case": KGainPreservationExactCase {
            case_id: input_case.id.clone(),
            input_token_ids: input_case.input_token_ids.clone(),
            hidden_size,
            num_tokens: token_count,
            q_dim: fixed_debug_trace.q_dim,
            kv_dim: fixed_debug_trace.kv_dim,
            qkv_dim: fixed_debug_trace.qkv_dim,
        },
        "mode": "layer0-attn-rmsnorm-scalar-runtime-fix-status",
        "source_scalar_capture_artifact_path": source_scalar_capture_artifact_path,
        "source_authoritative_replay_artifact_path": source_authoritative_replay_artifact_path,
        "files_changed": [
            "kernels/rms_norm_f16.cu",
            "crates/gpt-oss-model-runner/src/gpu_runner.rs",
            "crates/gpt-oss-bench/src/bin/runtime_forward_layer0_qkv_bf16_candidate_status.rs",
        ],
        "kernel_function_changed": "kernels/rms_norm_f16.cu::rms_norm_f16_bf16_policy_kernel",
        "old_scalar_reduction_behavior": {
            "reduction": "CUDA block-strided local sums followed by shared-memory halving reduction over thread partials",
            "multiply_order": "x * weight * inverse_rms",
            "shared_memory": "block_threads * sizeof(float)",
        },
        "fixed_scalar_reduction_behavior": {
            "reduction": "two-buffer shared-memory lane-order pairwise/tree f32 sum over BF16-expanded x*x, matching authoritative Rust/PyTorch replay",
            "inverse_rms": "1.0f / sqrtf(mean_square + epsilon)",
            "multiply_order": "x * inverse_rms, then multiply by BF16-expanded weight",
            "shared_memory": "2 * hidden_size * sizeof(float)",
            "output": "BF16 round-trip before existing __half store/capture path",
        },
        "scoped_only_to_layer0_attention_rmsnorm_bf16_policy": true,
        "authoritative_replay_vs_official_metrics": authoritative_replay_vs_official,
        "legacy_live_vs_authoritative_metrics_if_available": legacy_live_vs_authoritative,
        "fixed_live_vs_authoritative_metrics": fixed_live_vs_authoritative,
        "fixed_live_vs_official_metrics": fixed_live_vs_official,
        "fixed_normal_vs_debug_instrumented_metrics": fixed_normal_vs_debug,
        "token_18_lane_92_before_after_trace": token_lane_before_after_trace,
        "token_18_lane_92_fixed_live_vs_authoritative_metric": fixed_token_lane_vs_authoritative,
        "final_token_confirmation": {
            "final_token_index": final_token_index,
            "fixed_live_final_token_vs_official": fixed_live_final_token_vs_official,
        },
        "grouped_pre_rope_k_immediate_downstream_metric": grouped_pre_rope_k_metric,
        "grouped_pre_rope_k_first_differing_token_head_lane": grouped_pre_rope_k_first_diff,
        "grouped_pre_rope_k_worst_differing_token_head_lane": grouped_pre_rope_k_worst_diff,
        "k_helper_guard_metric": k_helper_guard_metric,
        "classification": classification,
        "runtime_forward_layer0_attn_rmsnorm_scalar_runtime_fix_status_now": format!(
            "runtime-forward layer0 attention RMSNorm scalar runtime fix status now: fixed_live_vs_authoritative max_abs={} mean_abs={} matched={}; fixed_live_vs_official max_abs={} mean_abs={} matched={}; token18_lane92 fixed={} authoritative={}; grouped_pre_rope_k max_abs={} mean_abs={} matched={}; k_helper_guard matched={}; classification={}; next bounded step: {}.",
            fixed_live_vs_authoritative.max_abs_diff,
            fixed_live_vs_authoritative.mean_abs_diff,
            fixed_live_vs_authoritative.matched,
            fixed_live_vs_official.max_abs_diff,
            fixed_live_vs_official.mean_abs_diff,
            fixed_live_vs_official.matched,
            fixed_token_lane_value,
            authoritative_token_lane_value,
            grouped_pre_rope_k_metric.max_abs_diff,
            grouped_pre_rope_k_metric.mean_abs_diff,
            grouped_pre_rope_k_metric.matched,
            k_helper_guard_metric.matched,
            classification,
            next_bounded_step
        ),
        "next_bounded_step": next_bounded_step,
    });

    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::Layer0AttnRmsnormScalarRuntimeFixStatus.default_output());
    write_pretty_json(&output, &summary)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn kv_lane_diff_summary(
    lhs: &[f32],
    rhs: &[f32],
    token_count: usize,
    kv_dim: usize,
    head_dim: usize,
) -> Result<(Option<serde_json::Value>, Option<serde_json::Value>)> {
    if lhs.len() != rhs.len() || lhs.len() != token_count * kv_dim {
        bail!("KV lane diff length mismatch");
    }
    let first =
        lhs.iter()
            .zip(rhs.iter())
            .enumerate()
            .find_map(|(flat_index, (lhs_value, rhs_value))| {
                if lhs_value == rhs_value {
                    None
                } else {
                    let lane = flat_index % kv_dim;
                    Some(serde_json::json!({
                        "token_index": flat_index / kv_dim,
                        "kv_head_index": lane / head_dim,
                        "head_dim_lane": lane % head_dim,
                        "flat_index": flat_index,
                        "runtime_value": lhs_value,
                        "official_value": rhs_value,
                        "abs_diff": (*lhs_value - *rhs_value).abs(),
                    }))
                }
            });
    let worst = lhs
        .iter()
        .zip(rhs.iter())
        .enumerate()
        .map(|(flat_index, (lhs_value, rhs_value))| {
            (
                flat_index,
                *lhs_value,
                *rhs_value,
                (*lhs_value - *rhs_value).abs(),
            )
        })
        .max_by(|(_, _, _, left), (_, _, _, right)| left.total_cmp(right))
        .and_then(|(flat_index, lhs_value, rhs_value, abs_diff)| {
            (abs_diff > 0.0).then(|| {
                let lane = flat_index % kv_dim;
                serde_json::json!({
                    "token_index": flat_index / kv_dim,
                    "kv_head_index": lane / head_dim,
                    "head_dim_lane": lane % head_dim,
                    "flat_index": flat_index,
                    "runtime_value": lhs_value,
                    "official_value": rhs_value,
                    "abs_diff": abs_diff,
                })
            })
        });
    Ok((first, worst))
}

fn k_causality_comparison_json(
    name: &str,
    lhs: &[f32],
    rhs: &[f32],
    token_count: usize,
    kv_dim: usize,
    head_dim: usize,
) -> Result<serde_json::Value> {
    let metrics = compare_vectors(lhs, rhs)?;
    let (first, worst) = kv_lane_diff_summary(lhs, rhs, token_count, kv_dim, head_dim)?;
    Ok(serde_json::json!({
        "comparison": name,
        "metrics": metrics,
        "first_differing_token_head_lane": first,
        "worst_differing_token_head_lane": worst,
    }))
}

fn mismatch_token_list(lhs: &[f32], rhs: &[f32], row_width: usize) -> Vec<usize> {
    let mut tokens = std::collections::BTreeSet::new();
    for (flat_index, (lhs_value, rhs_value)) in lhs.iter().zip(rhs.iter()).enumerate() {
        if lhs_value != rhs_value {
            tokens.insert(flat_index / row_width);
        }
    }
    tokens.into_iter().collect()
}

fn run_layer0_attn_rmsnorm_residual_lanes_k_causality_status(cli: &Cli) -> Result<()> {
    let source_scalar_fix_artifact_path =
        PathBuf::from(DEFAULT_LAYER0_ATTN_RMSNORM_SCALAR_RUNTIME_FIX_STATUS_OUTPUT);
    let source_authoritative_replay_artifact_path = PathBuf::from(
        DEFAULT_LAYER0_ATTN_RMSNORM_RUST_BF16_REPLAY_MULTIPLY_ORDER_FIX_STATUS_OUTPUT,
    );
    let source_k_pedantic_fix_artifact_path =
        PathBuf::from(DEFAULT_ALL_TOKEN_K_PEDANTIC_RUNTIME_FIX_STATUS_OUTPUT);
    let source_scalar_fix: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_scalar_fix_artifact_path).with_context(|| {
            format!(
                "failed to read scalar runtime fix artifact {}",
                source_scalar_fix_artifact_path.display()
            )
        })?,
    )?;
    if source_scalar_fix
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || source_scalar_fix
            .get("classification")
            .and_then(serde_json::Value::as_str)
            != Some("layer0_attn_rmsnorm_scalar_runtime_fix_partial")
    {
        bail!("source scalar runtime fix artifact is not the expected exact partial state");
    }
    let source_authoritative_replay: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_authoritative_replay_artifact_path).with_context(
            || {
                format!(
                    "failed to read authoritative replay artifact {}",
                    source_authoritative_replay_artifact_path.display()
                )
            },
        )?,
    )?;
    if source_authoritative_replay
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || source_authoritative_replay
            .get("classification")
            .and_then(serde_json::Value::as_str)
            != Some("rust_bf16_replay_multiply_order_fix_proven")
    {
        bail!("source authoritative replay artifact is not the expected exact proven replay state");
    }
    let source_k_pedantic_fix: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_k_pedantic_fix_artifact_path).with_context(|| {
            format!(
                "failed to read K pedantic fix artifact {}",
                source_k_pedantic_fix_artifact_path.display()
            )
        })?,
    )?;
    if source_k_pedantic_fix
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || source_k_pedantic_fix
            .get("classification")
            .and_then(serde_json::Value::as_str)
            != Some("all_token_k_pedantic_runtime_fix_proven")
    {
        bail!("source K pedantic helper fix artifact is not the expected exact proven state");
    }

    let (input_artifact, input_case) =
        load_single_case_artifact(&cli.local_residual_input_artifact)?;
    validate_exact_case_artifact(
        &input_artifact,
        &input_case,
        "layer0_residual_input",
        "developer-message-user-smoke",
        &input_case.input_token_ids,
    )?;
    let hidden_size = input_case
        .hidden_size
        .context("exact smoke case missing hidden_size")?;
    let model_root = Path::new(&input_artifact.provenance.model);
    let max_model_len = input_artifact.provenance.max_model_len.unwrap_or(128);
    let gpu_memory_utilization = input_artifact
        .provenance
        .gpu_memory_utilization
        .unwrap_or(0.75);

    let official_side_replay_path = cli
        .official_attn_rmsnorm_all_token_bf16_replay_artifact
        .clone();
    if let Some(parent) = official_side_replay_path.parent() {
        std::fs::create_dir_all(parent)?;
    }
    let official_side_status = Command::new(&cli.torch_python)
        .arg(&cli.official_attn_rmsnorm_all_token_bf16_replay_script)
        .arg("--model-root")
        .arg(model_root)
        .arg("--output")
        .arg(&official_side_replay_path)
        .arg("--device")
        .arg("cpu")
        .status()
        .with_context(|| {
            format!(
                "failed to run official-side RMSNorm replay script {} with {}",
                cli.official_attn_rmsnorm_all_token_bf16_replay_script
                    .display(),
                cli.torch_python.display()
            )
        })?;
    if !official_side_status.success() {
        bail!(
            "official-side RMSNorm replay script failed with status {:?}",
            official_side_status.code()
        );
    }
    let official_side: OfficialSideRmsNormReplayArtifact = serde_json::from_str(
        &std::fs::read_to_string(&official_side_replay_path).with_context(|| {
            format!(
                "failed to read official-side RMSNorm replay artifact {}",
                official_side_replay_path.display()
            )
        })?,
    )?;
    if official_side.case_id != "developer-message-user-smoke"
        || official_side.input_token_ids != input_case.input_token_ids
        || official_side.hidden_size != hidden_size
    {
        bail!("official-side RMSNorm replay artifact does not match exact smoke case");
    }
    let token_count = official_side.token_count;
    let expected_hidden_len = token_count * hidden_size;
    let epsilon = official_side.epsilon;
    let official_output = &official_side.official_module_output_f32;
    let authoritative_replay = replay_rmsnorm_bf16_policy_output_pairwise_reduction(
        &official_side.official_input_f32,
        &official_side.official_weight_f32,
        token_count,
        hidden_size,
        epsilon,
    )?;
    let authoritative_replay_vs_official = all_token_hidden_comparison_metrics(
        &authoritative_replay,
        official_output,
        token_count,
        hidden_size,
    )?;

    let fixed_trace = capture_layer0_qkv_trace_with_rmsnorm_scalar_debug(
        &input_artifact,
        &input_case,
        false,
        18,
        92,
    )?;
    if fixed_trace.num_tokens != token_count
        || fixed_trace.standalone_activation_full_bf16_bits.len() != expected_hidden_len
    {
        bail!("fixed live trace does not match exact RMSNorm output shape");
    }
    let fixed_live_output =
        bf16_bits_to_f32_slice(&fixed_trace.standalone_activation_full_bf16_bits);
    let fixed_live_vs_authoritative = all_token_hidden_comparison_metrics(
        &fixed_live_output,
        &authoritative_replay,
        token_count,
        hidden_size,
    )?;
    let final_token_index = token_count.checked_sub(1).context("empty token sequence")?;
    let final_start = final_token_index * hidden_size;
    let final_token_confirmation = compare_vectors(
        &fixed_live_output[final_start..final_start + hidden_size],
        &authoritative_replay[final_start..final_start + hidden_size],
    )?;

    let mut residual_lane_table = Vec::new();
    let mut bf16_bit_different_count = 0usize;
    let mut f32_only_drift_count = 0usize;
    let mut all_below_one_bf16_ulp = true;
    for flat_index in 0..expected_hidden_len {
        let live_value = fixed_live_output[flat_index];
        let auth_value = authoritative_replay[flat_index];
        if live_value == auth_value {
            continue;
        }
        let official_value = official_output[flat_index];
        let live_bits = fixed_trace.standalone_activation_full_bf16_bits[flat_index];
        let auth_bits = bf16::from_f32(auth_value).to_bits();
        let official_bits = bf16::from_f32(official_value).to_bits();
        let token_index = flat_index / hidden_size;
        let lane_index = flat_index % hidden_size;
        let bit_equivalence = if live_bits == auth_bits {
            f32_only_drift_count += 1;
            "f32_only_comparison_drift_after_same_bf16_bits"
        } else {
            bf16_bit_different_count += 1;
            "bf16_bit_different"
        };
        let live_bf16 = bf16::from_bits(live_bits);
        let next_bits = if live_bits & 0x8000 == 0 {
            live_bits.saturating_add(1)
        } else {
            live_bits.saturating_sub(1)
        };
        let one_ulp = (bf16::from_bits(next_bits).to_f32() - live_bf16.to_f32()).abs();
        let abs_diff = (live_value - auth_value).abs();
        if abs_diff > one_ulp {
            all_below_one_bf16_ulp = false;
        }
        residual_lane_table.push(serde_json::json!({
            "token_index": token_index,
            "hidden_lane": lane_index,
            "flat_index": flat_index,
            "fixed_live_value": live_value,
            "authoritative_replay_value": auth_value,
            "official_value": official_value,
            "abs_diff": abs_diff,
            "live_raw_stored_bits": format!("0x{live_bits:04x}"),
            "live_raw_stored_value": bf16::from_bits(live_bits).to_f32(),
            "captured_comparison_value": live_value,
            "authoritative_bf16_bits": format!("0x{auth_bits:04x}"),
            "authoritative_bf16_value": bf16::from_bits(auth_bits).to_f32(),
            "official_bf16_bits": format!("0x{official_bits:04x}"),
            "official_bf16_value": bf16::from_bits(official_bits).to_f32(),
            "bit_equivalence": bit_equivalence,
            "one_bf16_ulp_at_live_magnitude": one_ulp,
            "below_or_equal_one_bf16_ulp": abs_diff <= one_ulp,
        }));
    }
    let rmsnorm_residual_tokens: Vec<usize> = residual_lane_table
        .iter()
        .filter_map(|entry| entry.get("token_index").and_then(serde_json::Value::as_u64))
        .map(|value| value as usize)
        .collect::<std::collections::BTreeSet<_>>()
        .into_iter()
        .collect();
    let bf16_bit_equivalence_findings = if residual_lane_table.is_empty() {
        "no_remaining_residual_lanes"
    } else if bf16_bit_different_count == 0 {
        "all_residual_lanes_have_identical_bf16_bits"
    } else if f32_only_drift_count == 0 {
        "all_residual_lanes_are_bf16_bit_different"
    } else {
        "mixed_bf16_bit_difference_and_f32_only_drift"
    };

    let official_bundle = validate_official_k_rope_bundle(
        cli,
        &input_case,
        fixed_trace.num_tokens,
        fixed_trace.kv_dim,
    )?;
    let k_weight_bf16 = bf16_bits_to_bf16_slice(&fixed_trace.standalone_k_weight_bf16_bits);
    let fixed_live_norm_bf16 =
        bf16_bits_to_bf16_slice(&fixed_trace.standalone_activation_full_bf16_bits);
    let authoritative_norm_bf16: Vec<bf16> = authoritative_replay
        .iter()
        .map(|value| bf16::from_f32(*value))
        .collect();
    let official_norm_bf16: Vec<bf16> = official_output
        .iter()
        .map(|value| bf16::from_f32(*value))
        .collect();
    let fixed_live_k_bf16 = cpu_bf16_row_major_gemm(
        &fixed_live_norm_bf16,
        &k_weight_bf16,
        token_count,
        fixed_trace.kv_dim,
        hidden_size,
    )?;
    let authoritative_k_bf16 = cpu_bf16_row_major_gemm(
        &authoritative_norm_bf16,
        &k_weight_bf16,
        token_count,
        fixed_trace.kv_dim,
        hidden_size,
    )?;
    let official_norm_k_bf16 = cpu_bf16_row_major_gemm(
        &official_norm_bf16,
        &k_weight_bf16,
        token_count,
        fixed_trace.kv_dim,
        hidden_size,
    )?;
    let fixed_live_k = bf16_bits_to_f32_slice(&bf16_slice_to_bits(&fixed_live_k_bf16));
    let authoritative_k = bf16_bits_to_f32_slice(&bf16_slice_to_bits(&authoritative_k_bf16));
    let official_norm_k = bf16_bits_to_f32_slice(&bf16_slice_to_bits(&official_norm_k_bf16));
    let official_k = &official_bundle.layer0_k_pre_rope_f32;
    let head_dim = 64usize;
    let fixed_live_k_vs_official = k_causality_comparison_json(
        "fixed_live_norm_input_to_grouped_pre_rope_k_vs_official",
        &fixed_live_k,
        official_k,
        token_count,
        fixed_trace.kv_dim,
        head_dim,
    )?;
    let authoritative_k_vs_official = k_causality_comparison_json(
        "authoritative_replay_norm_input_to_grouped_pre_rope_k_vs_official",
        &authoritative_k,
        official_k,
        token_count,
        fixed_trace.kv_dim,
        head_dim,
    )?;
    let official_norm_k_vs_official = k_causality_comparison_json(
        "official_norm_input_to_grouped_pre_rope_k_vs_official",
        &official_norm_k,
        official_k,
        token_count,
        fixed_trace.kv_dim,
        head_dim,
    )?;
    let fixed_live_k_vs_authoritative_k = k_causality_comparison_json(
        "fixed_live_norm_k_result_vs_authoritative_replay_norm_k_result",
        &fixed_live_k,
        &authoritative_k,
        token_count,
        fixed_trace.kv_dim,
        head_dim,
    )?;
    let authoritative_k_vs_official_norm_k = k_causality_comparison_json(
        "authoritative_replay_norm_k_result_vs_official_norm_k_result",
        &authoritative_k,
        &official_norm_k,
        token_count,
        fixed_trace.kv_dim,
        head_dim,
    )?;

    let grouped_k_mismatch_tokens =
        mismatch_token_list(&fixed_live_k, official_k, fixed_trace.kv_dim);
    let grouped_first_token = fixed_live_k_vs_official
        .pointer("/first_differing_token_head_lane/token_index")
        .and_then(serde_json::Value::as_u64)
        .map(|value| value as usize);
    let grouped_worst_token = fixed_live_k_vs_official
        .pointer("/worst_differing_token_head_lane/token_index")
        .and_then(serde_json::Value::as_u64)
        .map(|value| value as usize);
    let residual_token_set: std::collections::BTreeSet<usize> =
        rmsnorm_residual_tokens.iter().copied().collect();
    let grouped_token_set: std::collections::BTreeSet<usize> =
        grouped_k_mismatch_tokens.iter().copied().collect();
    let overlap_tokens: Vec<usize> = residual_token_set
        .intersection(&grouped_token_set)
        .copied()
        .collect();
    let authoritative_k_metrics: CompareMetrics = serde_json::from_value(
        authoritative_k_vs_official
            .get("metrics")
            .cloned()
            .context("authoritative K comparison missing metrics")?,
    )?;
    let fixed_live_k_metrics: CompareMetrics = serde_json::from_value(
        fixed_live_k_vs_official
            .get("metrics")
            .cloned()
            .context("fixed live K comparison missing metrics")?,
    )?;
    let replacing_fixed_with_authoritative_collapses_k_mismatch = authoritative_k_metrics.matched;
    let replacing_fixed_with_authoritative_improves_k =
        candidate_clearly_better(&authoritative_k_metrics, &fixed_live_k_metrics);

    let classification = if fixed_live_vs_authoritative.matched && fixed_live_k_metrics.matched {
        "rmsnorm_and_grouped_pre_rope_k_cleared_or_prior_measurement_bug"
    } else if !residual_lane_table.is_empty() && bf16_bit_different_count == 0 {
        "rmsnorm_residual_is_capture_or_f32_comparison_artifact"
    } else if bf16_bit_different_count > 0
        && replacing_fixed_with_authoritative_collapses_k_mismatch
    {
        "rmsnorm_residual_causally_explains_grouped_k_mismatch"
    } else if bf16_bit_different_count > 0 {
        "grouped_k_mismatch_not_explained_by_remaining_rmsnorm_residual"
    } else {
        "rmsnorm_to_k_causality_test_blocked"
    };
    let next_bounded_step = match classification {
        "rmsnorm_residual_causally_explains_grouped_k_mismatch" => {
            "fix/prove the remaining RMSNorm BF16 residual lanes before returning to grouped_pre_rope_k"
        }
        "grouped_k_mismatch_not_explained_by_remaining_rmsnorm_residual" => {
            "return to grouped_pre_rope_k source breakdown using authoritative RMSNorm provenance"
        }
        "rmsnorm_residual_is_capture_or_f32_comparison_artifact" => {
            "treat RMSNorm as BF16-cleared and rerun grouped_pre_rope_k current path status"
        }
        "rmsnorm_and_grouped_pre_rope_k_cleared_or_prior_measurement_bug" => {
            "rerun grouped post-RoPE K and first attention-score consumer seams"
        }
        _ => "add a narrower feed-through hook for authoritative RMSNorm into the K helper path",
    };

    let summary = serde_json::json!({
        "schema_version": "runtime_forward_layer0_attn_rmsnorm_residual_lanes_k_causality_status/v1",
        "exact_case": KGainPreservationExactCase {
            case_id: input_case.id.clone(),
            input_token_ids: input_case.input_token_ids.clone(),
            hidden_size,
            num_tokens: token_count,
            q_dim: fixed_trace.q_dim,
            kv_dim: fixed_trace.kv_dim,
            qkv_dim: fixed_trace.qkv_dim,
        },
        "mode": "layer0-attn-rmsnorm-residual-lanes-k-causality-status",
        "source_artifact_paths": {
            "scalar_runtime_fix": source_scalar_fix_artifact_path,
            "authoritative_replay_proof": source_authoritative_replay_artifact_path,
            "k_pedantic_helper_fix": source_k_pedantic_fix_artifact_path,
            "official_side_replay": official_side_replay_path,
        },
        "active_rmsnorm_scalar_reduction_behavior": source_scalar_fix.get("fixed_scalar_reduction_behavior").cloned(),
        "active_k_helper_gemm_policy": {
            "policy": "pedantic all-token K helper semantics replayed by cpu_bf16_row_major_gemm for injected RMSNorm inputs",
            "source_fix_classification": source_k_pedantic_fix.get("classification").cloned(),
        },
        "rmsnorm_residual_metrics": fixed_live_vs_authoritative,
        "rmsnorm_residual_lane_table": residual_lane_table,
        "bf16_bit_equivalence_findings": {
            "summary": bf16_bit_equivalence_findings,
            "bf16_bit_different_count": bf16_bit_different_count,
            "f32_only_drift_count": f32_only_drift_count,
            "all_below_or_equal_one_bf16_ulp_for_magnitude": all_below_one_bf16_ulp,
        },
        "total_mismatching_token_count": rmsnorm_residual_tokens.len(),
        "total_mismatching_lane_count": bf16_bit_different_count + f32_only_drift_count,
        "authoritative_replay_vs_official_metrics": authoritative_replay_vs_official,
        "final_token_confirmation": {
            "final_token_index": final_token_index,
            "fixed_live_vs_authoritative": final_token_confirmation,
        },
        "k_causality_comparison_metrics": {
            "fixed_live_norm_input_to_grouped_pre_rope_k_vs_official": fixed_live_k_vs_official,
            "authoritative_replay_norm_input_to_grouped_pre_rope_k_vs_official": authoritative_k_vs_official,
            "official_norm_input_to_grouped_pre_rope_k_vs_official": official_norm_k_vs_official,
            "fixed_live_norm_k_result_vs_authoritative_replay_norm_k_result": fixed_live_k_vs_authoritative_k,
            "authoritative_replay_norm_k_result_vs_official_norm_k_result": authoritative_k_vs_official_norm_k,
        },
        "overlap_analysis": {
            "rmsnorm_residual_tokens": rmsnorm_residual_tokens,
            "grouped_pre_rope_k_mismatch_tokens": grouped_k_mismatch_tokens,
            "overlap_tokens": overlap_tokens,
            "grouped_pre_rope_k_first_mismatch_token": grouped_first_token,
            "grouped_pre_rope_k_worst_mismatch_token": grouped_worst_token,
            "first_mismatch_overlaps_rmsnorm_residual_tokens": grouped_first_token.is_some_and(|token| residual_token_set.contains(&token)),
            "worst_mismatch_overlaps_rmsnorm_residual_tokens": grouped_worst_token.is_some_and(|token| residual_token_set.contains(&token)),
            "replacing_fixed_live_norm_with_authoritative_replay_norm_collapses_k_mismatch": replacing_fixed_with_authoritative_collapses_k_mismatch,
            "replacing_fixed_live_norm_with_authoritative_replay_norm_materially_improves_k_mismatch": replacing_fixed_with_authoritative_improves_k,
        },
        "classification": classification,
        "runtime_forward_layer0_attn_rmsnorm_residual_lanes_k_causality_status_now": format!(
            "runtime-forward RMSNorm residual lanes -> K causality status now: rmsnorm residual lanes={} bf16_bit_different={} max_abs={} mean_abs={}; fixed-live K max_abs={} mean_abs={} matched={}; authoritative-norm K max_abs={} mean_abs={} matched={}; classification={}; next bounded step: {}.",
            bf16_bit_different_count + f32_only_drift_count,
            bf16_bit_different_count,
            fixed_live_vs_authoritative.max_abs_diff,
            fixed_live_vs_authoritative.mean_abs_diff,
            fixed_live_k_metrics.max_abs_diff,
            fixed_live_k_metrics.mean_abs_diff,
            fixed_live_k_metrics.matched,
            authoritative_k_metrics.max_abs_diff,
            authoritative_k_metrics.mean_abs_diff,
            authoritative_k_metrics.matched,
            classification,
            next_bounded_step
        ),
        "next_bounded_step": next_bounded_step,
    });

    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::Layer0AttnRmsnormResidualLanesKCausalityStatus.default_output());
    write_pretty_json(&output, &summary)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn run_grouped_pre_rope_k_authoritative_norm_source_breakdown_status(cli: &Cli) -> Result<()> {
    let source_causality_artifact_path =
        PathBuf::from(DEFAULT_LAYER0_ATTN_RMSNORM_RESIDUAL_LANES_K_CAUSALITY_STATUS_OUTPUT);
    let source_authoritative_replay_artifact_path = PathBuf::from(
        DEFAULT_LAYER0_ATTN_RMSNORM_RUST_BF16_REPLAY_MULTIPLY_ORDER_FIX_STATUS_OUTPUT,
    );
    let source_k_pedantic_fix_artifact_path =
        PathBuf::from(DEFAULT_ALL_TOKEN_K_PEDANTIC_RUNTIME_FIX_STATUS_OUTPUT);
    let source_ppp_semantics_artifact_path = cli
        .ppp_grouped_pre_rope_k_reference_semantics_status_artifact
        .clone();

    let source_causality: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_causality_artifact_path).with_context(|| {
            format!(
                "failed to read RMSNorm residual causality artifact {}",
                source_causality_artifact_path.display()
            )
        })?,
    )?;
    if source_causality
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || source_causality
            .get("classification")
            .and_then(serde_json::Value::as_str)
            != Some("grouped_k_mismatch_not_explained_by_remaining_rmsnorm_residual")
    {
        bail!("source RMSNorm residual causality artifact is not the expected exact state");
    }
    let source_authoritative_replay: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_authoritative_replay_artifact_path).with_context(
            || {
                format!(
                    "failed to read authoritative replay proof artifact {}",
                    source_authoritative_replay_artifact_path.display()
                )
            },
        )?,
    )?;
    if source_authoritative_replay
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || source_authoritative_replay
            .get("classification")
            .and_then(serde_json::Value::as_str)
            != Some("rust_bf16_replay_multiply_order_fix_proven")
    {
        bail!("source authoritative replay proof artifact is not the expected exact proven state");
    }
    let source_k_pedantic_fix: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_k_pedantic_fix_artifact_path).with_context(|| {
            format!(
                "failed to read K pedantic helper fix artifact {}",
                source_k_pedantic_fix_artifact_path.display()
            )
        })?,
    )?;
    if source_k_pedantic_fix
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || source_k_pedantic_fix
            .get("classification")
            .and_then(serde_json::Value::as_str)
            != Some("all_token_k_pedantic_runtime_fix_proven")
    {
        bail!("source K pedantic helper fix artifact is not the expected exact proven state");
    }
    let source_ppp_semantics: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_ppp_semantics_artifact_path).with_context(|| {
            format!(
                "failed to read PPP grouped pre-RoPE semantics artifact {}",
                source_ppp_semantics_artifact_path.display()
            )
        })?,
    )?;
    if source_ppp_semantics
        .get("classification")
        .and_then(serde_json::Value::as_str)
        != Some("runtime_k_reference_path_not_authoritative_enough")
    {
        bail!("PPP grouped pre-RoPE semantics artifact is not the expected exact clarification");
    }

    let (input_artifact, input_case) =
        load_single_case_artifact(&cli.local_residual_input_artifact)?;
    validate_exact_case_artifact(
        &input_artifact,
        &input_case,
        "layer0_residual_input",
        "developer-message-user-smoke",
        &input_case.input_token_ids,
    )?;
    let hidden_size = input_case
        .hidden_size
        .context("exact smoke case missing hidden_size")?;
    let model_root = Path::new(&input_artifact.provenance.model);
    let max_model_len = input_artifact.provenance.max_model_len.unwrap_or(128);
    let gpu_memory_utilization = input_artifact
        .provenance
        .gpu_memory_utilization
        .unwrap_or(0.75);

    let official_side_replay_path = cli
        .official_attn_rmsnorm_all_token_bf16_replay_artifact
        .clone();
    if let Some(parent) = official_side_replay_path.parent() {
        std::fs::create_dir_all(parent)?;
    }
    let official_side_status = Command::new(&cli.torch_python)
        .arg(&cli.official_attn_rmsnorm_all_token_bf16_replay_script)
        .arg("--model-root")
        .arg(model_root)
        .arg("--output")
        .arg(&official_side_replay_path)
        .arg("--device")
        .arg("cpu")
        .status()
        .with_context(|| {
            format!(
                "failed to run official-side RMSNorm replay script {} with {}",
                cli.official_attn_rmsnorm_all_token_bf16_replay_script
                    .display(),
                cli.torch_python.display()
            )
        })?;
    if !official_side_status.success() {
        bail!(
            "official-side RMSNorm replay script failed with status {:?}",
            official_side_status.code()
        );
    }
    let official_side: OfficialSideRmsNormReplayArtifact = serde_json::from_str(
        &std::fs::read_to_string(&official_side_replay_path).with_context(|| {
            format!(
                "failed to read official-side RMSNorm replay artifact {}",
                official_side_replay_path.display()
            )
        })?,
    )?;
    if official_side.case_id != "developer-message-user-smoke"
        || official_side.input_token_ids != input_case.input_token_ids
        || official_side.hidden_size != hidden_size
    {
        bail!("official-side RMSNorm replay artifact does not match exact smoke case");
    }
    let token_count = official_side.token_count;
    let expected_hidden_len = token_count * hidden_size;
    let authoritative_norm = replay_rmsnorm_bf16_policy_output_pairwise_reduction(
        &official_side.official_input_f32,
        &official_side.official_weight_f32,
        token_count,
        hidden_size,
        official_side.epsilon,
    )?;
    let authoritative_rmsnorm_replay_vs_official = all_token_hidden_comparison_metrics(
        &authoritative_norm,
        &official_side.official_module_output_f32,
        token_count,
        hidden_size,
    )?;

    let official_bundle =
        load_official_k_rope_bundle_artifact(&cli.official_k_rope_bundle_artifact)?;
    if official_bundle.case_id != "developer-message-user-smoke"
        || official_bundle.input_token_ids != input_case.input_token_ids
        || official_bundle.token_count != token_count
    {
        bail!("official K RoPE bundle does not match exact authoritative RMSNorm case");
    }

    info!(
        model_root = %model_root.display(),
        max_model_len,
        gpu_memory_utilization,
        "starting exact-case grouped pre-RoPE K authoritative-norm source breakdown status run"
    );
    let _bf16_guard = EnvFlagGuard::set(BF16_DENSE_QKV_ENV, true);
    let worker = build_worker(model_root, max_model_len, gpu_memory_utilization)?;
    let live_trace = capture_layer0_qkv_trace(&worker, &input_case.input_token_ids)?;
    if !live_trace.branch_taken {
        bail!("authoritative-norm grouped pre-RoPE K trace did not take bf16 fused-qkv branch");
    }
    let kv_dim = live_trace.kv_dim;
    let q_dim = live_trace.q_dim;
    let qkv_dim = live_trace.qkv_dim;
    let head_dim = official_bundle.layer0_k_rope_state.head_dim;
    if live_trace.num_tokens != token_count
        || kv_dim != official_bundle.kv_dim
        || official_bundle.layer0_k_pre_rope_f32.len() != token_count * kv_dim
        || live_trace.standalone_activation_full_bf16_bits.len() != expected_hidden_len
    {
        bail!("live trace and official grouped pre-RoPE K shapes do not agree");
    }

    let fixed_live_norm = bf16_bits_to_f32_slice(&live_trace.standalone_activation_full_bf16_bits);
    let fixed_live_rmsnorm_vs_authoritative = all_token_hidden_comparison_metrics(
        &fixed_live_norm,
        &authoritative_norm,
        token_count,
        hidden_size,
    )?;

    let authoritative_norm_bf16: Vec<bf16> = authoritative_norm
        .iter()
        .map(|value| bf16::from_f32(*value))
        .collect();
    let k_weight_bf16 = bf16_bits_to_bf16_slice(&live_trace.standalone_k_weight_bf16_bits);
    if k_weight_bf16.len() != kv_dim * hidden_size {
        bail!(
            "runtime K weight slice length {} does not match expected {}",
            k_weight_bf16.len(),
            kv_dim * hidden_size
        );
    }
    let explicit_cpu_replay_bf16 = cpu_bf16_row_major_gemm(
        &authoritative_norm_bf16,
        &k_weight_bf16,
        token_count,
        kv_dim,
        hidden_size,
    )?;
    let explicit_cpu_replay = bf16_slice_to_f32(&explicit_cpu_replay_bf16);

    let stream = worker.gpu_stream().clone();
    let authoritative_norm_gpu = stream
        .clone_htod(&authoritative_norm_bf16)
        .map_err(|e| anyhow::anyhow!("authoritative norm htod failed: {e}"))?;
    let k_weight_gpu = stream
        .clone_htod(&k_weight_bf16)
        .map_err(|e| anyhow::anyhow!("K weight htod failed: {e}"))?;
    let mut helper_output_gpu = stream
        .alloc_zeros::<bf16>(token_count * kv_dim)
        .map_err(|e| anyhow::anyhow!("authoritative-norm K helper output alloc failed: {e}"))?;
    worker.blas().hgemm_bf16_pedantic_no_tensor_op(
        token_count,
        kv_dim,
        hidden_size,
        bf16::ONE,
        &authoritative_norm_gpu,
        &k_weight_gpu,
        bf16::ZERO,
        &mut helper_output_gpu,
    )?;
    let helper_output_bf16: Vec<bf16> = stream
        .clone_dtoh(&helper_output_gpu)
        .map_err(|e| anyhow::anyhow!("authoritative-norm K helper output dtoh failed: {e}"))?;
    let helper_output = bf16_slice_to_f32(&helper_output_bf16);
    let official_k = &official_bundle.layer0_k_pre_rope_f32;

    let stage_summary = |stage_name: &str,
                         operation: &str,
                         local_name: &str,
                         reference_name: &str,
                         local: &[f32],
                         reference: &[f32]|
     -> Result<serde_json::Value> {
        let metrics = compare_vectors(local, reference)?;
        let (first, worst) = kv_lane_diff_summary(local, reference, token_count, kv_dim, head_dim)?;
        Ok(serde_json::json!({
            "stage_name": stage_name,
            "operation": operation,
            "local_tensor_name": local_name,
            "reference_tensor_name": reference_name,
            "local_shape": [token_count, kv_dim / head_dim, head_dim],
            "reference_shape": [token_count, kv_dim / head_dim, head_dim],
            "dtype": "f32-expanded BF16 values",
            "serialization_dtype": "bf16",
            "layout_interpretation": "[token, kv_head, lane] contiguous; flat [token, kv_dim]",
            "physical_stride": [kv_dim, head_dim, 1],
            "metrics": metrics,
            "first_differing_token_head_lane": first,
            "worst_differing_token_head_lane": worst,
        }))
    };

    let helper_vs_cpu = stage_summary(
        "authoritative_norm_current_pedantic_helper_vs_explicit_cpu_replay",
        "isolated pedantic all-token K helper using authoritative RMSNorm input compared to explicit Rust CPU replay",
        "isolated hgemm_bf16(authoritative_norm, runtime_k_weight)",
        "cpu_bf16_row_major_gemm(authoritative_norm, runtime_k_weight)",
        &helper_output,
        &explicit_cpu_replay,
    )?;
    let projection_before_grouped_vs_official = stage_summary(
        "k_projection_output_before_grouped_view",
        "authoritative RMSNorm input x runtime K weight before any grouped view",
        "isolated hgemm_bf16(authoritative_norm, runtime_k_weight)",
        "official_k_rope_bundle.layer0_k_pre_rope_f32",
        &helper_output,
        official_k,
    )?;
    let explicit_replay_vs_official = stage_summary(
        "explicit_cpu_rust_replay_before_grouped_view",
        "explicit Rust CPU BF16 replay using authoritative RMSNorm input and runtime K weight",
        "cpu_bf16_row_major_gemm(authoritative_norm, runtime_k_weight)",
        "official_k_rope_bundle.layer0_k_pre_rope_f32",
        &explicit_cpu_replay,
        official_k,
    )?;
    let k_slice_extraction = stage_summary(
        "k_slice_extraction",
        "direct K-only helper output compared to the extracted K slice readout for the same authoritative input path",
        "isolated hgemm_bf16(authoritative_norm, runtime_k_weight)",
        "explicit Rust CPU K-only replay",
        &helper_output,
        &explicit_cpu_replay,
    )?;
    let grouped_view_vs_official = stage_summary(
        "grouped_pre_rope_k_layout_view",
        "flat K projection interpreted as grouped [token, kv_head, lane]",
        "isolated helper output as grouped [token, kv_head, lane]",
        "official grouped/pre-RoPE [token, kv_head, lane]",
        &helper_output,
        official_k,
    )?;

    let projection_metrics: CompareMetrics = serde_json::from_value(
        projection_before_grouped_vs_official
            .get("metrics")
            .cloned()
            .context("projection stage missing metrics")?,
    )?;
    let grouped_metrics: CompareMetrics = serde_json::from_value(
        grouped_view_vs_official
            .get("metrics")
            .cloned()
            .context("grouped stage missing metrics")?,
    )?;
    let helper_vs_cpu_metrics: CompareMetrics = serde_json::from_value(
        helper_vs_cpu
            .get("metrics")
            .cloned()
            .context("helper-vs-cpu stage missing metrics")?,
    )?;

    let k_weight_f32 = bf16_slice_to_f32(&k_weight_bf16);
    let k_weight_metadata_inconsistent =
        q_dim + kv_dim > qkv_dim || k_weight_bf16.len() != kv_dim * hidden_size;
    let k_weight_slice_metadata = serde_json::json!({
        "runtime": {
            "source_tensor_name": "layer0 fused attn.qkv weight cast to BF16; extracted K slice",
            "fused_attn_qkv_weight_logical_shape": [qkv_dim, hidden_size],
            "k_slice_shape": [kv_dim, hidden_size],
            "dtype": "bf16",
            "row_column_orientation": "row-major [k_output_feature, hidden]; helper computes activation[token, hidden] x K_weight^T",
            "k_slice_offsets_elements": [q_dim * hidden_size, (q_dim + kv_dim) * hidden_size],
            "logical_layout": "[kv_dim, hidden_size]",
            "physical_stride": [hidden_size, 1],
            "stable_digest": stable_digest_f32(&k_weight_f32),
            "metadata_consistent_with_runtime_shapes": !k_weight_metadata_inconsistent,
        },
        "official": {
            "available": false,
            "reason": "no separate official K weight-slice metadata artifact is available in this bounded mode; official PyTorch K arithmetic is represented by official layer0_k_pre_rope_f32",
        }
    });

    let known_tokens = [5usize, 39, 44, 55, 56, 65];
    let mut known_mismatch_token_trace = Vec::new();
    for token in known_tokens {
        if token >= token_count {
            continue;
        }
        let token_start = token * kv_dim;
        let token_end = token_start + kv_dim;
        let (feature_idx, local_value, official_value, abs_diff) = helper_output
            [token_start..token_end]
            .iter()
            .zip(official_k[token_start..token_end].iter())
            .enumerate()
            .map(|(feature_idx, (local, official))| {
                (feature_idx, *local, *official, (*local - *official).abs())
            })
            .max_by(|(_, _, _, left), (_, _, _, right)| left.total_cmp(right))
            .context("empty K token slice")?;
        let flat_index = token_start + feature_idx;
        let norm_start = token * hidden_size;
        let authoritative_norm_token = &authoritative_norm[norm_start..norm_start + hidden_size];
        known_mismatch_token_trace.push(serde_json::json!({
            "token_index": token,
            "worst_kv_head_index": feature_idx / head_dim,
            "worst_head_dim_lane": feature_idx % head_dim,
            "flat_k_index": flat_index,
            "authoritative_norm_input_checksum_for_token": stable_digest_f32(authoritative_norm_token),
            "runtime_k_projection_value_before_grouped_view": helper_output[flat_index],
            "cpu_rust_replay_k_value": explicit_cpu_replay[flat_index],
            "official_pytorch_k_value": official_k[flat_index],
            "grouped_local_value": helper_output[flat_index],
            "grouped_official_value": official_k[flat_index],
            "local_minus_official": local_value - official_value,
            "abs_diff": abs_diff,
        }));
    }

    let authoritative_guard_regressed = !authoritative_rmsnorm_replay_vs_official.matched;
    let (earliest_operation_where_mismatch_appears, classification, next_bounded_step) =
        if authoritative_guard_regressed {
            (
                "authoritative_rmsnorm_output_guard",
                "authoritative_rmsnorm_provenance_regressed",
                "repair the authoritative RMSNorm replay/provenance before continuing grouped K attribution",
            )
        } else if k_weight_metadata_inconsistent {
            (
                "k_weight_slice_metadata",
                "k_weight_slice_or_orientation_mismatch_after_norm_clear",
                "inspect the runtime K weight slice offsets/orientation against official attn.qkv weight metadata",
            )
        } else if !projection_metrics.matched {
            (
                "k_projection_output_before_grouped_view",
                "k_projection_arithmetic_or_weight_policy_mismatch_after_norm_clear",
                "compare runtime K weight/projection arithmetic policy against official PyTorch attn.qkv K-slice arithmetic under authoritative RMSNorm input",
            )
        } else if !grouped_metrics.matched {
            (
                "grouped_pre_rope_k_layout_view",
                "grouped_k_layout_or_view_mismatch_after_norm_clear",
                "inspect only the flat K to grouped [token, kv_head, lane] view/readout",
            )
        } else {
            (
                "none",
                "grouped_pre_rope_k_cleared_after_authoritative_norm_provenance",
                "rerun grouped post-RoPE K and first attention-score consumer seams",
            )
        };

    let summary = serde_json::json!({
        "schema_version": "runtime_forward_layer0_grouped_pre_rope_k_authoritative_norm_source_breakdown_status/v1",
        "exact_case": KGainPreservationExactCase {
            case_id: input_case.id.clone(),
            input_token_ids: input_case.input_token_ids.clone(),
            hidden_size,
            num_tokens: token_count,
            q_dim,
            kv_dim,
            qkv_dim,
        },
        "mode": "grouped-pre-rope-k-authoritative-norm-source-breakdown-status",
        "source_artifact_paths": {
            "rmsnorm_residual_causality": source_causality_artifact_path,
            "authoritative_rmsnorm_replay_proof": source_authoritative_replay_artifact_path,
            "k_pedantic_helper_fix": source_k_pedantic_fix_artifact_path,
            "ppp_grouped_pre_rope_k_reference_semantics": source_ppp_semantics_artifact_path,
            "official_side_rmsnorm_replay": official_side_replay_path,
            "official_k_rope_bundle": cli.official_k_rope_bundle_artifact.clone(),
        },
        "active_rmsnorm_provenance": {
            "primary_input": "authoritative Rust/PyTorch BF16 RMSNorm replay output",
            "policy": "bf16 input, bf16 weight, f32 pairwise/tree reduction, x * inverse_rms then weight, bf16 output round-trip",
            "authoritative_rmsnorm_replay_vs_official": authoritative_rmsnorm_replay_vs_official,
            "fixed_live_rmsnorm_vs_authoritative_informational": fixed_live_rmsnorm_vs_authoritative,
        },
        "active_k_helper_gemm_policy": {
            "policy": "pedantic all-token K helper path",
            "helper_vs_explicit_cpu_replay_matched": helper_vs_cpu_metrics.matched,
            "source_fix_classification": source_k_pedantic_fix.get("classification").cloned(),
        },
        "k_weight_slice_metadata": k_weight_slice_metadata,
        "per_stage_source_breakdown_metrics": {
            "authoritative_norm_current_pedantic_helper_vs_explicit_cpu_replay": helper_vs_cpu,
            "k_projection_output_before_grouped_view": projection_before_grouped_vs_official,
            "explicit_cpu_rust_replay_before_grouped_view": explicit_replay_vs_official,
            "k_slice_extraction": k_slice_extraction,
            "grouped_pre_rope_k_layout_view": grouped_view_vs_official,
        },
        "known_mismatch_token_trace": known_mismatch_token_trace,
        "earliest_operation_where_mismatch_appears": earliest_operation_where_mismatch_appears,
        "classification": classification,
        "runtime_forward_grouped_pre_rope_k_authoritative_norm_source_breakdown_status_now": format!(
            "runtime-forward grouped pre-RoPE K authoritative-norm source breakdown status now: authoritative RMSNorm guard matched={}; helper_vs_cpu matched={} max_abs={} mean_abs={}; projection_before_grouped_vs_official max_abs={} mean_abs={} matched={}; grouped_view_vs_official max_abs={} mean_abs={} matched={}; earliest_operation={}; classification={}; next bounded step: {}.",
            !authoritative_guard_regressed,
            helper_vs_cpu_metrics.matched,
            helper_vs_cpu_metrics.max_abs_diff,
            helper_vs_cpu_metrics.mean_abs_diff,
            projection_metrics.max_abs_diff,
            projection_metrics.mean_abs_diff,
            projection_metrics.matched,
            grouped_metrics.max_abs_diff,
            grouped_metrics.mean_abs_diff,
            grouped_metrics.matched,
            earliest_operation_where_mismatch_appears,
            classification,
            next_bounded_step
        ),
        "next_bounded_step": next_bounded_step,
    });

    let output = cli.output.clone().unwrap_or_else(|| {
        Mode::GroupedPreRopeKAuthoritativeNormSourceBreakdownStatus.default_output()
    });
    write_pretty_json(&output, &summary)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn matrix_diff_summary_json(
    lhs: &[f32],
    rhs: &[f32],
    rows: usize,
    cols: usize,
    row_name: &str,
    col_name: &str,
) -> Result<(Option<serde_json::Value>, Option<serde_json::Value>)> {
    if lhs.len() != rows * cols || rhs.len() != rows * cols {
        bail!(
            "matrix diff inputs have lengths {} and {}, expected {}",
            lhs.len(),
            rhs.len(),
            rows * cols
        );
    }
    let first =
        lhs.iter()
            .zip(rhs.iter())
            .enumerate()
            .find_map(|(flat_index, (lhs_value, rhs_value))| {
                let abs_diff = (*lhs_value - *rhs_value).abs();
                (abs_diff > 0.0).then(|| {
                    serde_json::json!({
                        row_name: flat_index / cols,
                        col_name: flat_index % cols,
                        "flat_index": flat_index,
                        "lhs_value": lhs_value,
                        "rhs_value": rhs_value,
                        "abs_diff": abs_diff,
                    })
                })
            });
    let worst = lhs
        .iter()
        .zip(rhs.iter())
        .enumerate()
        .map(|(flat_index, (lhs_value, rhs_value))| {
            (
                flat_index,
                *lhs_value,
                *rhs_value,
                (*lhs_value - *rhs_value).abs(),
            )
        })
        .max_by(|(_, _, _, left), (_, _, _, right)| left.total_cmp(right))
        .and_then(|(flat_index, lhs_value, rhs_value, abs_diff)| {
            (abs_diff > 0.0).then(|| {
                serde_json::json!({
                    row_name: flat_index / cols,
                    col_name: flat_index % cols,
                    "flat_index": flat_index,
                    "lhs_value": lhs_value,
                    "rhs_value": rhs_value,
                    "abs_diff": abs_diff,
                })
            })
        });
    Ok((first, worst))
}

fn projection_comparison_json(
    name: &str,
    lhs: &[f32],
    official_module: &[f32],
    token_count: usize,
    kv_dim: usize,
) -> Result<serde_json::Value> {
    let metrics = all_token_hidden_comparison_metrics(lhs, official_module, token_count, kv_dim)?;
    Ok(serde_json::json!({
        "name": name,
        "metrics": metrics,
        "shape": [token_count, kv_dim],
        "dtype": "f32-expanded BF16 values",
        "layout": "[token, k_feature]",
    }))
}

fn f32_left_to_right_sum(values: &[f32]) -> f32 {
    let mut sum = 0.0f32;
    for value in values {
        sum += *value;
    }
    sum
}

fn f32_chunked_sum(values: &[f32], chunk_size: usize) -> f32 {
    let chunk_sums: Vec<f32> = values
        .chunks(chunk_size)
        .map(f32_left_to_right_sum)
        .collect();
    f32_left_to_right_sum(&chunk_sums)
}

fn bf16_dot_products(input_row: &[bf16], weight_row: &[bf16]) -> Result<Vec<f32>> {
    if input_row.len() != weight_row.len() {
        bail!(
            "dot product length mismatch: input {} vs weight {}",
            input_row.len(),
            weight_row.len()
        );
    }
    Ok(input_row
        .iter()
        .zip(weight_row.iter())
        .map(|(input, weight)| input.to_f32() * weight.to_f32())
        .collect())
}

fn bf16_dot_variant_sum(products: &[f32], policy_name: &str) -> Result<f32> {
    match policy_name {
        "current_rust_left_to_right_f32_accumulation" => Ok(f32_left_to_right_sum(products)),
        "pairwise_tree_f32_accumulation" => Ok(f32_pairwise_sum(products)),
        "chunked_16_then_left_to_right_f32_accumulation" => Ok(f32_chunked_sum(products, 16)),
        "chunked_32_then_left_to_right_f32_accumulation" => Ok(f32_chunked_sum(products, 32)),
        "chunked_64_then_left_to_right_f32_accumulation" => Ok(f32_chunked_sum(products, 64)),
        other => bail!("unknown BF16 dot policy {other}"),
    }
}

fn bf16_dot_variant_value(
    input_row: &[bf16],
    weight_row: &[bf16],
    policy_name: &str,
) -> Result<(f32, u16, f32)> {
    let products = bf16_dot_products(input_row, weight_row)?;
    let pre_output = bf16_dot_variant_sum(&products, policy_name)?;
    let output = bf16::from_f32(pre_output);
    Ok((pre_output, output.to_bits(), output.to_f32()))
}

fn summarize_known_lane_variant(
    name: &str,
    outputs: &[f32],
    official_outputs: &[f32],
    rust_outputs: &[f32],
) -> Result<serde_json::Value> {
    if outputs.len() != official_outputs.len() || outputs.len() != rust_outputs.len() {
        bail!("known-lane variant output length mismatch");
    }
    let official_diffs: Vec<f32> = outputs
        .iter()
        .zip(official_outputs.iter())
        .map(|(lhs, rhs)| (*lhs - *rhs).abs())
        .collect();
    let rust_diffs: Vec<f32> = outputs
        .iter()
        .zip(rust_outputs.iter())
        .map(|(lhs, rhs)| (*lhs - *rhs).abs())
        .collect();
    let max_abs_diff_vs_official = official_diffs
        .iter()
        .copied()
        .fold(0.0f32, |acc, value| acc.max(value));
    let mean_abs_diff_vs_official = if official_diffs.is_empty() {
        0.0
    } else {
        official_diffs.iter().sum::<f32>() / official_diffs.len() as f32
    };
    let max_abs_diff_vs_rust = rust_diffs
        .iter()
        .copied()
        .fold(0.0f32, |acc, value| acc.max(value));
    let mean_abs_diff_vs_rust = if rust_diffs.is_empty() {
        0.0
    } else {
        rust_diffs.iter().sum::<f32>() / rust_diffs.len() as f32
    };
    let lanes_matched_official = official_diffs.iter().filter(|diff| **diff == 0.0).count();
    let lanes_matched_rust = rust_diffs.iter().filter(|diff| **diff == 0.0).count();
    Ok(serde_json::json!({
        "name": name,
        "max_abs_diff_vs_official": max_abs_diff_vs_official,
        "mean_abs_diff_vs_official": mean_abs_diff_vs_official,
        "lanes_matched_official": lanes_matched_official,
        "matches_official_all_known_lanes": lanes_matched_official == outputs.len(),
        "max_abs_diff_vs_rust_helper": max_abs_diff_vs_rust,
        "mean_abs_diff_vs_rust_helper": mean_abs_diff_vs_rust,
        "lanes_matched_rust_helper": lanes_matched_rust,
        "matches_rust_helper_all_known_lanes": lanes_matched_rust == outputs.len(),
        "outputs": outputs,
    }))
}

fn run_k_projection_official_weight_arithmetic_status(cli: &Cli) -> Result<()> {
    let source_breakdown_artifact_path =
        PathBuf::from(DEFAULT_GROUPED_PRE_ROPE_K_AUTHORITATIVE_NORM_SOURCE_BREAKDOWN_STATUS_OUTPUT);
    let source_authoritative_replay_artifact_path = PathBuf::from(
        DEFAULT_LAYER0_ATTN_RMSNORM_RUST_BF16_REPLAY_MULTIPLY_ORDER_FIX_STATUS_OUTPUT,
    );
    let source_k_pedantic_fix_artifact_path =
        PathBuf::from(DEFAULT_ALL_TOKEN_K_PEDANTIC_RUNTIME_FIX_STATUS_OUTPUT);

    let source_breakdown: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_breakdown_artifact_path).with_context(|| {
            format!(
                "failed to read authoritative-norm grouped K source breakdown artifact {}",
                source_breakdown_artifact_path.display()
            )
        })?,
    )?;
    if source_breakdown
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || source_breakdown
            .get("classification")
            .and_then(serde_json::Value::as_str)
            != Some("k_projection_arithmetic_or_weight_policy_mismatch_after_norm_clear")
    {
        bail!("source grouped K authoritative-norm breakdown artifact is not the expected state");
    }
    let source_authoritative_replay: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_authoritative_replay_artifact_path).with_context(
            || {
                format!(
                    "failed to read authoritative replay proof artifact {}",
                    source_authoritative_replay_artifact_path.display()
                )
            },
        )?,
    )?;
    if source_authoritative_replay
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || source_authoritative_replay
            .get("classification")
            .and_then(serde_json::Value::as_str)
            != Some("rust_bf16_replay_multiply_order_fix_proven")
    {
        bail!("source authoritative replay proof artifact is not the expected exact proven state");
    }
    let source_k_pedantic_fix: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_k_pedantic_fix_artifact_path).with_context(|| {
            format!(
                "failed to read K pedantic helper fix artifact {}",
                source_k_pedantic_fix_artifact_path.display()
            )
        })?,
    )?;
    if source_k_pedantic_fix
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || source_k_pedantic_fix
            .get("classification")
            .and_then(serde_json::Value::as_str)
            != Some("all_token_k_pedantic_runtime_fix_proven")
    {
        bail!("source K pedantic helper fix artifact is not the expected exact proven state");
    }

    let (input_artifact, input_case) =
        load_single_case_artifact(&cli.local_residual_input_artifact)?;
    validate_exact_case_artifact(
        &input_artifact,
        &input_case,
        "layer0_residual_input",
        "developer-message-user-smoke",
        &input_case.input_token_ids,
    )?;
    let hidden_size = input_case
        .hidden_size
        .context("exact smoke case missing hidden_size")?;
    let model_root = Path::new(&input_artifact.provenance.model);
    let max_model_len = input_artifact.provenance.max_model_len.unwrap_or(128);
    let gpu_memory_utilization = input_artifact
        .provenance
        .gpu_memory_utilization
        .unwrap_or(0.75);

    let official_side_replay_path = cli
        .official_attn_rmsnorm_all_token_bf16_replay_artifact
        .clone();
    if let Some(parent) = official_side_replay_path.parent() {
        std::fs::create_dir_all(parent)?;
    }
    let official_side_status = Command::new(&cli.torch_python)
        .arg(&cli.official_attn_rmsnorm_all_token_bf16_replay_script)
        .arg("--model-root")
        .arg(model_root)
        .arg("--output")
        .arg(&official_side_replay_path)
        .arg("--device")
        .arg("cpu")
        .status()
        .with_context(|| {
            format!(
                "failed to run official-side RMSNorm replay script {} with {}",
                cli.official_attn_rmsnorm_all_token_bf16_replay_script
                    .display(),
                cli.torch_python.display()
            )
        })?;
    if !official_side_status.success() {
        bail!(
            "official-side RMSNorm replay script failed with status {:?}",
            official_side_status.code()
        );
    }
    let official_side: OfficialSideRmsNormReplayArtifact = serde_json::from_str(
        &std::fs::read_to_string(&official_side_replay_path).with_context(|| {
            format!(
                "failed to read official-side RMSNorm replay artifact {}",
                official_side_replay_path.display()
            )
        })?,
    )?;
    if official_side.case_id != "developer-message-user-smoke"
        || official_side.input_token_ids != input_case.input_token_ids
        || official_side.hidden_size != hidden_size
    {
        bail!("official-side RMSNorm replay artifact does not match exact smoke case");
    }
    let token_count = official_side.token_count;
    let authoritative_norm = replay_rmsnorm_bf16_policy_output_pairwise_reduction(
        &official_side.official_input_f32,
        &official_side.official_weight_f32,
        token_count,
        hidden_size,
        official_side.epsilon,
    )?;
    let authoritative_rmsnorm_replay_vs_official = all_token_hidden_comparison_metrics(
        &authoritative_norm,
        &official_side.official_module_output_f32,
        token_count,
        hidden_size,
    )?;

    let official_extraction_path = cli.official_k_projection_weight_arithmetic_artifact.clone();
    if let Some(parent) = official_extraction_path.parent() {
        std::fs::create_dir_all(parent)?;
    }
    let official_extraction_status = Command::new(&cli.torch_python)
        .arg(&cli.official_k_projection_weight_arithmetic_script)
        .arg("--model-root")
        .arg(model_root)
        .arg("--rmsnorm-replay")
        .arg(&official_side_replay_path)
        .arg("--output")
        .arg(&official_extraction_path)
        .arg("--device")
        .arg("cpu")
        .status()
        .with_context(|| {
            format!(
                "failed to run official K projection extraction script {} with {}",
                cli.official_k_projection_weight_arithmetic_script.display(),
                cli.torch_python.display()
            )
        })?;
    if !official_extraction_status.success() {
        bail!(
            "official K projection extraction script failed with status {:?}",
            official_extraction_status.code()
        );
    }
    let official_extraction: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&official_extraction_path).with_context(|| {
            format!(
                "failed to read official K projection extraction artifact {}",
                official_extraction_path.display()
            )
        })?,
    )?;
    if official_extraction
        .get("case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
    {
        bail!("official K projection extraction artifact is not the exact smoke case");
    }

    info!(
        model_root = %model_root.display(),
        max_model_len,
        gpu_memory_utilization,
        "starting exact-case K projection official weight/arithmetic status run"
    );
    let _bf16_guard = EnvFlagGuard::set(BF16_DENSE_QKV_ENV, true);
    let worker = build_worker(model_root, max_model_len, gpu_memory_utilization)?;
    let live_trace = capture_layer0_qkv_trace(&worker, &input_case.input_token_ids)?;
    if !live_trace.branch_taken {
        bail!("K projection official weight/arithmetic trace did not take bf16 fused-qkv branch");
    }
    let kv_dim = live_trace.kv_dim;
    let q_dim = live_trace.q_dim;
    let qkv_dim = live_trace.qkv_dim;
    if live_trace.num_tokens != token_count
        || live_trace.standalone_k_weight_bf16_bits.len() != kv_dim * hidden_size
    {
        bail!("live trace K dimensions do not match exact case");
    }

    let official_k_weight: Vec<f32> = serde_json::from_value(
        official_extraction
            .get("official_k_weight_f32")
            .cloned()
            .context("official extraction missing official_k_weight_f32")?,
    )?;
    let official_k_bias: Vec<f32> = serde_json::from_value(
        official_extraction
            .get("official_k_bias_f32")
            .cloned()
            .unwrap_or_else(|| serde_json::json!([])),
    )?;
    let official_module_k_output: Vec<f32> = serde_json::from_value(
        official_extraction
            .pointer("/official_projection_outputs/official_module_k_output_f32")
            .cloned()
            .context("official extraction missing module K output")?,
    )?;
    let official_manual_k_output: Vec<f32> = serde_json::from_value(
        official_extraction
            .pointer("/official_projection_outputs/official_manual_k_output_f32")
            .cloned()
            .context("official extraction missing manual K output")?,
    )?;
    if official_k_weight.len() != kv_dim * hidden_size
        || official_module_k_output.len() != token_count * kv_dim
        || official_manual_k_output.len() != token_count * kv_dim
    {
        bail!("official K extraction shapes do not match runtime dimensions");
    }

    let runtime_k_weight_bf16 = bf16_bits_to_bf16_slice(&live_trace.standalone_k_weight_bf16_bits);
    let runtime_k_weight = bf16_slice_to_f32(&runtime_k_weight_bf16);
    let official_k_weight_bf16: Vec<bf16> = official_k_weight
        .iter()
        .map(|value| bf16::from_f32(*value))
        .collect();
    let authoritative_norm_bf16: Vec<bf16> = authoritative_norm
        .iter()
        .map(|value| bf16::from_f32(*value))
        .collect();
    let runtime_cpu_replay_bf16 = cpu_bf16_row_major_gemm(
        &authoritative_norm_bf16,
        &runtime_k_weight_bf16,
        token_count,
        kv_dim,
        hidden_size,
    )?;
    let runtime_cpu_replay = bf16_slice_to_f32(&runtime_cpu_replay_bf16);
    let official_weight_rust_replay_bf16 = cpu_bf16_row_major_gemm(
        &authoritative_norm_bf16,
        &official_k_weight_bf16,
        token_count,
        kv_dim,
        hidden_size,
    )?;
    let official_weight_rust_replay = bf16_slice_to_f32(&official_weight_rust_replay_bf16);

    let stream = worker.gpu_stream().clone();
    let authoritative_norm_gpu = stream
        .clone_htod(&authoritative_norm_bf16)
        .map_err(|e| anyhow::anyhow!("authoritative norm htod failed: {e}"))?;
    let runtime_k_weight_gpu = stream
        .clone_htod(&runtime_k_weight_bf16)
        .map_err(|e| anyhow::anyhow!("runtime K weight htod failed: {e}"))?;
    let mut runtime_helper_gpu = stream
        .alloc_zeros::<bf16>(token_count * kv_dim)
        .map_err(|e| anyhow::anyhow!("runtime K helper output alloc failed: {e}"))?;
    worker.blas().hgemm_bf16_pedantic_no_tensor_op(
        token_count,
        kv_dim,
        hidden_size,
        bf16::ONE,
        &authoritative_norm_gpu,
        &runtime_k_weight_gpu,
        bf16::ZERO,
        &mut runtime_helper_gpu,
    )?;
    let runtime_helper: Vec<f32> = stream
        .clone_dtoh(&runtime_helper_gpu)
        .map_err(|e| anyhow::anyhow!("runtime K helper dtoh failed: {e}"))?
        .iter()
        .map(|value| value.to_f32())
        .collect();

    let k_weight_metrics = compare_vectors(&runtime_k_weight, &official_k_weight)?;
    let (weight_first, weight_worst) = matrix_diff_summary_json(
        &runtime_k_weight,
        &official_k_weight,
        kv_dim,
        hidden_size,
        "k_output_feature_row",
        "hidden_lane",
    )?;
    let k_weight_comparison_metrics = serde_json::json!({
        "metrics": k_weight_metrics,
        "shape": [kv_dim, hidden_size],
        "runtime_dtype": "bf16",
        "official_dtype": official_extraction.pointer("/official_k_weight_metadata/dtype").and_then(serde_json::Value::as_str).unwrap_or("unknown"),
        "runtime_orientation": "row-major [k_output_feature, hidden]",
        "official_orientation": official_extraction.pointer("/official_k_weight_metadata/layout_orientation").and_then(serde_json::Value::as_str).unwrap_or("unknown"),
        "runtime_digest": stable_digest_f32(&runtime_k_weight),
        "official_digest": stable_digest_f32(&official_k_weight),
        "first_differing_row_hidden_lane": weight_first,
        "worst_differing_row_hidden_lane": weight_worst,
    });

    let runtime_bias_bits = &live_trace.canonical_k_bias_bf16_bits;
    let runtime_bias_f32 = bf16_bits_to_f32_slice(runtime_bias_bits);
    let runtime_bias_all_zero = runtime_bias_f32.iter().all(|value| *value == 0.0);
    let official_bias_all_zero = official_k_bias.iter().all(|value| *value == 0.0);
    let bias_metrics =
        if !official_k_bias.is_empty() && runtime_bias_f32.len() == official_k_bias.len() {
            Some(compare_vectors(&runtime_bias_f32, &official_k_bias)?)
        } else {
            None
        };
    let k_bias_metadata = serde_json::json!({
        "official": official_extraction.get("k_bias_metadata").cloned(),
        "runtime": {
            "exists": !runtime_bias_f32.is_empty(),
            "shape": if runtime_bias_f32.is_empty() { vec![] } else { vec![runtime_bias_f32.len()] },
            "dtype": if runtime_bias_f32.is_empty() { "none" } else { "bf16" },
            "max_abs": runtime_bias_f32.iter().fold(0.0f32, |acc, value| acc.max(value.abs())),
            "mean_abs": if runtime_bias_f32.is_empty() { 0.0 } else { runtime_bias_f32.iter().map(|value| value.abs()).sum::<f32>() / runtime_bias_f32.len() as f32 },
            "stable_digest": stable_digest_f32(&runtime_bias_f32),
            "all_zero": runtime_bias_all_zero,
        },
        "runtime_vs_official_metrics": bias_metrics,
        "bias_policy_consistent": (official_k_bias.is_empty() || official_bias_all_zero) && (runtime_bias_f32.is_empty() || runtime_bias_all_zero),
    });

    let projection_table = serde_json::json!({
        "official_module_k_output_vs_itself": projection_comparison_json(
            "official_module_k_output_vs_itself",
            &official_module_k_output,
            &official_module_k_output,
            token_count,
            kv_dim,
        )?,
        "official_manual_pytorch_k_projection_vs_official_module": projection_comparison_json(
            "official_manual_pytorch_k_projection_vs_official_module",
            &official_manual_k_output,
            &official_module_k_output,
            token_count,
            kv_dim,
        )?,
        "rust_cpu_replay_authoritative_input_runtime_k_weight_vs_official_module": projection_comparison_json(
            "rust_cpu_replay_authoritative_input_runtime_k_weight_vs_official_module",
            &runtime_cpu_replay,
            &official_module_k_output,
            token_count,
            kv_dim,
        )?,
        "rust_pedantic_helper_authoritative_input_runtime_k_weight_vs_official_module": projection_comparison_json(
            "rust_pedantic_helper_authoritative_input_runtime_k_weight_vs_official_module",
            &runtime_helper,
            &official_module_k_output,
            token_count,
            kv_dim,
        )?,
        "rust_cpu_replay_authoritative_input_official_k_weight_vs_official_module": projection_comparison_json(
            "rust_cpu_replay_authoritative_input_official_k_weight_vs_official_module",
            &official_weight_rust_replay,
            &official_module_k_output,
            token_count,
            kv_dim,
        )?,
        "rust_pedantic_helper_vs_rust_cpu_replay_runtime_k_weight": projection_comparison_json(
            "rust_pedantic_helper_vs_rust_cpu_replay_runtime_k_weight",
            &runtime_helper,
            &runtime_cpu_replay,
            token_count,
            kv_dim,
        )?,
    });

    let official_manual_metrics: CompareMetrics = serde_json::from_value(
        projection_table
            .pointer("/official_manual_pytorch_k_projection_vs_official_module/metrics")
            .cloned()
            .context("projection table missing official manual metrics")?,
    )?;
    let rust_runtime_metrics: CompareMetrics = serde_json::from_value(
        projection_table
            .pointer(
                "/rust_cpu_replay_authoritative_input_runtime_k_weight_vs_official_module/metrics",
            )
            .cloned()
            .context("projection table missing rust runtime metrics")?,
    )?;
    let rust_official_weight_metrics: CompareMetrics = serde_json::from_value(
        projection_table
            .pointer(
                "/rust_cpu_replay_authoritative_input_official_k_weight_vs_official_module/metrics",
            )
            .cloned()
            .context("projection table missing rust official-weight metrics")?,
    )?;
    let helper_vs_cpu_metrics: CompareMetrics = serde_json::from_value(
        projection_table
            .pointer("/rust_pedantic_helper_vs_rust_cpu_replay_runtime_k_weight/metrics")
            .cloned()
            .context("projection table missing helper-vs-cpu metrics")?,
    )?;

    let known_tokens = [5usize, 39, 44, 55, 56, 65];
    let mut known_mismatch_token_trace = Vec::new();
    for token in known_tokens {
        if token >= token_count {
            continue;
        }
        let token_start = token * kv_dim;
        let token_end = token_start + kv_dim;
        let (feature_idx, _, official_value, abs_diff) = runtime_cpu_replay[token_start..token_end]
            .iter()
            .zip(official_module_k_output[token_start..token_end].iter())
            .enumerate()
            .map(|(feature_idx, (local, official))| {
                (feature_idx, *local, *official, (*local - *official).abs())
            })
            .max_by(|(_, _, _, left), (_, _, _, right)| left.total_cmp(right))
            .context("empty K token slice")?;
        let flat_index = token_start + feature_idx;
        let norm_start = token * hidden_size;
        known_mismatch_token_trace.push(serde_json::json!({
            "token_index": token,
            "worst_k_feature_index": feature_idx,
            "worst_kv_head_index": feature_idx / 64,
            "worst_head_dim_lane": feature_idx % 64,
            "flat_k_index": flat_index,
            "authoritative_rmsnorm_input_checksum_for_token": stable_digest_f32(&authoritative_norm[norm_start..norm_start + hidden_size]),
            "official_manual_pytorch_k_value": official_manual_k_output[flat_index],
            "official_module_k_value": official_module_k_output[flat_index],
            "rust_cpu_replay_k_value": runtime_cpu_replay[flat_index],
            "pedantic_helper_k_value": runtime_helper[flat_index],
            "local_grouped_k_value": runtime_cpu_replay[flat_index],
            "official_grouped_pre_rope_k_value": official_value,
            "local_minus_official": runtime_cpu_replay[flat_index] - official_value,
            "abs_diff": abs_diff,
        }));
    }

    let orientation_range_suspect = q_dim + kv_dim > qkv_dim
        || official_extraction
            .pointer("/official_k_weight_metadata/k_slice_row_range")
            .and_then(serde_json::Value::as_array)
            .is_some_and(|range| {
                range.first().and_then(serde_json::Value::as_u64) != Some(q_dim as u64)
                    || range.get(1).and_then(serde_json::Value::as_u64)
                        != Some((q_dim + kv_dim) as u64)
            });
    let bias_policy_mismatch =
        !official_bias_all_zero || (!runtime_bias_f32.is_empty() && !runtime_bias_all_zero);
    let (earliest_divergent_source, classification, next_bounded_step) =
        if orientation_range_suspect {
            (
                "weight/slice",
                "k_weight_slice_or_orientation_mismatch_after_norm_clear",
                "fix/prove the K slice offset/orientation contract against official attn.qkv",
            )
        } else if !k_weight_metrics.matched {
            (
            "weight/slice",
            "k_weight_value_or_loader_mismatch_after_norm_clear",
            "compare runtime weight loading/casting for the layer0 attn.qkv K slice against official checkpoint values",
        )
        } else if bias_policy_mismatch {
            (
                "bias",
                "k_bias_policy_mismatch_after_norm_clear",
                "align the K bias policy at the layer0 attn.qkv K projection seam",
            )
        } else if !official_manual_metrics.matched {
            (
            "official manual replay mismatch",
            "official_qkv_manual_projection_policy_not_modeled",
            "model the exact official PyTorch qkv module arithmetic before changing runtime projection",
        )
        } else if !rust_runtime_metrics.matched
            || !helper_vs_cpu_metrics.matched
            || !rust_official_weight_metrics.matched
        {
            (
            "arithmetic/dtype policy",
            "k_projection_arithmetic_dtype_policy_mismatch_after_weight_clear",
            "inspect BF16 linear arithmetic policy differences between Rust replay/helper and official PyTorch under matched weights",
        )
        } else {
            (
                "none",
                "k_projection_mismatch_cleared_or_prior_measurement_bug",
                "rerun grouped-pre-rope-k-authoritative-norm-source-breakdown-status",
            )
        };

    let summary = serde_json::json!({
        "schema_version": "runtime_forward_layer0_k_projection_official_weight_arithmetic_status/v1",
        "exact_case": KGainPreservationExactCase {
            case_id: input_case.id.clone(),
            input_token_ids: input_case.input_token_ids.clone(),
            hidden_size,
            num_tokens: token_count,
            q_dim,
            kv_dim,
            qkv_dim,
        },
        "mode": "k-projection-official-weight-arithmetic-status",
        "source_artifact_paths": {
            "grouped_pre_rope_k_authoritative_norm_source_breakdown": source_breakdown_artifact_path,
            "authoritative_rmsnorm_replay_proof": source_authoritative_replay_artifact_path,
            "k_pedantic_helper_fix": source_k_pedantic_fix_artifact_path,
            "official_rmsnorm_replay": official_side_replay_path,
        },
        "python_script_path_used_for_official_extraction": cli.official_k_projection_weight_arithmetic_script.clone(),
        "official_extraction_artifact_path": official_extraction_path,
        "authoritative_rmsnorm_guard_metric": authoritative_rmsnorm_replay_vs_official,
        "official_k_weight_metadata": official_extraction.get("official_k_weight_metadata").cloned(),
        "runtime_k_weight_metadata": {
            "source_tensor_name": "layer0 fused attn.qkv weight cast to BF16; extracted K slice",
            "fused_attn_qkv_weight_logical_shape": [qkv_dim, hidden_size],
            "k_slice_offsets_elements": [q_dim * hidden_size, (q_dim + kv_dim) * hidden_size],
            "k_slice_shape": [kv_dim, hidden_size],
            "dtype": "bf16",
            "orientation": "row-major [k_output_feature, hidden]",
            "helper_contract": "activation[token, hidden] x K_weight^T",
            "stride": [hidden_size, 1],
            "stable_digest": stable_digest_f32(&runtime_k_weight),
        },
        "k_weight_comparison_metrics": k_weight_comparison_metrics,
        "k_bias_metadata": k_bias_metadata,
        "projection_arithmetic_comparison_table": projection_table,
        "known_mismatch_token_trace": known_mismatch_token_trace,
        "earliest_divergent_source": earliest_divergent_source,
        "classification": classification,
        "runtime_forward_k_projection_official_weight_arithmetic_status_now": format!(
            "runtime-forward K projection official weight/arithmetic status now: weight matched={} max_abs={} mean_abs={}; official_manual_vs_module matched={} max_abs={} mean_abs={}; rust_runtime_vs_official matched={} max_abs={} mean_abs={}; rust_official_weight_vs_official matched={} max_abs={} mean_abs={}; helper_vs_cpu matched={}; earliest_divergent_source={}; classification={}; next bounded step: {}.",
            k_weight_metrics.matched,
            k_weight_metrics.max_abs_diff,
            k_weight_metrics.mean_abs_diff,
            official_manual_metrics.matched,
            official_manual_metrics.max_abs_diff,
            official_manual_metrics.mean_abs_diff,
            rust_runtime_metrics.matched,
            rust_runtime_metrics.max_abs_diff,
            rust_runtime_metrics.mean_abs_diff,
            rust_official_weight_metrics.matched,
            rust_official_weight_metrics.max_abs_diff,
            rust_official_weight_metrics.mean_abs_diff,
            helper_vs_cpu_metrics.matched,
            earliest_divergent_source,
            classification,
            next_bounded_step,
        ),
        "next_bounded_step": next_bounded_step,
    });

    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::KProjectionOfficialWeightArithmeticStatus.default_output());
    write_pretty_json(&output, &summary)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn run_k_projection_bf16_linear_policy_discriminator_status(cli: &Cli) -> Result<()> {
    let source_artifact_path =
        PathBuf::from(DEFAULT_K_PROJECTION_OFFICIAL_WEIGHT_ARITHMETIC_STATUS_OUTPUT);
    let source: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_artifact_path).with_context(|| {
            format!(
                "failed to read K projection official weight/arithmetic artifact {}",
                source_artifact_path.display()
            )
        })?,
    )?;
    if source
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || source
            .get("classification")
            .and_then(serde_json::Value::as_str)
            != Some("k_projection_arithmetic_dtype_policy_mismatch_after_weight_clear")
    {
        bail!("source K projection official weight/arithmetic artifact is not the expected state");
    }

    let (input_artifact, input_case) =
        load_single_case_artifact(&cli.local_residual_input_artifact)?;
    validate_exact_case_artifact(
        &input_artifact,
        &input_case,
        "layer0_residual_input",
        "developer-message-user-smoke",
        &input_case.input_token_ids,
    )?;
    let model_root = Path::new(&input_artifact.provenance.model);
    let hidden_size = source
        .pointer("/exact_case/hidden_size")
        .and_then(serde_json::Value::as_u64)
        .context("source artifact missing hidden_size")? as usize;
    let token_count = source
        .pointer("/exact_case/num_tokens")
        .and_then(serde_json::Value::as_u64)
        .context("source artifact missing token_count")? as usize;
    let kv_dim = source
        .pointer("/exact_case/kv_dim")
        .and_then(serde_json::Value::as_u64)
        .context("source artifact missing kv_dim")? as usize;

    let official_side_replay_path =
        PathBuf::from(DEFAULT_LAYER0_ATTN_RMSNORM_ALL_TOKEN_BF16_REPLAY_OFFICIAL_SIDE_OUTPUT);
    let official_extraction_path = cli.official_k_projection_weight_arithmetic_artifact.clone();
    let official_extraction_status = Command::new(&cli.torch_python)
        .arg(&cli.official_k_projection_weight_arithmetic_script)
        .arg("--model-root")
        .arg(model_root)
        .arg("--rmsnorm-replay")
        .arg(&official_side_replay_path)
        .arg("--output")
        .arg(&official_extraction_path)
        .arg("--device")
        .arg("cpu")
        .status()
        .with_context(|| {
            format!(
                "failed to run official K projection extraction script {} with {}",
                cli.official_k_projection_weight_arithmetic_script.display(),
                cli.torch_python.display()
            )
        })?;
    if !official_extraction_status.success() {
        bail!(
            "official K projection extraction script failed with status {:?}",
            official_extraction_status.code()
        );
    }

    let official_extraction: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&official_extraction_path).with_context(|| {
            format!(
                "failed to read official K projection extraction artifact {}",
                official_extraction_path.display()
            )
        })?,
    )?;
    let official_side: OfficialSideRmsNormReplayArtifact = serde_json::from_str(
        &std::fs::read_to_string(&official_side_replay_path).with_context(|| {
            format!(
                "failed to read official-side RMSNorm replay artifact {}",
                official_side_replay_path.display()
            )
        })?,
    )?;
    if official_side.case_id != "developer-message-user-smoke"
        || official_side.hidden_size != hidden_size
        || official_side.token_count != token_count
    {
        bail!("official-side RMSNorm replay artifact does not match source exact case");
    }
    let authoritative_norm = official_side
        .policy_outputs_f32
        .get("manual_bf16_input_bf16_weight_f32_reduction_bf16_output")
        .context("official-side RMSNorm replay missing authoritative policy output")?;
    if authoritative_norm.len() != token_count * hidden_size {
        bail!("authoritative norm shape mismatch");
    }
    let authoritative_norm_bf16: Vec<bf16> = authoritative_norm
        .iter()
        .map(|value| bf16::from_f32(*value))
        .collect();
    let official_k_weight_f32: Vec<f32> = serde_json::from_value(
        official_extraction
            .get("official_k_weight_f32")
            .cloned()
            .context("official extraction missing official_k_weight_f32")?,
    )?;
    if official_k_weight_f32.len() != kv_dim * hidden_size {
        bail!("official K weight shape mismatch");
    }
    let official_k_weight_bf16: Vec<bf16> = official_k_weight_f32
        .iter()
        .map(|value| bf16::from_f32(*value))
        .collect();
    let official_module_k_output: Vec<f32> = serde_json::from_value(
        official_extraction
            .pointer("/official_projection_outputs/official_module_k_output_f32")
            .cloned()
            .context("official extraction missing module K output")?,
    )?;
    let official_manual_k_output: Vec<f32> = serde_json::from_value(
        official_extraction
            .pointer("/official_projection_outputs/official_manual_k_output_f32")
            .cloned()
            .context("official extraction missing manual K output")?,
    )?;
    if official_module_k_output.len() != token_count * kv_dim
        || official_manual_k_output.len() != token_count * kv_dim
    {
        bail!("official K output shape mismatch");
    }

    let known_source = source
        .get("known_mismatch_token_trace")
        .and_then(serde_json::Value::as_array)
        .context("source artifact missing known_mismatch_token_trace")?;
    let mut known_lanes = Vec::new();
    for item in known_source {
        let token = item
            .get("token_index")
            .and_then(serde_json::Value::as_u64)
            .context("known lane missing token_index")? as usize;
        let feature = item
            .get("worst_k_feature_index")
            .and_then(serde_json::Value::as_u64)
            .context("known lane missing worst_k_feature_index")? as usize;
        known_lanes.push((token, feature));
    }
    let worst_token = 65usize;
    let worst_feature = 293usize;

    let policy_names = [
        "current_rust_left_to_right_f32_accumulation",
        "pairwise_tree_f32_accumulation",
        "chunked_16_then_left_to_right_f32_accumulation",
        "chunked_32_then_left_to_right_f32_accumulation",
        "chunked_64_then_left_to_right_f32_accumulation",
    ];
    let mut policy_outputs: BTreeMap<&str, Vec<f32>> = BTreeMap::new();
    let mut policy_pre_outputs: BTreeMap<&str, Vec<f32>> = BTreeMap::new();
    let mut policy_bits: BTreeMap<&str, Vec<u16>> = BTreeMap::new();
    for policy_name in policy_names {
        let mut outputs = Vec::with_capacity(known_lanes.len());
        let mut pre_outputs = Vec::with_capacity(known_lanes.len());
        let mut bits = Vec::with_capacity(known_lanes.len());
        for (token, feature) in &known_lanes {
            let input_row =
                &authoritative_norm_bf16[token * hidden_size..(token + 1) * hidden_size];
            let weight_row =
                &official_k_weight_bf16[feature * hidden_size..(feature + 1) * hidden_size];
            let (pre_output, output_bits, output_value) =
                bf16_dot_variant_value(input_row, weight_row, policy_name)?;
            pre_outputs.push(pre_output);
            bits.push(output_bits);
            outputs.push(output_value);
        }
        policy_outputs.insert(policy_name, outputs);
        policy_pre_outputs.insert(policy_name, pre_outputs);
        policy_bits.insert(policy_name, bits);
    }

    let official_known_outputs: Vec<f32> = known_lanes
        .iter()
        .map(|(token, feature)| official_module_k_output[token * kv_dim + feature])
        .collect();
    let rust_known_outputs: Vec<f32> = known_source
        .iter()
        .map(|item| {
            item.get("rust_cpu_replay_k_value")
                .and_then(serde_json::Value::as_f64)
                .unwrap_or(0.0) as f32
        })
        .collect();
    let helper_known_outputs: Vec<f32> = known_source
        .iter()
        .map(|item| {
            item.get("pedantic_helper_k_value")
                .and_then(serde_json::Value::as_f64)
                .unwrap_or(0.0) as f32
        })
        .collect();
    let mut discriminator_table = Vec::new();
    discriminator_table.push(summarize_known_lane_variant(
        "official_pytorch_manual_projection_policy",
        &official_manual_k_output
            .chunks(kv_dim)
            .enumerate()
            .flat_map(|(token, row)| {
                known_lanes
                    .iter()
                    .filter(move |(known_token, _)| *known_token == token)
                    .map(move |(_, feature)| row[*feature])
            })
            .collect::<Vec<_>>(),
        &official_known_outputs,
        &rust_known_outputs,
    )?);
    for policy_name in policy_names {
        discriminator_table.push(summarize_known_lane_variant(
            policy_name,
            policy_outputs.get(policy_name).unwrap(),
            &official_known_outputs,
            &rust_known_outputs,
        )?);
    }

    let mut known_mismatch_lane_table = Vec::new();
    for (idx, (token, feature)) in known_lanes.iter().enumerate() {
        let flat_index = token * kv_dim + feature;
        let local_minus_official = rust_known_outputs[idx] - official_module_k_output[flat_index];
        let rust_bits = bf16::from_f32(rust_known_outputs[idx]).to_bits();
        let official_bits = bf16::from_f32(official_module_k_output[flat_index]).to_bits();
        known_mismatch_lane_table.push(serde_json::json!({
            "token_index": token,
            "k_feature_index": feature,
            "kv_head_index": feature / 64,
            "head_dim_lane": feature % 64,
            "official_module_value": official_module_k_output[flat_index],
            "official_manual_pytorch_value": official_manual_k_output[flat_index],
            "rust_cpu_replay_value": rust_known_outputs[idx],
            "pedantic_helper_value": helper_known_outputs[idx],
            "local_minus_official": local_minus_official,
            "abs_diff": local_minus_official.abs(),
            "rust_bf16_bits": format!("0x{rust_bits:04x}"),
            "official_bf16_bits": format!("0x{official_bits:04x}"),
            "bf16_bits_differ": rust_bits != official_bits,
            "one_bf16_ulp_or_less_at_this_magnitude": (rust_bits as i32 - official_bits as i32).abs() <= 1,
        }));
    }

    let worst_input_row =
        &authoritative_norm_bf16[worst_token * hidden_size..(worst_token + 1) * hidden_size];
    let worst_weight_row =
        &official_k_weight_bf16[worst_feature * hidden_size..(worst_feature + 1) * hidden_size];
    let worst_input_row_f32: Vec<f32> =
        worst_input_row.iter().map(|value| value.to_f32()).collect();
    let worst_weight_row_f32: Vec<f32> = worst_weight_row
        .iter()
        .map(|value| value.to_f32())
        .collect();
    let worst_flat = worst_token * kv_dim + worst_feature;
    let current_pre = policy_pre_outputs
        .get("current_rust_left_to_right_f32_accumulation")
        .and_then(|values| values.last())
        .copied()
        .context("missing current worst pre-output")?;
    let current_bits = policy_bits
        .get("current_rust_left_to_right_f32_accumulation")
        .and_then(|values| values.last())
        .copied()
        .context("missing current worst bits")?;
    let best_scalar_policy = discriminator_table
        .iter()
        .filter(|item| {
            item.get("name").and_then(serde_json::Value::as_str)
                != Some("official_pytorch_manual_projection_policy")
        })
        .max_by(|left, right| {
            let l = left
                .get("lanes_matched_official")
                .and_then(serde_json::Value::as_u64)
                .unwrap_or(0);
            let r = right
                .get("lanes_matched_official")
                .and_then(serde_json::Value::as_u64)
                .unwrap_or(0);
            l.cmp(&r).then_with(|| {
                let ldiff = left
                    .get("max_abs_diff_vs_official")
                    .and_then(serde_json::Value::as_f64)
                    .unwrap_or(f64::INFINITY);
                let rdiff = right
                    .get("max_abs_diff_vs_official")
                    .and_then(serde_json::Value::as_f64)
                    .unwrap_or(f64::INFINITY);
                rdiff.total_cmp(&ldiff)
            })
        })
        .cloned()
        .context("no scalar policy variants")?;
    let best_scalar_name = best_scalar_policy
        .get("name")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("unknown");
    let best_scalar_index = policy_names
        .iter()
        .position(|name| *name == best_scalar_name)
        .unwrap_or(0);
    let best_scalar_pre = policy_pre_outputs
        .get(best_scalar_name)
        .and_then(|values| values.last())
        .copied();
    let best_scalar_bits = policy_bits
        .get(best_scalar_name)
        .and_then(|values| values.last())
        .copied();
    let products = bf16_dot_products(worst_input_row, worst_weight_row)?;
    let product_digest = stable_digest_f32(&products);
    let current_matches_rust = policy_outputs
        .get("current_rust_left_to_right_f32_accumulation")
        .is_some_and(|values| values == &rust_known_outputs);
    let scalar_full_match = discriminator_table.iter().any(|item| {
        item.get("name").and_then(serde_json::Value::as_str)
            != Some("official_pytorch_manual_projection_policy")
            && item
                .get("matches_official_all_known_lanes")
                .and_then(serde_json::Value::as_bool)
                == Some(true)
    });
    let official_manual_metrics =
        compare_vectors(&official_manual_k_output, &official_module_k_output)?;
    let (earliest_divergent_stage, classification, next_bounded_step) = if official_known_outputs
        == rust_known_outputs
    {
        (
            "none",
            "k_projection_arithmetic_mismatch_cleared_or_prior_measurement_bug",
            "rerun grouped-pre-rope-k-authoritative-norm-source-breakdown-status",
        )
    } else if scalar_full_match && current_matches_rust {
        (
            "accumulation_order",
            "k_projection_reduction_order_delta_identified",
            "prove/fix the K projection dot-product reduction order against the scalar variant that matches official",
        )
    } else {
        (
            "accumulation_order",
            "official_k_projection_policy_not_fully_modeled",
            "model the exact PyTorch CPU BF16 linear reduction policy for the remaining known-lane mismatch before changing runtime",
        )
    };

    let worst_lane_trace = serde_json::json!({
        "token_index": worst_token,
        "k_feature_index": worst_feature,
        "kv_head_index": worst_feature / 64,
        "head_dim_lane": worst_feature % 64,
        "input_vector_digest": stable_digest_f32(&worst_input_row_f32),
        "k_weight_row_digest": stable_digest_f32(&worst_weight_row_f32),
        "product_vector_digest": product_digest,
        "first_bf16_input_values": &worst_input_row_f32[..worst_input_row_f32.len().min(8)],
        "last_bf16_input_values": &worst_input_row_f32[worst_input_row_f32.len().saturating_sub(8)..],
        "first_bf16_weight_values": &worst_weight_row_f32[..worst_weight_row_f32.len().min(8)],
        "last_bf16_weight_values": &worst_weight_row_f32[worst_weight_row_f32.len().saturating_sub(8)..],
        "official_module_value": official_module_k_output[worst_flat],
        "official_manual_pytorch_value": official_manual_k_output[worst_flat],
        "official_pytorch_pre_output_dot_value": null,
        "official_pytorch_pre_output_dot_value_available": false,
        "rust_current_pre_output_dot_value": current_pre,
        "rust_current_bf16_output_bits": format!("0x{current_bits:04x}"),
        "rust_current_bf16_output_value": bf16::from_bits(current_bits).to_f32(),
        "best_scalar_policy_index": best_scalar_index,
        "best_scalar_policy_name": best_scalar_name,
        "best_scalar_pre_output_dot_value": best_scalar_pre,
        "best_scalar_bf16_output_bits": best_scalar_bits.map(|bits| format!("0x{bits:04x}")),
        "best_scalar_bf16_output_value": best_scalar_bits.map(|bits| bf16::from_bits(bits).to_f32()),
        "absolute_pre_output_delta_current_vs_best_scalar": best_scalar_pre.map(|value| (current_pre - value).abs()),
        "official_bf16_output_bits": format!("0x{:04x}", bf16::from_f32(official_module_k_output[worst_flat]).to_bits()),
        "official_bf16_output_value": official_module_k_output[worst_flat],
        "delta_crosses_bf16_rounding_boundary": current_bits != bf16::from_f32(official_module_k_output[worst_flat]).to_bits(),
        "first_stage_where_official_and_rust_diverge": earliest_divergent_stage,
    });

    let summary = serde_json::json!({
        "schema_version": "runtime_forward_layer0_k_projection_bf16_linear_policy_discriminator_status/v1",
        "exact_case": {
            "case_id": "developer-message-user-smoke",
            "token_count": token_count,
            "hidden_size": hidden_size,
            "kv_dim": kv_dim,
        },
        "mode": "k-projection-bf16-linear-policy-discriminator-status",
        "source_artifact_path": source_artifact_path,
        "python_script_path_used_for_official_side_policy_capture": cli.official_k_projection_weight_arithmetic_script.clone(),
        "official_extraction_artifact_path": official_extraction_path,
        "known_mismatch_lane_table": known_mismatch_lane_table,
        "official_pytorch_policy_metadata": {
            "module_path": "block.0.attn.qkv",
            "manual_projection_path": "torch.nn.functional.linear(official_norm_bf16, official_k_weight_bf16, zero_bias)",
            "manual_projection_matches_module": official_manual_metrics,
            "torch_metadata": official_extraction.get("provenance").cloned(),
            "execution_device": official_extraction.pointer("/provenance/device").cloned(),
            "output_dtype_before_serialization": "bfloat16",
            "scalar_explicit_loop_path_note": "explicit scalar variants are modeled locally from the same BF16-expanded input and weight; PyTorch module/manual linear pre-output scalar is not exposed",
        },
        "rust_helper_policy_metadata": {
            "current_rust_replay_policy": "BF16 input/weight, f32 products, left-to-right f32 accumulation, BF16 output",
            "pedantic_helper_policy_observed": "matches current Rust CPU replay exactly on known lanes",
            "source_weights": "matched official/runtime K weight slice",
        },
        "dot_product_policy_discriminator_table": discriminator_table,
        "worst_lane_trace": worst_lane_trace,
        "earliest_divergent_stage": earliest_divergent_stage,
        "classification": classification,
        "runtime_forward_k_projection_bf16_linear_policy_discriminator_status_now": format!(
            "runtime-forward K projection BF16 linear policy discriminator status now: official manual PyTorch still matches module; current Rust/helper left-to-right matches Rust helper; best scalar variant={} but scalar_full_match={}; earliest_divergent_stage={}; classification={}; next bounded step: {}.",
            best_scalar_name,
            scalar_full_match,
            earliest_divergent_stage,
            classification,
            next_bounded_step,
        ),
        "next_bounded_step": next_bounded_step,
    });

    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::KProjectionBf16LinearPolicyDiscriminatorStatus.default_output());
    write_pretty_json(&output, &summary)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn run_k_projection_pytorch_bf16_linear_backend_policy_status(cli: &Cli) -> Result<()> {
    let source_artifact_path =
        PathBuf::from(DEFAULT_K_PROJECTION_BF16_LINEAR_POLICY_DISCRIMINATOR_STATUS_OUTPUT);
    let source: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_artifact_path).with_context(|| {
            format!(
                "failed to read K projection BF16 linear policy discriminator artifact {}",
                source_artifact_path.display()
            )
        })?,
    )?;
    if source
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || source
            .get("classification")
            .and_then(serde_json::Value::as_str)
            != Some("official_k_projection_policy_not_fully_modeled")
    {
        bail!("source K projection BF16 linear policy discriminator artifact is not the expected state");
    }

    let (input_artifact, input_case) =
        load_single_case_artifact(&cli.local_residual_input_artifact)?;
    validate_exact_case_artifact(
        &input_artifact,
        &input_case,
        "layer0_residual_input",
        "developer-message-user-smoke",
        &input_case.input_token_ids,
    )?;
    let model_root = Path::new(&input_artifact.provenance.model);
    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::KProjectionPytorchBf16LinearBackendPolicyStatus.default_output());
    if let Some(parent) = output.parent() {
        std::fs::create_dir_all(parent)?;
    }
    let verbose_log = output.with_file_name(
        "developer-message.runner-layer0-k-projection-pytorch-bf16-linear-backend-policy.onednn.log",
    );
    let probe_json = output.with_file_name(
        "developer-message.runner-layer0-k-projection-pytorch-bf16-linear-backend-policy.probe.json",
    );
    let status = Command::new(&cli.torch_python)
        .arg(&cli.k_projection_pytorch_bf16_linear_backend_policy_script)
        .arg("--model-root")
        .arg(model_root)
        .arg("--source")
        .arg(&source_artifact_path)
        .arg("--rmsnorm-replay")
        .arg(DEFAULT_LAYER0_ATTN_RMSNORM_ALL_TOKEN_BF16_REPLAY_OFFICIAL_SIDE_OUTPUT)
        .arg("--official-extraction")
        .arg(&cli.official_k_projection_weight_arithmetic_artifact)
        .arg("--output")
        .arg(&output)
        .arg("--verbose-log")
        .arg(&verbose_log)
        .arg("--probe-json")
        .arg(&probe_json)
        .arg("--device")
        .arg("cpu")
        .status()
        .with_context(|| {
            format!(
                "failed to run PyTorch BF16 linear backend policy script {} with {}",
                cli.k_projection_pytorch_bf16_linear_backend_policy_script
                    .display(),
                cli.torch_python.display()
            )
        })?;
    if !status.success() {
        bail!(
            "PyTorch BF16 linear backend policy script failed with status {:?}",
            status.code()
        );
    }
    let summary: serde_json::Value =
        serde_json::from_str(&std::fs::read_to_string(&output).with_context(|| {
            format!(
                "failed to read PyTorch BF16 linear backend policy artifact {}",
                output.display()
            )
        })?)?;
    if summary
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || summary.get("mode").and_then(serde_json::Value::as_str)
            != Some("k-projection-pytorch-bf16-linear-backend-policy-status")
        || summary
            .get("classification")
            .and_then(serde_json::Value::as_str)
            .is_none()
    {
        bail!("PyTorch BF16 linear backend policy artifact failed exact-case validation");
    }
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

