fn run_q_pre_post_rope_runtime_localization_status(cli: &Cli) -> Result<()> {
    let source_q_path =
        PathBuf::from(DEFAULT_Q_PROVENANCE_AFTER_K_CANDIDATE_SOURCE_BREAKDOWN_STATUS_OUTPUT);
    let source_q: serde_json::Value =
        serde_json::from_str(&std::fs::read_to_string(&source_q_path).with_context(|| {
            format!(
                "failed to read Q provenance source artifact {}",
                source_q_path.display()
            )
        })?)?;
    if source_q
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || source_q
            .get("classification")
            .and_then(serde_json::Value::as_str)
            != Some("q_provenance_mismatch_confirmed_as_score_blocker")
    {
        bail!("source Q provenance artifact is not the expected exact score-blocker state");
    }

    let source_k_post_score_path =
        PathBuf::from(DEFAULT_K_POST_ROPE_AND_SCORE_AFTER_ONEDNN_K_CANDIDATE_STATUS_OUTPUT);
    let source_k_post_score: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(&source_k_post_score_path).with_context(|| {
            format!(
                "failed to read K post-RoPE/score source artifact {}",
                source_k_post_score_path.display()
            )
        })?,
    )?;
    if source_k_post_score
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || source_k_post_score
            .get("classification")
            .and_then(serde_json::Value::as_str)
            != Some("score_consumer_blocked_by_q_provenance_gap")
    {
        bail!("source K post-RoPE/score artifact is not the expected exact Q gap state");
    }

    let (input_artifact, input_case) =
        load_single_case_artifact(&cli.local_residual_input_artifact)?;
    validate_exact_case_artifact(
        &input_artifact,
        &input_case,
        "layer0_residual_input",
        "developer-message-user-smoke",
        &input_case.input_token_ids,
    )?;
    let model_root = Path::new(&input_artifact.provenance.model);
    let max_model_len = input_artifact.provenance.max_model_len.unwrap_or(128);
    let gpu_memory_utilization = input_artifact
        .provenance
        .gpu_memory_utilization
        .unwrap_or(0.75);
    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::QPrePostRopeRuntimeLocalizationStatus.default_output());
    if let Some(parent) = output.parent() {
        std::fs::create_dir_all(parent)?;
    }

    let _dense_guard = EnvFlagGuard::set(BF16_DENSE_QKV_ENV, true);
    let worker = build_worker(model_root, max_model_len, gpu_memory_utilization)?;
    let trace = capture_layer0_qkv_trace(&worker, &input_case.input_token_ids)?;
    if !trace.branch_taken {
        bail!("local Q pre/post RoPE capture did not take the BF16 dense-QKV branch");
    }
    let expected_pre_len = trace
        .num_tokens
        .checked_mul(trace.q_dim)
        .context("Q pre-RoPE capture length overflow")?;
    let expected_qkv_len = trace
        .num_tokens
        .checked_mul(trace.qkv_dim)
        .context("QKV capture length overflow")?;
    if trace.qkv_projection_output.len() != expected_qkv_len {
        bail!(
            "unexpected qkv projection output length: expected {}, found {}",
            expected_qkv_len,
            trace.qkv_projection_output.len()
        );
    }
    if trace.q_post_rope_before_attention_f32.len() != expected_pre_len {
        bail!(
            "unexpected Q post-RoPE capture length: expected {}, found {}",
            expected_pre_len,
            trace.q_post_rope_before_attention_f32.len()
        );
    }
    let local_q_pre_rope_f32 = trace.qkv_projection_output[..expected_pre_len].to_vec();
    let local_capture_path = output.with_file_name(
        "developer-message.runner-layer0-q-pre-post-rope-runtime-localization.local-q-capture.json",
    );
    std::fs::write(
        &local_capture_path,
        serde_json::to_string_pretty(&serde_json::json!({
            "schema_version": "runtime_forward_layer0_q_pre_post_rope_local_capture/v1",
            "case_id": "developer-message-user-smoke",
            "boundary": "layer0_q_pre_and_post_rope_runtime_debug_capture",
            "num_tokens": trace.num_tokens,
            "q_dim": trace.q_dim,
            "kv_dim": trace.kv_dim,
            "qkv_dim": trace.qkv_dim,
            "local_q_pre_rope_shape": [trace.num_tokens, trace.q_dim],
            "local_q_pre_rope_layout": "[token, q_feature]",
            "local_q_pre_rope_f32": local_q_pre_rope_f32,
            "local_q_post_rope_shape": [trace.num_tokens, trace.q_dim],
            "local_q_post_rope_layout": "[token, q_feature]",
            "local_q_post_rope_f32": trace.q_post_rope_before_attention_f32,
        }))?,
    )
    .with_context(|| {
        format!(
            "failed to write local Q pre/post RoPE capture {}",
            local_capture_path.display()
        )
    })?;

    let k_candidate_path =
        PathBuf::from(DEFAULT_K_PROJECTION_ONEDNN_ORACLE_SCOPED_HELPER_FIX_STATUS_OUTPUT);
    let verbose_log = output.with_file_name(
        "developer-message.runner-layer0-q-pre-post-rope-runtime-localization.onednn.log",
    );
    let status = Command::new(&cli.torch_python)
        .arg(&cli.q_pre_post_rope_runtime_localization_script)
        .arg("--model-root")
        .arg(model_root)
        .arg("--source-q-provenance")
        .arg(&source_q_path)
        .arg("--source-k-post-score")
        .arg(&source_k_post_score_path)
        .arg("--source-k-candidate")
        .arg(&k_candidate_path)
        .arg("--source-rmsnorm-replay-proof")
        .arg(DEFAULT_LAYER0_ATTN_RMSNORM_RUST_BF16_REPLAY_MULTIPLY_ORDER_FIX_STATUS_OUTPUT)
        .arg("--official-weight-arithmetic")
        .arg(&cli.official_k_projection_weight_arithmetic_artifact)
        .arg("--rmsnorm-replay")
        .arg(DEFAULT_LAYER0_ATTN_RMSNORM_ALL_TOKEN_BF16_REPLAY_OFFICIAL_SIDE_OUTPUT)
        .arg("--local-q-capture")
        .arg(&local_capture_path)
        .arg("--q-post-rope-official")
        .arg(&cli.official_q_post_rope_before_attention_artifact)
        .arg("--score-official")
        .arg(&cli.official_final_token_raw_scaled_qk_logits_pre_mask_artifact)
        .arg("--output")
        .arg(&output)
        .arg("--verbose-log")
        .arg(&verbose_log)
        .arg("--device")
        .arg("cpu")
        .status()
        .with_context(|| {
            format!(
                "failed to run Q pre/post RoPE runtime localization script {} with {}",
                cli.q_pre_post_rope_runtime_localization_script.display(),
                cli.torch_python.display()
            )
        })?;
    if !status.success() {
        bail!(
            "Q pre/post RoPE runtime localization script failed with status {:?}",
            status.code()
        );
    }
    let summary: serde_json::Value =
        serde_json::from_str(&std::fs::read_to_string(&output).with_context(|| {
            format!(
                "failed to read Q pre/post RoPE runtime localization artifact {}",
                output.display()
            )
        })?)?;
    if summary
        .pointer("/exact_case/case_id")
        .and_then(serde_json::Value::as_str)
        != Some("developer-message-user-smoke")
        || summary.get("mode").and_then(serde_json::Value::as_str)
            != Some("q-pre-post-rope-runtime-localization-status")
        || summary
            .get("classification")
            .and_then(serde_json::Value::as_str)
            .is_none()
    {
        bail!("Q pre/post RoPE runtime localization artifact failed exact-case validation");
    }
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

