fn run_k_post_bias_contradiction_status(cli: &Cli) -> Result<()> {
    let (local_artifact, local_case) =
        load_single_case_artifact(&cli.local_residual_input_artifact)?;
    validate_exact_case_artifact(
        &local_artifact,
        &local_case,
        "layer0_residual_input",
        "developer-message-user-smoke",
        &local_case.input_token_ids,
    )?;

    let exact_hidden_size = local_case
        .hidden_size
        .context("exact smoke case missing hidden_size")?;
    let model_root = Path::new(&local_artifact.provenance.model);
    let max_model_len = local_artifact.provenance.max_model_len.unwrap_or(128);
    let gpu_memory_utilization = local_artifact
        .provenance
        .gpu_memory_utilization
        .unwrap_or(0.75);
    let visible_devices = local_artifact
        .provenance
        .visible_devices
        .clone()
        .unwrap_or_else(|| env::var("CUDA_VISIBLE_DEVICES").unwrap_or_else(|_| "<unset>".into()));

    info!(
        model_root = %model_root.display(),
        max_model_len,
        gpu_memory_utilization,
        visible_devices = %visible_devices,
        full_qkv_k_stage_status_artifact = %cli.full_qkv_k_stage_status_artifact.display(),
        k_bias_delta_status_artifact = %Mode::KBiasDeltaStatus.default_output().display(),
        "starting exact-case layer0 K post-bias contradiction status run"
    );

    let k_only_proof_capture = k_interaction_capture_variant(
        model_root,
        max_model_len,
        gpu_memory_utilization,
        &local_case.input_token_ids,
        true,
        true,
        None,
    )?;
    let stage_full_capture = k_interaction_capture_variant(
        model_root,
        max_model_len,
        gpu_memory_utilization,
        &local_case.input_token_ids,
        true,
        false,
        Some("full"),
    )?;
    let delta_full_capture = k_interaction_capture_variant(
        model_root,
        max_model_len,
        gpu_memory_utilization,
        &local_case.input_token_ids,
        true,
        false,
        Some("full"),
    )?;

    let summary = build_k_post_bias_contradiction_status_summary(
        cli,
        &local_case,
        &local_artifact,
        &visible_devices,
        exact_hidden_size,
        &k_only_proof_capture,
        &stage_full_capture,
        &delta_full_capture,
    )?;
    let output = cli
        .output
        .clone()
        .unwrap_or_else(|| Mode::KPostBiasContradictionStatus.default_output());
    write_pretty_json(&output, &summary)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

